{
  "name": "Dokan Khata - Business Ledger",
  "description": "A comprehensive Bengali business management and accounting app inspired by TallyKhata, allowing shop owners to track receivables, payables, and cash flow."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ContactType {
  CUSTOMER = 'CUSTOMER',
  SUPPLIER = 'SUPPLIER'
}

export interface Transaction {
  id: string;
  type: 'DUE_GIVEN' | 'RECEIVED';
  amount: number;
  description: string;
  date: string;
}

export interface Contact {
  id: string;
  name: string;
  phone: string;
  type: ContactType;
  balance: number; // Positive means receivable (from customer), Negative means payable (to supplier)
  lastActivity: string;
  transactions: Transaction[];
}

export interface DailyCash {
  sales: number;
  purchases: number;
  expenses: number;
  receivedFromOwners: number;
  takenByOwners: number;
  totalCash: number;
}

export type ViewState = 'TALLY' | 'CASHBOX' | 'WALLET' | 'MENU' | 'ADD_CONTACT' | 'CONTACT_DETAILS';

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, 
  Wallet, 
  Menu, 
  BookOpen, 
  Search, 
  UserPlus, 
  Plus, 
  Minus, 
  ArrowLeft, 
  MoreVertical, 
  Calendar, 
  Camera, 
  ChevronRight,
  Filter,
  Download,
  Package,
  FileText,
  Bell,
  HelpCircle,
  QrCode,
  CloudUpload,
  MessageSquare,
  ChevronDown
} from 'lucide-react';
import { Contact, ContactType, ViewState, DailyCash, Transaction } from './types';
import TallyView from './components/TallyView';
import CashboxView from './components/CashboxView';
import AddContactForm from './components/AddContactForm';
import ContactDetails from './components/ContactDetails';
import Navigation from './components/Navigation';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('TALLY');
  const [contacts, setContacts] = useState<Contact[]>(() => {
    const saved = localStorage.getItem('dokan_contacts');
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        name: 'Subongkar Vai Galachipa',
        phone: '01700000001',
        type: ContactType.CUSTOMER,
        balance: 4000,
        lastActivity: '২ দিন আগে',
        transactions: []
      },
      {
        id: '2',
        name: 'Saiful Telecom caca',
        phone: '01700000002',
        type: ContactType.SUPPLIER,
        balance: -1230,
        lastActivity: '২ মাস আগে',
        transactions: []
      }
    ];
  });

  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('dokan_contacts', JSON.stringify(contacts));
  }, [contacts]);

  const addContact = (newContact: Contact) => {
    setContacts(prev => [...prev, newContact]);
    setCurrentView('TALLY');
  };

  const updateContactTransactions = (contactId: string, transaction: Transaction) => {
    setContacts(prev => prev.map(c => {
      if (c.id === contactId) {
        const newBalance = transaction.type === 'DUE_GIVEN' 
          ? c.balance + transaction.amount 
          : c.balance - transaction.amount;
        return {
          ...c,
          balance: newBalance,
          lastActivity: 'এখনই',
          transactions: [transaction, ...c.transactions]
        };
      }
      return c;
    }));
  };

  const selectedContact = useMemo(() => 
    contacts.find(c => c.id === selectedContactId), 
    [contacts, selectedContactId]
  );

  const renderView = () => {
    switch (currentView) {
      case 'TALLY':
        return (
          <TallyView 
            contacts={contacts} 
            onSelectContact={(id) => {
              setSelectedContactId(id);
              setCurrentView('CONTACT_DETAILS');
            }}
            onAddContact={() => setCurrentView('ADD_CONTACT')}
          />
        );
      case 'CASHBOX':
        return <CashboxView />;
      case 'ADD_CONTACT':
        return (
          <AddContactForm 
            onBack={() => setCurrentView('TALLY')} 
            onSave={addContact} 
          />
        );
      case 'CONTACT_DETAILS':
        return selectedContact ? (
          <ContactDetails 
            contact={selectedContact} 
            onBack={() => setCurrentView('TALLY')}
            onAddTransaction={(t) => updateContactTransactions(selectedContact.id, t)}
          />
        ) : null;
      default:
        return <div className="p-10 text-center">Work in Progress</div>;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen flex flex-col relative shadow-xl">
      {/* Header */}
      <header className="bg-[#D32F2F] text-white px-4 py-3 sticky top-0 z-40">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setIsSidebarOpen(true)}>
            <div className="bg-white/20 p-1 rounded-md">
              <span className="text-sm font-bold">saiful telec...</span>
            </div>
            <ChevronDown size={16} />
          </div>

          <div className="flex items-center gap-4">
            <div className="relative">
              <Bell size={24} />
              <span className="absolute -top-1 -right-1 bg-white text-[#D32F2F] text-[10px] font-bold rounded-full w-4 h-4 flex items-center justify-center">99+</span>
              <span className="block text-[10px] mt-1 text-center">ইনবক্স</span>
            </div>
            <div className="flex flex-col items-center">
              <HelpCircle size={24} />
              <span className="text-[10px] mt-1">হেল্প</span>
            </div>
          </div>
        </div>
        <div className="mt-1 text-xs font-semibold opacity-90">স্ট্যান্ডার্ড</div>
      </header>

      {/* Sidebar */}
      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20">
        {renderView()}
      </main>

      {/* Bottom Navigation */}
      {['TALLY', 'CASHBOX', 'WALLET', 'MENU'].includes(currentView) && (
        <Navigation currentView={currentView} onNavigate={setCurrentView} />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { BookOpen, Wallet, Menu, CreditCard } from 'lucide-react';
import { ViewState } from '../types';

interface NavigationProps {
  currentView: ViewState;
  onNavigate: (view: ViewState) => void;
}

const Navigation: React.FC<NavigationProps> = ({ currentView, onNavigate }) => {
  const tabs = [
    { id: 'TALLY', label: 'টালি', icon: BookOpen },
    { id: 'CASHBOX', label: 'ক্যাশ বক্স', icon: Wallet },
    { id: 'WALLET', label: 'ওয়ালেট', icon: CreditCard },
    { id: 'MENU', label: 'মেনু', icon: Menu },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 flex justify-around py-2 z-50">
      {tabs.map((tab) => (
        <button
          key={tab.id}
          onClick={() => onNavigate(tab.id as ViewState)}
          className={`flex flex-col items-center flex-1 transition-colors ${
            currentView === tab.id ? 'text-[#D32F2F]' : 'text-gray-500'
          }`}
        >
          <div className={`p-1 rounded-full ${currentView === tab.id ? 'bg-[#FFE9E9]' : ''}`}>
             <tab.icon size={22} fill={currentView === tab.id ? 'currentColor' : 'none'} />
          </div>
          <span className="text-xs mt-1 font-medium">{tab.label}</span>
        </button>
      ))}
    </nav>
  );
};

export default Navigation;

import React, { useState } from 'react';
import { ArrowLeft, User, Phone, Banknote, Calendar, Camera } from 'lucide-react';
import { Contact, ContactType } from '../types';

interface AddContactFormProps {
  onBack: () => void;
  onSave: (contact: Contact) => void;
}

const AddContactForm: React.FC<AddContactFormProps> = ({ onBack, onSave }) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [type, setType] = useState<ContactType>(ContactType.CUSTOMER);
  const [initialBalance, setInitialBalance] = useState('');

  const handleSave = () => {
    if (!name || !phone) return;

    const newContact: Contact = {
      id: Date.now().toString(),
      name,
      phone,
      type,
      balance: parseFloat(initialBalance || '0') * (type === ContactType.CUSTOMER ? 1 : -1),
      lastActivity: 'এখনই',
      transactions: []
    };

    onSave(newContact);
  };

  return (
    <div className="bg-white min-h-full flex flex-col">
      <header className="flex items-center gap-4 p-4 border-b border-gray-100">
        <button onClick={onBack} className="text-gray-600"><ArrowLeft size={24} /></button>
        <h2 className="text-lg font-bold">নতুন কাস্টমার/সাপ্লায়ার</h2>
      </header>

      <div className="p-6 space-y-6">
        {/* Profile Pic Placeholder */}
        <div className="flex justify-center relative">
          <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center text-gray-400">
            <User size={48} />
          </div>
          <button className="absolute bottom-0 translate-x-10 bg-white shadow p-1 rounded-lg border border-gray-200">
            <Camera size={18} className="text-gray-600" />
          </button>
        </div>

        {/* Type Toggle */}
        <div className="flex gap-4">
          <button 
            onClick={() => setType(ContactType.CUSTOMER)}
            className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${
              type === ContactType.CUSTOMER ? 'border-[#D32F2F] bg-red-50 text-[#D32F2F]' : 'border-gray-200 text-gray-500'
            }`}
          >
            <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${
              type === ContactType.CUSTOMER ? 'border-[#D32F2F]' : 'border-gray-400'
            }`}>
              {type === ContactType.CUSTOMER && <div className="w-2 h-2 bg-[#D32F2F] rounded-full" />}
            </div>
            কাস্টমার
          </button>
          <button 
            onClick={() => setType(ContactType.SUPPLIER)}
            className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${
              type === ContactType.SUPPLIER ? 'border-[#D32F2F] bg-red-50 text-[#D32F2F]' : 'border-gray-200 text-gray-500'
            }`}
          >
            <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${
              type === ContactType.SUPPLIER ? 'border-[#D32F2F]' : 'border-gray-400'
            }`}>
              {type === ContactType.SUPPLIER && <div className="w-2 h-2 bg-[#D32F2F] rounded-full" />}
            </div>
            সাপ্লায়ার
          </button>
        </div>

        <button className="w-full flex items-center justify-center gap-2 p-4 bg-gray-50 rounded-xl text-gray-700 font-bold">
           ফোনবুক থেকে যোগ করি
        </button>

        <div className="space-y-4">
          <div className="relative">
            <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
            <input 
              type="text" 
              placeholder="নাম" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full p-4 pl-12 bg-white border border-gray-200 rounded-xl outline-none focus:border-red-400 transition-colors"
            />
          </div>

          <div className="relative">
            <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
            <input 
              type="tel" 
              placeholder="মোবাইল নম্বর" 
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              className="w-full p-4 pl-12 bg-white border border-gray-200 rounded-xl outline-none focus:border-red-400 transition-colors"
            />
          </div>

          <div className="relative">
             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-700 font-bold text-lg">৳</div>
            <input 
              type="number" 
              placeholder="পূর্বের বাকি (জের)" 
              value={initialBalance}
              onChange={(e) => setInitialBalance(e.target.value)}
              className="w-full p-4 pl-12 bg-white border border-gray-200 rounded-xl outline-none focus:border-red-400 transition-colors"
            />
          </div>
        </div>

        <div className="flex gap-4">
          <button className="flex-1 flex items-center gap-2 p-2 bg-gray-50 rounded-xl text-sm font-medium text-gray-600">
            <Calendar size={18} /> ১২ জানুয়ারি
          </button>
          <button className="flex-1 flex items-center justify-center gap-2 p-2 bg-gray-50 rounded-xl text-sm font-medium text-gray-600">
            <Camera size={18} /> ছবি
          </button>
        </div>

        <button 
          onClick={handleSave}
          disabled={!name || !phone}
          className={`w-full p-4 rounded-full font-bold text-white transition-all ${
            name && phone ? 'bg-[#D32F2F]' : 'bg-red-200'
          }`}
        >
          নিশ্চিত
        </button>
      </div>
    </div>
  );
};

export default AddContactForm;

import React, { useState } from 'react';
import { ArrowLeft, MoreVertical, Calendar, Camera, Plus, Minus, MessageSquare } from 'lucide-react';
import { Contact, Transaction } from '../types';

interface ContactDetailsProps {
  contact: Contact;
  onBack: () => void;
  onAddTransaction: (t: Transaction) => void;
}

const ContactDetails: React.FC<ContactDetailsProps> = ({ contact, onBack, onAddTransaction }) => {
  const [dilamAmount, setDilamAmount] = useState('');
  const [pelamAmount, setPelamAmount] = useState('');
  const [description, setDescription] = useState('');
  const [showForm, setShowForm] = useState(false);

  const handleSubmit = (type: 'DUE_GIVEN' | 'RECEIVED') => {
    const amount = parseFloat(type === 'DUE_GIVEN' ? dilamAmount : pelamAmount);
    if (!amount || isNaN(amount)) return;

    const newTransaction: Transaction = {
      id: Date.now().toString(),
      type,
      amount,
      description,
      date: new Date().toLocaleDateString('bn-BD')
    };

    onAddTransaction(newTransaction);
    setDilamAmount('');
    setPelamAmount('');
    setDescription('');
    setShowForm(false);
  };

  return (
    <div className="bg-white min-h-full flex flex-col relative">
      <header className="flex items-center justify-between p-4 border-b border-gray-100 sticky top-0 bg-white z-10">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="text-gray-600"><ArrowLeft size={24} /></button>
          <div className="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center text-white font-bold">
            {contact.name.substring(0, 1)}
          </div>
          <div>
            <h2 className="font-bold text-gray-900 leading-tight">{contact.name}</h2>
            <p className="text-xs text-gray-500">{contact.phone}</p>
          </div>
        </div>
        <button><MoreVertical size={20} className="text-gray-500" /></button>
      </header>

      {/* Balance Summary Bar */}
      <div className="px-4 py-3 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
        <div className="text-sm">
          পাবো <span className="text-[#D32F2F] font-bold">৳ {Math.abs(contact.balance).toLocaleString('bn-BD')}.০০</span>
        </div>
        <div className="text-[10px] text-gray-400">(৫ সেকেন্ড আগে)</div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {/* Transaction Input Area */}
        <div className="space-y-4 mb-8">
           <div className="flex gap-3">
              <div className="flex-1 relative">
                 <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-700 font-bold">৳</div>
                 <input 
                   type="number" 
                   placeholder="দিলাম/বেচা"
                   value={dilamAmount}
                   onChange={(e) => {
                     setDilamAmount(e.target.value);
                     setPelamAmount('');
                   }}
                   className="w-full p-4 pl-8 border border-gray-200 rounded-xl outline-none focus:border-red-400 transition-colors"
                 />
              </div>
              <div className="flex-1 relative">
                 <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-700 font-bold">৳</div>
                 <input 
                   type="number" 
                   placeholder="পেলাম"
                   value={pelamAmount}
                   onChange={(e) => {
                     setPelamAmount(e.target.value);
                     setDilamAmount('');
                   }}
                   className="w-full p-4 pl-8 border border-gray-200 rounded-xl outline-none focus:border-red-400 transition-colors"
                 />
              </div>
           </div>

           <div className="relative">
              <MessageSquare className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                type="text" 
                placeholder="বিবরণ"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full p-4 pl-12 border border-gray-200 rounded-xl outline-none focus:border-red-400 transition-colors"
              />
           </div>

           <div className="flex items-center justify-between">
              <div className="flex gap-2">
                <button className="flex items-center gap-2 p-2 px-3 bg-gray-50 rounded-xl text-xs font-bold text-gray-600">
                  <Calendar size={16} /> ১৭ জানুয়ারি
                </button>
                <button className="flex items-center gap-2 p-2 px-3 bg-gray-50 rounded-xl text-xs font-bold text-gray-600">
                  <Camera size={16} /> ছবি
                </button>
              </div>

              <div className="flex items-center gap-2">
                 <span className="text-xs font-bold text-gray-500">টালি-মেসেজ</span>
                 <div className="w-10 h-6 bg-gray-200 rounded-full relative p-1 cursor-pointer">
                    <div className="w-4 h-4 bg-white rounded-full shadow-sm"></div>
                 </div>
              </div>
           </div>
        </div>

        {/* Action Button */}
        <button 
          onClick={() => handleSubmit(dilamAmount ? 'DUE_GIVEN' : 'RECEIVED')}
          disabled={!dilamAmount && !pelamAmount}
          className={`w-full p-4 rounded-full font-bold text-white transition-all ${
            dilamAmount || pelamAmount ? 'bg-[#D32F2F]' : 'bg-red-200'
          }`}
        >
          নিশ্চিত
        </button>

        {/* Past Transactions List */}
        <div className="mt-8 space-y-3">
           <h3 className="text-xs font-bold text-gray-400 uppercase">লেনদেন ইতিহাস</h3>
           {contact.transactions.map(t => (
             <div key={t.id} className="p-3 bg-gray-50 rounded-xl flex justify-between items-center border border-gray-100">
                <div>
                  <div className="text-sm font-bold text-gray-800">{t.description || (t.type === 'DUE_GIVEN' ? 'দিলাম' : 'পেলাম')}</div>
                  <div className="text-[10px] text-gray-400">{t.date}</div>
                </div>
                <div className={`font-bold ${t.type === 'DUE_GIVEN' ? 'text-[#D32F2F]' : 'text-green-600'}`}>
                   {t.type === 'RECEIVED' ? '+' : '-'} {t.amount.toLocaleString('bn-BD')}
                </div>
             </div>
           ))}
           {contact.transactions.length === 0 && (
             <div className="text-center py-10 text-gray-400 italic text-sm">কোনো লেনদেন পাওয়া যায়নি</div>
           )}
        </div>
      </div>
    </div>
  );
};

export default ContactDetails;

