export enum ContactType {
  CUSTOMER = 'CUSTOMER',
  SUPPLIER = 'SUPPLIER'
}

export interface Transaction {
  id: string;
  type: 'DUE_GIVEN' | 'RECEIVED';
  amount: number;
  description: string;
  date: string;
}

export interface Contact {
  id: string;
  name: string;
  phone: string;
  type: ContactType;
  balance: number; // Positive means receivable (from customer), Negative means payable (to supplier)
  lastActivity: string;
  transactions: Transaction[];
}

export interface SalePurchaseRecord {
  id: string;
  type: 'SALE' | 'PURCHASE';
  amount: number;
  description: string;
  date: string;
  isCash: boolean;
}

export type ViewState = 'TALLY' | 'CASHBOX' | 'WALLET' | 'MENU' | 'ADD_CONTACT' | 'CONTACT_DETAILS' | 'BECHA_KENA';

import React, { useState } from 'react';
import { ArrowLeft, Plus, Minus, Calendar, ShoppingCart, ShoppingBag, ChevronRight, History } from 'lucide-react';
import { SalePurchaseRecord } from '../types';

interface BechaKenaViewProps {
  records: SalePurchaseRecord[];
  onBack: () => void;
  onAddRecord: (record: SalePurchaseRecord) => void;
}

const BechaKenaView: React.FC<BechaKenaViewProps> = ({ records, onBack, onAddRecord }) => {
  const [amount, setAmount] = useState('');
  const [description, setDescription] = useState('');
  const [isCash, setIsCash] = useState(true);

  const totalSales = records
    .filter(r => r.type === 'SALE')
    .reduce((acc, curr) => acc + curr.amount, 0);

  const totalPurchases = records
    .filter(r => r.type === 'PURCHASE')
    .reduce((acc, curr) => acc + curr.amount, 0);

  const handleAdd = (type: 'SALE' | 'PURCHASE') => {
    if (!amount) return;
    const newRecord: SalePurchaseRecord = {
      id: Date.now().toString(),
      type,
      amount: parseFloat(amount),
      description,
      date: new Date().toLocaleDateString('bn-BD'),
      isCash
    };
    onAddRecord(newRecord);
    setAmount('');
    setDescription('');
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col">
      <header className="flex items-center gap-4 p-4 bg-white border-b border-gray-100 sticky top-0 z-10">
        <button onClick={onBack} className="text-gray-600"><ArrowLeft size={24} /></button>
        <h2 className="text-lg font-bold">বেচা কেনা হিসাব</h2>
      </header>

      {/* Summary Card */}
      <div className="p-4 grid grid-cols-2 gap-3">
        <div className="bg-white p-4 rounded-2xl shadow-sm border-l-4 border-green-500">
          <div className="text-xs text-gray-500 font-bold uppercase mb-1">মোট বেচা</div>
          <div className="text-xl font-black text-green-600">৳ {totalSales.toLocaleString('bn-BD')}</div>
        </div>
        <div className="bg-white p-4 rounded-2xl shadow-sm border-l-4 border-red-500">
          <div className="text-xs text-gray-500 font-bold uppercase mb-1">মোট কেনা</div>
          <div className="text-xl font-black text-red-600">৳ {totalPurchases.toLocaleString('bn-BD')}</div>
        </div>
      </div>

      {/* Input Form */}
      <div className="mx-4 mb-4 bg-white p-4 rounded-2xl shadow-sm space-y-3">
        <div className="flex gap-2 mb-2">
          <button 
            onClick={() => setIsCash(true)}
            className={`flex-1 py-1 rounded-full text-xs font-bold transition-all ${isCash ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-500'}`}
          >নগদ</button>
          <button 
            onClick={() => setIsCash(false)}
            className={`flex-1 py-1 rounded-full text-xs font-bold transition-all ${!isCash ? 'bg-orange-500 text-white' : 'bg-gray-100 text-gray-500'}`}
          >বাকি</button>
        </div>

        <input 
          type="number" 
          placeholder="টাকার পরিমাণ (৳)" 
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          className="w-full p-3 bg-gray-50 border border-gray-100 rounded-xl outline-none focus:border-red-400 font-bold text-lg"
        />
        <input 
          type="text" 
          placeholder="বিবরণ (ঐচ্ছিক)" 
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          className="w-full p-3 bg-gray-50 border border-gray-100 rounded-xl outline-none focus:border-red-400 text-sm"
        />

        <div className="flex gap-3">
          <button 
            onClick={() => handleAdd('SALE')}
            className="flex-1 bg-green-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-transform"
          >
            <Plus size={18} /> বেচা
          </button>
          <button 
            onClick={() => handleAdd('PURCHASE')}
            className="flex-1 bg-red-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-transform"
          >
            <Minus size={18} /> কেনা
          </button>
        </div>
      </div>

      {/* Transaction List */}
      <div className="flex-1 bg-white rounded-t-3xl p-4 shadow-inner">
        <div className="flex items-center justify-between mb-4 px-2">
          <h3 className="text-sm font-bold text-gray-500 flex items-center gap-2">
            <History size={16} /> লেনদেনের তালিকা
          </h3>
          <span className="text-[10px] bg-gray-100 px-2 py-1 rounded text-gray-400">আজ, ১৭ জানুয়ারি</span>
        </div>

        <div className="space-y-3">
          {records.length === 0 ? (
            <div className="text-center py-10 text-gray-400 text-sm italic">এখনো কোনো হিসাব যোগ করা হয়নি</div>
          ) : (
            records.slice().reverse().map((record) => (
              <div key={record.id} className="flex items-center gap-3 p-3 border-b border-gray-50">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${
                  record.type === 'SALE' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'
                }`}>
                  {record.type === 'SALE' ? <ShoppingCart size={20} /> : <ShoppingBag size={20} />}
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <span className="font-bold text-gray-800">{record.type === 'SALE' ? 'মাল বিক্রি' : 'মাল ক্রয়'}</span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded ${record.isCash ? 'bg-blue-50 text-blue-600' : 'bg-orange-50 text-orange-600'}`}>
                      {record.isCash ? 'নগদ' : 'বাকি'}
                    </span>
                  </div>
                  <p className="text-xs text-gray-400">{record.description || 'বিবরণ নেই'}</p>
                </div>
                <div className={`text-right font-black ${record.type === 'SALE' ? 'text-green-600' : 'text-red-600'}`}>
                  {record.type === 'SALE' ? '+' : '-'} {record.amount.toLocaleString('bn-BD')}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default BechaKenaView;

import React, { useState, useEffect, useMemo } from 'react';
