  const [currentView, setCurrentView] = useState<ViewState>('TALLY');
  const [contacts, setContacts] = useState<Contact[]>(() => {
    const saved = localStorage.getItem('dokan_contacts');
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        name: 'Subongkar Vai Galachipa',
        phone: '01700000001',
        type: ContactType.CUSTOMER,
        balance: 4000,
        lastActivity: '২ দিন আগে',
        transactions: []
      },
      {
        id: '2',
        name: 'Saiful Telecom caca',
        phone: '01700000002',
        type: ContactType.SUPPLIER,
        balance: -1230,
        lastActivity: '২ মাস আগে',
        transactions: []
      }
    ];
  });

  const [salePurchaseRecords, setSalePurchaseRecords] = useState<SalePurchaseRecord[]>(() => {
    const saved = localStorage.getItem('dokan_becha_kena');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('dokan_contacts', JSON.stringify(contacts));
  }, [contacts]);

  useEffect(() => {
    localStorage.setItem('dokan_becha_kena', JSON.stringify(salePurchaseRecords));
  }, [salePurchaseRecords]);

  const addContact = (newContact: Contact) => {
    setContacts(prev => [...prev, newContact]);
    setCurrentView('TALLY');
  };

  const addSalePurchaseRecord = (record: SalePurchaseRecord) => {
    setSalePurchaseRecords(prev => [...prev, record]);
  };

  const updateContactTransactions = (contactId: string, transaction: Transaction) => {
    setContacts(prev => prev.map(c => {
      if (c.id === contactId) {
        const newBalance = transaction.type === 'DUE_GIVEN' 
          ? c.balance + transaction.amount 
          : c.balance - transaction.amount;
        return {
          ...c,
          balance: newBalance,
          lastActivity: 'এখনই',
          transactions: [transaction, ...c.transactions]
        };
      }
      return c;
    }));
  };

  const selectedContact = useMemo(() => 
    contacts.find(c => c.id === selectedContactId), 
    [contacts, selectedContactId]
  );

  const renderView = () => {
    switch (currentView) {
      case 'TALLY':
        return (
          <TallyView 
            contacts={contacts} 
            onSelectContact={(id) => {
              setSelectedContactId(id);
              setCurrentView('CONTACT_DETAILS');
            }}
            onAddContact={() => setCurrentView('ADD_CONTACT')}
            onNavigate={setCurrentView}
          />
        );
      case 'CASHBOX':
        return <CashboxView />;
      case 'ADD_CONTACT':
        return (
          <AddContactForm 
            onBack={() => setCurrentView('TALLY')} 
            onSave={addContact} 
          />
        );
      case 'CONTACT_DETAILS':
        return selectedContact ? (
          <ContactDetails 
            contact={selectedContact} 
            onBack={() => setCurrentView('TALLY')}
            onAddTransaction={(t) => updateContactTransactions(selectedContact.id, t)}
          />
        ) : null;
      case 'BECHA_KENA':
        return (
          <BechaKenaView 
            records={salePurchaseRecords}
            onBack={() => setCurrentView('TALLY')}
            onAddRecord={addSalePurchaseRecord}
          />
        );
      case 'CLOUD_BACKUP':
        return (
          <CloudBackup 
            data={{ contacts, salePurchaseRecords }}
            onBack={() => setCurrentView('TALLY')}
          />
        );
      default:
        return <div className="p-10 text-center">Work in Progress</div>;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen flex flex-col relative shadow-xl">
      {/* Header */}
      <header className="bg-[#D32F2F] text-white px-4 py-3 sticky top-0 z-40">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setIsSidebarOpen(true)}>
            <div className="bg-white/20 p-1 rounded-md">
              <span className="text-sm font-bold">saiful telec...</span>
            </div>
            <ChevronDown size={16} />
          </div>

          <div className="flex items-center gap-4">
            <div className="relative">
              <Bell size={24} />
              <span className="absolute -top-1 -right-1 bg-white text-[#D32F2F] text-[10px] font-bold rounded-full w-4 h-4 flex items-center justify-center">99+</span>
              <span className="block text-[10px] mt-1 text-center">ইনবক্স</span>
            </div>
            <div className="flex flex-col items-center">
              <HelpCircle size={24} />
              <span className="text-[10px] mt-1">হেল্প</span>
            </div>
          </div>
        </div>
        <div className="mt-1 text-xs font-semibold opacity-90">স্ট্যান্ডার্ড</div>
      </header>

      {/* Sidebar */}
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        onNavigate={(view) => {
          setCurrentView(view);
          setIsSidebarOpen(false);
        }}
      />

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20">
        {renderView()}
      </main>

      {/* Bottom Navigation */}
      {['TALLY', 'CASHBOX', 'WALLET', 'MENU'].includes(currentView) && (
        <Navigation currentView={currentView} onNavigate={setCurrentView} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  ArrowLeft, 
  CloudUpload, 
  CheckCircle2, 
  RefreshCw, 
  Database, 
  ShieldCheck, 
  LogOut,
  Mail,
  Lock
} from 'lucide-react';

interface CloudBackupProps {
  onBack: () => void;
  data: any;
}

interface UserProfile {
  name: string;
  email: string;
  photo: string;
}

const CloudBackup: React.FC<CloudBackupProps> = ({ onBack, data }) => {
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(() => {
    return localStorage.getItem('dokan_user_logged_in') === 'true';
  });
  const [user, setUser] = useState<UserProfile | null>(() => {
    const savedUser = localStorage.getItem('dokan_user_profile');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [lastSynced, setLastSynced] = useState<string | null>(() => localStorage.getItem('dokan_last_sync'));
  const [syncSuccess, setSyncSuccess] = useState(false);

  const handleLogin = () => {
    setIsLoggingIn(true);
    // Simulate Google OAuth login delay
    setTimeout(() => {
      const mockUser = {
        name: 'Saiful Islam',
        email: 'saiful.telecom@gmail.com',
        photo: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Saiful'
      };
      setUser(mockUser);
      setIsLoggedIn(true);
      setIsLoggingIn(false);
      localStorage.setItem('dokan_user_logged_in', 'true');
      localStorage.setItem('dokan_user_profile', JSON.stringify(mockUser));
    }, 2000);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUser(null);
    localStorage.removeItem('dokan_user_logged_in');
    localStorage.removeItem('dokan_user_profile');
  };

  const handleSync = () => {
    setIsSyncing(true);
    setSyncSuccess(false);

    setTimeout(() => {
      const now = new Date().toLocaleString('bn-BD', {
        hour: '2-digit',
        minute: '2-digit',
        day: '2-digit',
        month: 'long',
        year: 'numeric'
      });

      localStorage.setItem('dokan_last_sync', now);
      setLastSynced(now);
      setIsSyncing(false);
      setSyncSuccess(true);
      setTimeout(() => setSyncSuccess(false), 5000);
    }, 3000);
  };

  // Login Screen View
  if (!isLoggedIn) {
    return (
      <div className="bg-white min-h-full flex flex-col">
        <header className="flex items-center gap-4 p-4 border-b border-gray-100">
          <button onClick={onBack} className="text-gray-600"><ArrowLeft size={24} /></button>
          <h2 className="text-lg font-bold">লগইন করুন</h2>
        </header>

        <div className="flex-1 p-8 flex flex-col items-center justify-center text-center">
          <div className="w-20 h-20 bg-red-50 rounded-3xl flex items-center justify-center mb-6">
            <Mail size={40} className="text-red-600" />
          </div>
          <h3 className="text-2xl font-black text-gray-800 mb-2">গুগল দিয়ে সাইন-ইন</h3>
          <p className="text-sm text-gray-500 mb-10 px-4">
            আপনার ডাটা সুরক্ষিত রাখতে এবং গুগল ড্রাইভে ব্যাকআপ নিতে জিমেইল দিয়ে লগইন করা প্রয়োজন।
          </p>

          <div className="w-full space-y-4">
            <button 
              onClick={handleLogin}
              disabled={isLoggingIn}
              className="w-full py-4 px-6 bg-white border-2 border-gray-100 rounded-2xl flex items-center justify-center gap-4 shadow-sm active:scale-95 transition-all hover:bg-gray-50"
            >
              {isLoggingIn ? (
                <RefreshCw className="animate-spin text-red-600" size={24} />
              ) : (
                <img src="https://www.google.com/favicon.ico" alt="Google" className="w-6 h-6" />
              )}
              <span className="font-bold text-gray-700">
                {isLoggingIn ? 'অপেক্ষা করুন...' : 'Sign in with Google'}
              </span>
            </button>

            <div className="flex items-center gap-2 justify-center text-gray-400 text-xs mt-6">
               <Lock size={14} />
               <span>আপনার ডাটা শতভাগ এনক্রিপ্টেড এবং সুরক্ষিত</span>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Backup Controls View (After Login)
  return (
    <div className="bg-white min-h-full flex flex-col">
      <header className="flex items-center justify-between p-4 border-b border-gray-100 sticky top-0 bg-white z-10">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="text-gray-600"><ArrowLeft size={24} /></button>
          <h2 className="text-lg font-bold">ডাটা ব্যাকআপ</h2>
        </div>
        <button onClick={handleLogout} className="text-red-600 flex items-center gap-1 font-bold text-sm">
           <LogOut size={18} /> লগআউট
        </button>
      </header>

      <div className="flex-1 p-6 flex flex-col items-center text-center">
        {/* Animated Icon */}
        <div className={`w-28 h-28 rounded-full bg-red-50 flex items-center justify-center mb-6 relative ${isSyncing ? 'animate-pulse' : ''}`}>
          <div className={`absolute inset-0 border-4 border-red-200 border-t-red-600 rounded-full ${isSyncing ? 'animate-spin' : 'hidden'}`}></div>
          <CloudUpload size={50} className={isSyncing ? 'text-red-400' : 'text-red-600'} />
        </div>

        {/* Account Info Card */}
        <div className="w-full bg-gray-50 rounded-2xl p-4 mb-6 flex items-center gap-4 border border-gray-100">
           <img 
             src={user?.photo} 
             alt="Profile" 
             className="w-12 h-12 rounded-full border-2 border-white shadow-sm"
           />
           <div className="text-left flex-1">
              <div className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">বর্তমান ইউজার</div>
              <div className="text-sm font-bold text-gray-800">{user?.name}</div>
              <div className="text-[11px] text-gray-500">{user?.email}</div>
           </div>
        </div>

        {/* Backup Status List */}
        <div className="w-full space-y-3 mb-8">
           <div className="flex justify-between items-center p-4 bg-white border border-gray-100 rounded-xl">
              <div className="flex items-center gap-3">
                 <Database size={20} className="text-gray-400" />
                 <span className="text-sm font-medium text-gray-700">ব্যাকআপ ফাইল সাইজ</span>
              </div>
              <span className="text-sm font-bold text-gray-900">৪২০ কেবি</span>
           </div>

           <div className="flex justify-between items-center p-4 bg-white border border-gray-100 rounded-xl">
              <div className="flex items-center gap-3">
                 <RefreshCw size={20} className="text-gray-400" />
                 <span className="text-sm font-medium text-gray-700">শেষ ব্যাকআপ সময়</span>
              </div>
              <span className="text-xs font-bold text-red-600">{lastSynced || 'কখনো করা হয়নি'}</span>
           </div>
        </div>

        {/* Success Alert */}
        {syncSuccess && (
          <div className="w-full bg-green-50 text-green-700 p-4 rounded-xl flex items-center gap-3 mb-6 animate-bounce">
             <CheckCircle2 size={24} />
             <span className="text-sm font-bold">সফলভাবে গুগল ড্রাইভে ব্যাকআপ নেওয়া হয়েছে!</span>
          </div>
        )}

        {/* Action Button */}
        <button 
          onClick={handleSync}
          disabled={isSyncing}
          className={`w-full py-4 rounded-full font-bold text-white shadow-lg flex items-center justify-center gap-3 transition-all ${
            isSyncing ? 'bg-gray-400 cursor-not-allowed' : 'bg-[#D32F2F] active:scale-95 hover:bg-red-700'
          }`}
        >
          {isSyncing ? <RefreshCw className="animate-spin" size={20} /> : <CloudUpload size={20} />}
          {isSyncing ? 'ব্যাকআপ হচ্ছে...' : 'এখনই ব্যাকআপ নিন'}
        </button>

        <p className="mt-4 text-[11px] text-gray-400 leading-relaxed">
          আপনার ফোনের ইন্টারনাল স্টোরেজ থেকে সব কন্টাক্ট এবং লেনদেনের ডাটা নিরাপদভাবে গুগল ড্রাইভের একটি হিডেন ফোল্ডারে সেভ করা হবে।
        </p>

        <div className="mt-8 flex items-center gap-2 text-gray-300">
           <ShieldCheck size={16} />
           <span className="text-[10px] font-bold uppercase tracking-widest">Google Secured Storage</span>
        </div>
      </div>
    </div>
  );
};

export default CloudBackup;

{
  "name": "Dokan Khata - Business Ledger",
