import React, { useState, useEffect, useRef } from 'react';
import { ArrowLeft, Send, Sparkles, Bot, TrendingUp, Info, Zap, ShoppingBag } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { Contact, SalePurchaseRecord } from '../types';

interface AIChatViewProps {
  onBack: () => void;
  contacts: Contact[];
  records: SalePurchaseRecord[];
}

interface Message {
  role: 'user' | 'ai';
  text: string;
}

const AIChatView: React.FC<AIChatViewProps> = ({ onBack, contacts, records }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'ai', text: 'আসসালামু আলাইকুম! আমি আপনার দোকানের এআই অ্যাসিস্ট্যান্ট। আমি আপনার হিসাব বিশ্লেষণ করেছি। আজ কি জানতে চান?' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const generateAIResponse = async (userInput: string) => {
    setIsTyping(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Prepare ledger summary for context
    const receivable = contacts.reduce((acc, curr) => curr.balance > 0 ? acc + curr.balance : acc, 0);
    const payable = Math.abs(contacts.reduce((acc, curr) => curr.balance < 0 ? acc + curr.balance : acc, 0));
    const totalSales = records.filter(r => r.type === 'SALE').reduce((acc, curr) => acc + curr.amount, 0);

    const context = `
      User Business Data:
      - Total Receivable (পাবো): ${receivable} BDT
      - Total Payable (দেবো): ${payable} BDT
      - Total Sales (মোট বিক্রি): ${totalSales} BDT
      - Number of Contacts: ${contacts.length}

      Task: Act as a professional shop accounting assistant. Provide advice in Bengali.
      User asked: ${userInput}
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: context,
        config: {
          systemInstruction: "You are a helpful AI business assistant for shop owners in Bangladesh. You analyze their ledger data and provide market trends. Always speak politely in Bengali. If they ask about market price, give a professional estimation of currently trending items in local grocery/telecom markets."
        }
      });

      setMessages(prev => [...prev, { role: 'ai', text: response.text || 'দুঃখিত, আমি এই মুহূর্তে বুঝতে পারছি না।' }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', text: 'ইন্টারনেট কানেকশন চেক করুন। আবার চেষ্টা করুন।' }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleSend = () => {
    if (!input.trim()) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    generateAIResponse(userMsg);
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col h-[calc(100vh-64px)]">
      <header className="flex items-center gap-4 p-4 bg-white border-b border-gray-100 shadow-sm">
        <button onClick={onBack} className="text-gray-600"><ArrowLeft size={24} /></button>
        <div className="flex items-center gap-2">
          <div className="bg-purple-100 p-2 rounded-lg text-purple-600">
            <Bot size={20} />
          </div>
          <h2 className="text-lg font-bold">এআই অ্যাসিস্ট্যান্ট</h2>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-2xl text-sm shadow-sm ${
              m.role === 'user' 
                ? 'bg-purple-600 text-white rounded-br-none' 
                : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-gray-100 p-3 rounded-2xl flex gap-1">
              <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-gray-100 space-y-3">
        {/* Quick Tips */}
        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
          <button 
            onClick={() => { setInput('আজকের হিসাবের সারাংশ কি?'); }}
            className="whitespace-nowrap bg-purple-50 text-purple-700 px-3 py-1.5 rounded-full text-[11px] font-bold border border-purple-100 flex items-center gap-1"
          >
            <Zap size={12} /> আজকের সারাংশ
          </button>
          <button 
            onClick={() => { setInput('বর্তমানে মার্কেটে কোন জিনিসের দাম বাড়ছে?'); }}
            className="whitespace-nowrap bg-blue-50 text-blue-700 px-3 py-1.5 rounded-full text-[11px] font-bold border border-blue-100 flex items-center gap-1"
          >
            <TrendingUp size={12} /> মার্কেট ট্রেন্ড
          </button>
          <button 
            onClick={() => { setInput('বেস্ট সেলিং প্রোডাক্ট লিস্ট দাও'); }}
            className="whitespace-nowrap bg-orange-50 text-orange-700 px-3 py-1.5 rounded-full text-[11px] font-bold border border-orange-100 flex items-center gap-1"
          >
            <ShoppingBag size={12} /> বেস্ট প্রোডাক্ট
          </button>
        </div>

        <div className="flex gap-2">
          <input 
            type="text" 
            placeholder="আপনার প্রশ্ন লিখুন..." 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            className="flex-1 bg-gray-100 border-none rounded-xl px-4 py-3 text-sm focus:ring-1 focus:ring-purple-400 outline-none"
          />
          <button 
            onClick={handleSend}
            className="bg-purple-600 text-white p-3 rounded-xl shadow-md active:scale-90 transition-transform"
          >
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChatView;

