interface AddContactFormProps {
  onBack: () => void;
  onSave: (contact: Contact) => void;
}

const AddContactForm: React.FC<AddContactFormProps> = ({ onBack, onSave }) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [type, setType] = useState<ContactType>(ContactType.CUSTOMER);
  const [initialBalance, setInitialBalance] = useState('');
  const [isPickerSupported, setIsPickerSupported] = useState(true);

  const handleSave = () => {
    if (!name || !phone) return;

    const newContact: Contact = {
      id: Date.now().toString(),
      name,
      phone,
      type,
      balance: parseFloat(initialBalance || '0') * (type === ContactType.CUSTOMER ? 1 : -1),
      lastActivity: 'এখনই',
      transactions: []
    };

    onSave(newContact);
  };

  const handleContactPicker = async () => {
    try {
      // Security Check: The Contacts API can only be used in the top-level browsing context (not in an iframe)
      if (window.self !== window.top) {
        alert('নিরাপত্তার কারণে আইফ্রেম (iframe) থেকে ফোনবুক এক্সেস করা সম্ভব নয়। অনুগ্রহ করে সরাসরি ব্রাউজারে অ্যাপটি ওপেন করে চেষ্টা করুন।');
        setIsPickerSupported(false);
        return;
      }

      // Check if Contact Picker API is supported
      if ('contacts' in navigator && 'select' in (navigator as any).contacts) {
        const props = ['name', 'tel'];
        const opts = { multiple: false };
        const contacts = await (navigator as any).contacts.select(props, opts);

        if (contacts && contacts.length > 0) {
          const selectedContact = contacts[0];
          // Set name
          if (selectedContact.name && selectedContact.name.length > 0) {
            setName(selectedContact.name[0]);
          }
          // Set phone (remove extra spaces and characters)
          if (selectedContact.tel && selectedContact.tel.length > 0) {
            const rawPhone = selectedContact.tel[0];
            const cleanPhone = rawPhone.replace(/[^\d+]/g, '');
            setPhone(cleanPhone);
          }
        }
      } else {
        setIsPickerSupported(false);
        alert('আপনার ব্রাউজারটি ফোনবুক থেকে কন্টাক্ট নেওয়ার ফিচারটি সাপোর্ট করছে না। অনুগ্রহ করে ম্যানুয়ালি নাম-নম্বর লিখুন।');
      }
    } catch (err) {
      console.error('Contact picker error:', err);
      // Handle specific "top frame" error message gracefully if the check above missed something
      if (err instanceof Error && err.message.includes('top frame')) {
        alert('নিরাপত্তার কারণে এই পরিবেশে ফোনবুক ব্যবহার করা যাবে না।');
      }
    }
  };

  return (
    <div className="bg-white min-h-full flex flex-col">
      <header className="flex items-center gap-4 p-4 border-b border-gray-100">
        <button onClick={onBack} className="text-gray-600"><ArrowLeft size={24} /></button>
        <h2 className="text-lg font-bold">নতুন কাস্টমার/সাপ্লায়ার</h2>
      </header>

      <div className="p-6 space-y-6">
        {/* Profile Pic Placeholder */}
        <div className="flex justify-center relative">
          <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center text-gray-400">
            <User size={48} />
          </div>
          <button className="absolute bottom-0 translate-x-10 bg-white shadow p-1 rounded-lg border border-gray-200">
            <Camera size={18} className="text-gray-600" />
          </button>
        </div>

        {/* Type Toggle */}
        <div className="flex gap-4">
          <button 
            onClick={() => setType(ContactType.CUSTOMER)}
            className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${
              type === ContactType.CUSTOMER ? 'border-[#D32F2F] bg-red-50 text-[#D32F2F]' : 'border-gray-200 text-gray-500'
            }`}
          >
            <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${
              type === ContactType.CUSTOMER ? 'border-[#D32F2F]' : 'border-gray-400'
            }`}>
              {type === ContactType.CUSTOMER && <div className="w-2 h-2 bg-[#D32F2F] rounded-full" />}
            </div>
            কাস্টমার
          </button>
          <button 
            onClick={() => setType(ContactType.SUPPLIER)}
            className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${
              type === ContactType.SUPPLIER ? 'border-[#D32F2F] bg-red-50 text-[#D32F2F]' : 'border-gray-200 text-gray-500'
            }`}
          >
            <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${
              type === ContactType.SUPPLIER ? 'border-[#D32F2F]' : 'border-gray-400'
            }`}>
              {type === ContactType.SUPPLIER && <div className="w-2 h-2 bg-[#D32F2F] rounded-full" />}
            </div>
            সাপ্লায়ার
          </button>
        </div>

        <button 
          onClick={handleContactPicker}
          className="w-full flex items-center justify-center gap-2 p-4 bg-blue-50 text-blue-700 rounded-xl font-bold border border-blue-100 active:scale-95 transition-all"
        >
           <User size={20} /> ফোনবুক থেকে যোগ করি
        </button>

        {!isPickerSupported && (
          <div className="bg-orange-50 p-3 rounded-lg flex items-start gap-2 text-orange-700 text-xs">
            <Info size={14} className="mt-0.5 shrink-0" />
            <span>আপনার ফোনের কন্টাক্ট লিস্ট থেকে সরাসরি কন্টাক্ট নিতে Chrome বা Safari ব্রাউজার ব্যবহার করুন এবং নিশ্চিত করুন আপনি কোনো ফ্রেমের ভেতর নেই।</span>
          </div>
        )}

        <div className="space-y-4">
          <div className="relative">
            <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
            <input 
              type="text" 
              placeholder="নাম" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full p-4 pl-12 bg-white border border-gray-200 rounded-xl outline-none focus:border-red-400 transition-colors"
            />
          </div>

          <div className="relative">
            <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
