  records: SalePurchaseRecord[];
}

interface Message {
  role: 'user' | 'ai';
  text: string;
}

const FormattedText: React.FC<{ text: string; isAi: boolean }> = ({ text, isAi }) => {
  // Simple markdown-lite parser for bold and lists
  const lines = text.split('\n');

  return (
    <div className="space-y-1.5">
      {lines.map((line, i) => {
        const trimmedLine = line.trim();
        if (!trimmedLine) return <div key={i} className="h-2" />;

        // Detect bullet points (starting with * or -)
        const isBullet = trimmedLine.startsWith('* ') || trimmedLine.startsWith('- ');
        const content = isBullet ? trimmedLine.substring(2) : line;

        // Process bold text **text**
        const parts = content.split(/(\*\*.*?\*\*)/g);
        const renderedParts = parts.map((part, index) => {
          if (part.startsWith('**') && part.endsWith('**')) {
            return (
              <strong key={index} className={`font-black ${isAi ? 'text-purple-900' : 'text-white'}`}>
                {part.slice(2, -2)}
              </strong>
            );
          }
          return part;
        });

        return (
          <div key={i} className={`${isBullet ? 'pl-4 flex gap-2' : ''}`}>
            {isBullet && <span className={`${isAi ? 'text-purple-500' : 'text-purple-200'} font-bold`}>•</span>}
            <span className="leading-relaxed">{renderedParts}</span>
          </div>
        );
      })}
    </div>
  );
};

const AIChatView: React.FC<AIChatViewProps> = ({ onBack, contacts, records }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'ai', text: 'আসসালামু আলাইকুম! আমি আপনার দোকানের এআই অ্যাসিস্ট্যান্ট।\n\nআমি আপনার **হিসাব বিশ্লেষণ** করেছি। আজ আপনার ব্যবসার জন্য কোনো পরামর্শ বা **মার্কেট ট্রেন্ড** সম্পর্কে জানতে চান?' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const generateAIResponse = async (userInput: string) => {
    setIsTyping(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const receivable = contacts.reduce((acc, curr) => curr.balance > 0 ? acc + curr.balance : acc, 0);
    const payable = Math.abs(contacts.reduce((acc, curr) => curr.balance < 0 ? acc + curr.balance : acc, 0));
    const totalSales = records.filter(r => r.type === 'SALE').reduce((acc, curr) => acc + curr.amount, 0);

    const context = `
      User Business Data:
      - Total Receivable (পাবো): ${receivable} BDT
      - Total Payable (দেবো): ${payable} BDT
      - Total Sales (মোট বিক্রি): ${totalSales} BDT
      - Number of Contacts: ${contacts.length}

      Task: Act as a professional shop accounting assistant for a Bangladeshi merchant.
      User asked: ${userInput}
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: context,
        config: {
          systemInstruction: `You are a helpful AI business assistant for shop owners in Bangladesh. 
          FORMATTING RULES:
          1. Use **bold** for all numbers, monetary values, and important keywords.
          2. Use bullet points (starting with '*') for lists or step-by-step advice.
          3. Keep sentences concise and easy to read on mobile.
          4. Always respond in polite, professional Bengali.
          5. Structure your advice into logical sections using double newlines.

          Example: 
          আপনার বর্তমান **মোট বাকি** হচ্ছে **৳ ৫০০০**। 
          পরামর্শ:
          * কাস্টমারকে **এসএমএস** পাঠান।
          * নতুন **স্টক** চেক করুন।`
        }
      });

      setMessages(prev => [...prev, { role: 'ai', text: response.text || 'দুঃখিত, আমি এই মুহূর্তে বুঝতে পারছি না।' }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', text: 'ইন্টারনেট কানেকশন চেক করুন। আবার চেষ্টা করুন।' }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleSend = () => {
    if (!input.trim()) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    generateAIResponse(userMsg);
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col h-[calc(100vh-64px)]">
      <header className="flex items-center gap-4 p-4 bg-white border-b border-gray-100 shadow-sm">
