            <Bot size={20} />
          </div>
          <h2 className="text-lg font-bold">এআই অ্যাসিস্ট্যান্ট</h2>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[88%] p-3.5 rounded-2xl text-[13px] shadow-sm ${
              m.role === 'user' 
                ? 'bg-purple-600 text-white rounded-br-none' 
                : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none'
            }`}>
              <FormattedText text={m.text} isAi={m.role === 'ai'} />
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-gray-100 p-3 rounded-2xl flex gap-1.5 items-center">
              <div className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce"></div>
