              <span className="text-[10px] text-gray-400 font-bold ml-1">এআই চিন্তা করছে...</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-gray-100 space-y-3">
        {/* Quick Tips */}
        <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
          <button 
            onClick={() => { setInput('আজকের হিসাবের সারাংশ কি?'); }}
