          >
            <Zap size={12} /> আজকের সারাংশ
          </button>
          <button 
            onClick={() => { setInput('বর্তমানে মার্কেটে কোন জিনিসের দাম বাড়ছে?'); }}
            className="whitespace-nowrap bg-blue-50 text-blue-700 px-3 py-1.5 rounded-full text-[11px] font-bold border border-blue-100 flex items-center gap-1 active:scale-95 transition-transform"
          >
            <TrendingUp size={12} /> মার্কেট ট্রেন্ড
          </button>
          <button 
            onClick={() => { setInput('বেস্ট সেলিং প্রোডাক্ট লিস্ট দাও'); }}
            className="whitespace-nowrap bg-orange-50 text-orange-700 px-3 py-1.5 rounded-full text-[11px] font-bold border border-orange-100 flex items-center gap-1 active:scale-95 transition-transform"
          >
            <ShoppingBag size={12} /> বেস্ট প্রোডাক্ট
          </button>
        </div>

        <div className="flex gap-2">
          <input 
            type="text" 
            placeholder="আপনার প্রশ্ন লিখুন..." 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            className="flex-1 bg-gray-100 border-none rounded-xl px-4 py-3 text-sm focus:ring-1 focus:ring-purple-400 outline-none transition-shadow"
          />
          <button 
            onClick={handleSend}
