  }, [stockItems]);

  const addContact = (newContact: Contact) => {
    setContacts(prev => [...prev, newContact]);
    setCurrentView('TALLY');
  };

  const addSalePurchaseRecord = (record: SalePurchaseRecord) => {
    setSalePurchaseRecords(prev => [...prev, record]);
  };

  const updateContactTransactions = (contactId: string, transaction: Transaction) => {
    setContacts(prev => prev.map(c => {
      if (c.id === contactId) {
        const newBalance = transaction.type === 'DUE_GIVEN' 
          ? c.balance + transaction.amount 
          : c.balance - transaction.amount;
        return {
          ...c,
          balance: newBalance,
          lastActivity: 'এখনই',
          transactions: [transaction, ...c.transactions]
        };
      }
      return c;
    }));
  };

  const handleUpdateStock = (updatedItems: StockItem[]) => {
    setStockItems(updatedItems);
  };

  const selectedContact = useMemo(() => 
    contacts.find(c => c.id === selectedContactId), 
    [contacts, selectedContactId]
  );

  const renderView = () => {
    switch (currentView) {
      case 'TALLY':
        return (
          <TallyView 
            contacts={contacts} 
            onSelectContact={(id) => {
              setSelectedContactId(id);
              setCurrentView('CONTACT_DETAILS');
            }}
            onAddContact={() => setCurrentView('ADD_CONTACT')}
            onNavigate={setCurrentView}
          />
        );
      case 'CASHBOX':
        return <CashboxView />;
      case 'ADD_CONTACT':
        return (
          <AddContactForm 
            onBack={() => setCurrentView('TALLY')} 
            onSave={addContact} 
          />
        );
      case 'CONTACT_DETAILS':
        return selectedContact ? (
          <ContactDetails 
            contact={selectedContact} 
            onBack={() => setCurrentView('TALLY')}
            onAddTransaction={(t) => updateContactTransactions(selectedContact.id, t)}
            onShowRecommendations={() => setCurrentView('AI_RECOMMENDATIONS')}
          />
        ) : null;
      case 'BECHA_KENA':
        return (
          <BechaKenaView 
            records={salePurchaseRecords}
            onBack={() => setCurrentView('TALLY')}
            onAddRecord={addSalePurchaseRecord}
          />
        );
      case 'CLOUD_BACKUP':
        return (
          <CloudBackup 
            data={{ contacts, salePurchaseRecords }}
            onBack={() => setCurrentView('TALLY')}
          />
        );
      case 'AI_CHAT':
        return (
          <AIChatView 
            contacts={contacts}
            records={salePurchaseRecords}
            onBack={() => setCurrentView('TALLY')}
          />
        );
      case 'AI_RECOMMENDATIONS':
        return (
          <SmartRecommendationsView 
            contact={selectedContact || null}
            allRecords={salePurchaseRecords}
            onBack={() => setCurrentView(selectedContact ? 'CONTACT_DETAILS' : 'TALLY')}
          />
        );
      case 'STOCK':
        return (
          <StockView 
            items={stockItems}
            onBack={() => setCurrentView('TALLY')}
            onUpdateStock={handleUpdateStock}
          />
        );
      default:
        return <div className="p-10 text-center">Work in Progress</div>;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen flex flex-col relative shadow-xl">
      {/* Header */}
      <header className="bg-[#D32F2F] text-white px-4 py-3 sticky top-0 z-40">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setIsSidebarOpen(true)}>
            <div className="bg-white/20 p-1 rounded-md">
              <span className="text-sm font-bold">saiful telec...</span>
            </div>
            <ChevronDown size={16} />
          </div>

          <div className="flex items-center gap-4">
            <div 
              onClick={() => setCurrentView('AI_CHAT')}
              className="flex flex-col items-center cursor-pointer animate-pulse"
            >
              <Sparkles size={24} className="text-yellow-300" />
              <span className="text-[10px] mt-1 text-white">এআই</span>
            </div>
            <div className="relative">
              <Bell size={24} />
              <span className="absolute -top-1 -right-1 bg-white text-[#D32F2F] text-[10px] font-bold rounded-full w-4 h-4 flex items-center justify-center">99+</span>
              <span className="block text-[10px] mt-1 text-center">ইনবক্স</span>
            </div>
            <div className="flex flex-col items-center">
              <HelpCircle size={24} />
              <span className="text-[10px] mt-1">হেল্প</span>
            </div>
          </div>
        </div>
        <div className="mt-1 text-xs font-semibold opacity-90">স্ট্যান্ডার্ড</div>
      </header>

      {/* Sidebar */}
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        onNavigate={(view) => {
          setCurrentView(view);
          setIsSidebarOpen(false);
        }}
      />

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20">
        {renderView()}
      </main>

      {/* Bottom Navigation */}
      {['TALLY', 'CASHBOX', 'WALLET', 'MENU'].includes(currentView) && (
        <Navigation currentView={currentView} onNavigate={setCurrentView} />
      )}
    </div>
  );
};

export default App;

