interface StockViewProps {
  items: StockItem[];
  onBack: () => void;
  onUpdateStock: (items: StockItem[]) => void;
}

const StockView: React.FC<StockViewProps> = ({ items, onBack, onUpdateStock }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<StockItem>>({});
  const [isAdding, setIsAdding] = useState(false);

  const totalBuyingValuation = items.reduce((acc, curr) => acc + (curr.quantity * curr.buyingPrice), 0);
  const totalSellingValuation = items.reduce((acc, curr) => acc + (curr.quantity * curr.sellingPrice), 0);

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleEditClick = (item: StockItem) => {
    setEditingId(item.id);
    setEditForm(item);
  };

  const handleSave = () => {
    if (editingId && editForm.name) {
      const updated = items.map(item => item.id === editingId ? { ...item, ...editForm, lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' }) } : item);
      onUpdateStock(updated as StockItem[]);
      setEditingId(null);
    } else if (isAdding && editForm.name) {
      const newItem: StockItem = {
        id: Date.now().toString(),
        name: editForm.name || '',
        quantity: editForm.quantity || 0,
        unit: editForm.unit || 'পিস',
        buyingPrice: editForm.buyingPrice || 0,
        sellingPrice: editForm.sellingPrice || 0,
        lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' })
      };
      onUpdateStock([...items, newItem]);
      setIsAdding(false);
      setEditForm({});
    }
  };

  const handleDelete = (id: string) => {
    if (confirm('আপনি কি এই আইটেমটি ডিলিট করতে চান?')) {
      onUpdateStock(items.filter(item => item.id !== id));
    }
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-100 shadow-sm sticky top-0 z-10">
