            <div className="bg-red-100 p-2 rounded-lg text-red-600">
              <Package size={20} />
            </div>
            <h2 className="text-lg font-bold">স্টক হিসাব</h2>
          </div>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="bg-red-600 text-white p-2 rounded-full shadow-md active:scale-90 transition-all"
        >
          <Plus size={20} />
        </button>
