        <div className="bg-white p-4 rounded-2xl shadow-sm border-b-4 border-blue-500 hover:shadow-md transition-shadow duration-300">
          <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">মোট কেনা মূল্য</div>
          <div className="text-xl font-black text-blue-600">৳ {totalBuyingValuation.toLocaleString('bn-BD')}</div>
        </div>
        <div className="bg-white p-4 rounded-2xl shadow-sm border-b-4 border-green-500 hover:shadow-md transition-shadow duration-300">
          <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">মোট সম্ভাব্য বিক্রি</div>
