            type="text" 
            placeholder="পণ্য খুঁজুন..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-white border border-gray-100 rounded-xl pl-10 pr-4 py-2.5 text-sm focus:ring-1 focus:ring-red-400 outline-none shadow-sm"
          />
