          <Calendar size={16} className="text-red-500" /> তারিখ
        </button>
      </div>

      {/* Stock List */}
      <div className="flex-1 bg-white rounded-t-[32px] shadow-inner p-4 space-y-4">
        {isAdding && (
          <div className="bg-red-50 p-4 rounded-2xl border border-red-100 space-y-3 animate-in slide-in-from-top-4 duration-300">
