            </button>
          </div>
        )}

        {filteredItems.map((item) => (
          <div 
            key={item.id}
            className="group relative bg-white border border-gray-100 rounded-2xl p-4 shadow-sm hover:shadow-md hover:border-gray-300 transition-all duration-300"
