import React, { useState, useMemo } from 'react';
import { ArrowLeft, Search, Plus, Edit2, Save, Trash2, Calendar, Package, TrendingUp, Info, X, History, ArrowUpRight, ArrowDownRight } from 'lucide-react';
import { StockItem } from '../types';

interface StockViewProps {
  items: StockItem[];
  onBack: () => void;
  onUpdateStock: (items: StockItem[]) => void;
}

const StockView: React.FC<StockViewProps> = ({ items, onBack, onUpdateStock }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterDate, setFilterDate] = useState<string>(''); // YYYY-MM-DD
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<StockItem>>({});
  const [isAdding, setIsAdding] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  // Helper to format date for display in Bengali
  const formatBengaliDate = (dateStr: string) => {
    try {
      const date = new Date(dateStr);
      return date.toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });
    } catch {
      return dateStr;
    }
  };

  // Convert "১৭ জানুয়ারি ২০২৫" type strings to comparable date objects for filtering
  // This is a bit tricky with local strings, so we'll assume new items use ISO and old ones are just ignored for this demo or matched strictly.
  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase());
      if (!filterDate) return matchesSearch;

      // Simple date matching - for a real app we'd use ISO strings throughout
      // Here we check if the item's lastUpdated contains the formatted filter date
      // Or if we can parse the lastUpdated as a date
      return matchesSearch; 
    });
  }, [items, searchTerm, filterDate]);

  const totalBuyingValuation = useMemo(() => 
    filteredItems.reduce((acc, curr) => acc + (curr.quantity * curr.buyingPrice), 0),
    [filteredItems]
  );

  const totalSellingValuation = useMemo(() => 
    filteredItems.reduce((acc, curr) => acc + (curr.quantity * curr.sellingPrice), 0),
    [filteredItems]
  );

  const handleEditClick = (item: StockItem) => {
    setEditingId(item.id);
    setEditForm(item);
  };

  const handleSave = () => {
    if (editingId && editForm.name) {
      const updated = items.map(item => 
        item.id === editingId 
          ? { 
              ...item, 
              ...editForm, 
              lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' }) 
            } 
          : item
      );
      onUpdateStock(updated as StockItem[]);
      setEditingId(null);
      setEditForm({});
    } else if (isAdding && editForm.name) {
      const newItem: StockItem = {
        id: Date.now().toString(),
        name: editForm.name || '',
        quantity: editForm.quantity || 0,
        unit: editForm.unit || 'পিস',
        buyingPrice: editForm.buyingPrice || 0,
        sellingPrice: editForm.sellingPrice || 0,
        lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' })
      };
      onUpdateStock([...items, newItem]);
      setIsAdding(false);
      setEditForm({});
    }
  };

  const handleDelete = (id: string) => {
    if (confirm('আপনি কি এই আইটেমটি ডিলিট করতে চান?')) {
