import React, { useState, useRef, useEffect } from 'react';
import { 
  ArrowLeft, 
  MoreVertical, 
  Calendar, 
  Camera, 
  Plus, 
  Minus, 
  MessageSquare, 
  FileText, 
  ArrowUpRight, 
  ArrowDownRight,
  ChevronDown,
  Sparkles,
  Edit2,
  Trash2
} from 'lucide-react';
import { Contact, Transaction } from '../types';

interface ContactDetailsProps {
  contact: Contact;
  onBack: () => void;
  onAddTransaction: (t: Transaction) => void;
  onShowRecommendations?: () => void;
  onEditContact: (contact: Contact) => void;
  onDeleteContact: (id: string) => void;
}

const ContactDetails: React.FC<ContactDetailsProps> = ({ 
  contact, 
  onBack, 
  onAddTransaction, 
  onShowRecommendations,
  onEditContact,
  onDeleteContact
}) => {
  const [dilamAmount, setDilamAmount] = useState('');
  const [pelamAmount, setPelamAmount] = useState('');
  const [description, setDescription] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const historyRef = useRef<HTMLDivElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSubmit = (type: 'DUE_GIVEN' | 'RECEIVED') => {
    const amount = parseFloat(type === 'DUE_GIVEN' ? dilamAmount : pelamAmount);
    if (!amount || isNaN(amount)) return;

    const newTransaction: Transaction = {
      id: Date.now().toString(),
      type,
      amount,
      description,
      date: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' })
    };

    onAddTransaction(newTransaction);
    setDilamAmount('');
    setPelamAmount('');
    setDescription('');
