  const formatBengaliDate = (dateStr: string) => {
    try {
      const date = new Date(dateStr);
      return date.toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });
    } catch {
      return dateStr;
    }
  };

  // Convert "১৭ জানুয়ারি ২০২৫" type strings to comparable date objects for filtering
  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase());
      if (!filterDate) return matchesSearch;
      return matchesSearch; 
    });
  }, [items, searchTerm, filterDate]);

