          সোশ্যাল মিডিয়ায় এর চাহিদা গত সপ্তাহে **১৫%** বেড়েছে।"
          `
        }
      });

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

      setMessages(prev => [...prev, { 
        role: 'ai', 
        text: response.text || 'দুঃখিত, কোনো তথ্য পাওয়া যায়নি।',
        sources: groundingChunks
      }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', text: 'সার্ভারে সমস্যা হয়েছে। পুনরায় চেষ্টা করুন।' }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleSend = () => {
    if (!input.trim()) return;
    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    generateAIResponse(userMsg);
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col h-[calc(100vh-64px)]">
      <header className="flex items-center gap-4 p-4 bg-white border-b border-gray-100 shadow-sm sticky top-0 z-20">
