const FormattedText: React.FC<{ text: string; isAi: boolean }> = ({ text, isAi }) => {
  const lines = text.split('\n');

  return (
    <div className="space-y-1.5">
      {lines.map((line, i) => {
        const trimmedLine = line.trim();
        if (!trimmedLine) return <div key={i} className="h-2" />;

        const isBullet = trimmedLine.startsWith('* ') || trimmedLine.startsWith('- ');
        const content = isBullet ? trimmedLine.substring(2) : line;

        const parts = content.split(/(\*\*.*?\*\*)/g);
        const renderedParts = parts.map((part, index) => {
          if (part.startsWith('**') && part.endsWith('**')) {
            return (
              <strong key={index} className={`font-black ${isAi ? 'text-purple-900' : 'text-white'}`}>
                {part.slice(2, -2)}
              </strong>
            );
          }
          return part;
        });

        return (
          <div key={i} className={`${isBullet ? 'pl-4 flex gap-2' : ''}`}>
            {isBullet && <span className={`${isAi ? 'text-purple-500' : 'text-purple-200'} font-bold`}>•</span>}
            <span className="leading-relaxed">{renderedParts}</span>
          </div>
        );
      })}
    </div>
  );
};

const AIChatView: React.FC<AIChatViewProps> = ({ onBack, contacts, records, persistedMessages, onMessagesUpdate, onClearChat }) => {
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Derive recent questions from message history for quick recall
  const recentQueries = Array.from(new Set(
    persistedMessages
      .filter(m => m.role === 'user')
      .map(m => m.text)
  )).reverse().slice(0, 5);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [persistedMessages, isTyping]);

  const generateAIResponse = async (userInput: string) => {
    setIsTyping(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const receivable = contacts.reduce((acc, curr) => curr.balance > 0 ? acc + curr.balance : acc, 0);
    const payable = Math.abs(contacts.reduce((acc, curr) => curr.balance < 0 ? acc + curr.balance : acc, 0));
    const totalSales = records.filter(r => r.type === 'SALE').reduce((acc, curr) => acc + curr.amount, 0);

    const context = `
      Current Local Store Context:
      - Total Receivable: ${receivable} BDT
      - Total Payable: ${payable} BDT
      - Total Sales: ${totalSales} BDT
      - Total Contacts: ${contacts.length}

      User Inquiry: ${userInput}
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: context,
        config: {
          tools: [{ googleSearch: {} }],
          systemInstruction: `You are a highly advanced AI Business Strategist for Bangladeshi shop owners.
          CAPABILITIES:
          1. Use Google Search to find real-time product prices, social media trends (Facebook/TikTok trends in BD), and market rankings.
          2. If the user asks about a product, provide its current market price, Google/E-commerce ranking, and technical specifications.
          3. Compare local store data with market trends to give growth advice.

          FORMATTING RULES:
          - Use **bold** for prices, percentages, and rankings.
          - Use bullet points for clear specifications.
          - Always respond in professional Bengali.
          - If information is found via search, mention the ranking status in Bangladesh.

          EXAMPLE OUTPUT:
          "বর্তমানে **Samsung Galaxy S23** বাংলাদেশে গুগল র‍্যাঙ্কিং-এ **৩য়** অবস্থানে আছে। 
          বর্তমান বাজারমূল্য: **৳৯৫,০০০**। 
          সোশ্যাল মিডিয়ায় এর চাহিদা গত সপ্তাহে **১৫%** বেড়েছে।"
          `
        }
      });

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

      onMessagesUpdate([...persistedMessages, { role: 'user', text: userInput }, { 
        role: 'ai', 
        text: response.text || 'দুঃখিত, কোনো তথ্য পাওয়া যায়নি।',
        sources: groundingChunks
      }]);
    } catch (error) {
      onMessagesUpdate([...persistedMessages, { role: 'user', text: userInput }, { role: 'ai', text: 'সার্ভারে সমস্যা হয়েছে। পুনরায় চেষ্টা করুন।' }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleSend = () => {
    if (!input.trim()) return;
    const userMsg = input;
    // Update local messages first for responsiveness if needed, 
    // but here we wait for the full turn to keep persisted history consistent.
    onMessagesUpdate([...persistedMessages, { role: 'user', text: userMsg }]);
    setInput('');
    generateAIResponse(userMsg);
  };

  const handleClear = () => {
    if (confirm('আপনি কি নিশ্চিত যে আপনি পুরো চ্যাট হিস্ট্রি মুছে ফেলতে চান?')) {
      onClearChat();
    }
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col h-[calc(100vh-64px)]">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-100 shadow-sm sticky top-0 z-20">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="text-gray-600 active:scale-90 transition-transform"><ArrowLeft size={24} /></button>
          <div className="flex items-center gap-2">
            <div className="bg-purple-600 p-2 rounded-lg text-white shadow-lg shadow-purple-100">
              <Bot size={20} />
            </div>
            <div>
              <h2 className="text-sm font-bold text-gray-900 leading-none">স্মার্ট এআই অ্যাসিস্ট্যান্ট</h2>
              <div className="flex items-center gap-1 mt-0.5">
                <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">রিয়েল-টাইম সার্চ এনাবলড</span>
              </div>
            </div>
          </div>
        </div>
        <button 
          onClick={handleClear}
          className="p-2 text-gray-400 hover:text-red-600 transition-colors"
          title="চ্যাট ক্লিয়ার করুন"
        >
          <Trash2 size={20} />
        </button>
      </header>

      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {persistedMessages.map((m, i) => (
          <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`max-w-[90%] p-4 rounded-2xl text-[13px] shadow-sm transition-all ${
              m.role === 'user' 
                ? 'bg-purple-600 text-white rounded-br-none' 
                : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none'
            }`}>
              <FormattedText text={m.text} isAi={m.role === 'ai'} />

              {m.sources && m.sources.length > 0 && (
                <div className="mt-4 pt-3 border-t border-gray-50 space-y-2">
