                    <Globe size={10} /> তথ্যের উৎসসমূহ
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {m.sources.map((src, idx) => src.web && (
                      <a 
                        key={idx} 
                        href={src.web.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-1 bg-gray-50 px-2 py-1 rounded-md text-[10px] font-bold text-blue-600 border border-gray-100 hover:bg-blue-50 transition-colors"
                      >
                        <ExternalLink size={10} /> {src.web.title || 'Source'}
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-gray-100 p-4 rounded-2xl flex flex-col gap-2 shadow-sm">
              <div className="flex gap-1.5 items-center">
                <div className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce"></div>
