              <Bot size={20} />
            </div>
            <div>
              <h2 className="text-sm font-bold text-gray-900 leading-none">স্মার্ট এআই অ্যাসিস্ট্যান্ট</h2>
              <div className="flex items-center gap-1 mt-0.5">
                <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">রিয়েল-টাইম সার্চ এনাবলড</span>
              </div>
            </div>
          </div>
        </div>
        <button 
          onClick={handleClear}
          className="p-2 text-gray-400 hover:text-red-600 transition-colors"
          title="চ্যাট ক্লিয়ার করুন"
        >
          <Trash2 size={20} />
        </button>
      </header>

      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {persistedMessages.map((m, i) => (
          <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`max-w-[90%] p-4 rounded-2xl text-[13px] shadow-sm transition-all ${
              m.role === 'user' 
                ? 'bg-purple-600 text-white rounded-br-none' 
                : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none'
            }`}>
              <FormattedText text={m.text} isAi={m.role === 'ai'} />

              {m.sources && m.sources.length > 0 && (
                <div className="mt-4 pt-3 border-t border-gray-50 space-y-2">
                  <div className="flex items-center gap-1.5 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                    <Globe size={10} /> তথ্যের উৎসসমূহ
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {m.sources.map((src, idx) => src.web && (
                      <a 
                        key={idx} 
                        href={src.web.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-1 bg-gray-50 px-2 py-1 rounded-md text-[10px] font-bold text-blue-600 border border-gray-100 hover:bg-blue-50 transition-colors"
                      >
                        <ExternalLink size={10} /> {src.web.title || 'Source'}
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-gray-100 p-4 rounded-2xl flex flex-col gap-2 shadow-sm">
              <div className="flex gap-1.5 items-center">
