                <div className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                <span className="text-[10px] text-gray-400 font-black ml-1 uppercase tracking-tighter">সার্চ ইঞ্জিন স্ক্যান করা হচ্ছে...</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-gray-100 space-y-3 sticky bottom-0 shadow-[0_-4px_15px_rgba(0,0,0,0.03)]">
        {/* Recall & Quick Tips */}
        <div className="space-y-2">
          {recentQueries.length > 0 && (
            <div className="flex items-center gap-2 px-1">
               <RotateCcw size={12} className="text-gray-400" />
               <div className="flex gap-2 overflow-x-auto no-scrollbar py-1">
