                   <button 
                     key={idx}
                     onClick={() => setInput(query)}
                     className="whitespace-nowrap bg-purple-50 text-purple-600 px-3 py-1.5 rounded-lg text-[10px] font-black border border-purple-100 active:scale-95 transition-all hover:bg-purple-100"
                   >
                     {/* Fixed 'unknown' type error by explicitly typing query as string in map and at definition */}
                     {query.length > 25 ? query.substring(0, 25) + '...' : query}
                   </button>
                 ))}
               </div>
            </div>
          )}

          <div className="flex gap-2 overflow-x-auto pb-1 no-scrollbar border-b border-gray-50 pb-2">
            <button 
              onClick={() => setInput('সয়াবিন তেলের বর্তমান বাজার দর কত?')}
              className="whitespace-nowrap bg-gray-50 hover:bg-purple-50 hover:text-purple-700 px-4 py-2.5 rounded-xl text-[11px] font-bold text-gray-600 border border-gray-100 transition-all flex items-center gap-2 active:scale-95"
