  text: string;
  sources?: GroundingChunk[];
}

const FormattedText: React.FC<{ text: string; isAi: boolean }> = ({ text, isAi }) => {
  const lines = text.split('\n');

  return (
    <div className="space-y-1.5">
      {lines.map((line, i) => {
        const trimmedLine = line.trim();
        if (!trimmedLine) return <div key={i} className="h-2" />;

        const isBullet = trimmedLine.startsWith('* ') || trimmedLine.startsWith('- ');
        const content = isBullet ? trimmedLine.substring(2) : line;

        const parts = content.split(/(\*\*.*?\*\*)/g);
        const renderedParts = parts.map((part, index) => {
          if (part.startsWith('**') && part.endsWith('**')) {
            return (
              <strong key={index} className={`font-black ${isAi ? 'text-purple-900' : 'text-white'}`}>
                {part.slice(2, -2)}
              </strong>
            );
          }
          return part;
        });

        return (
          <div key={i} className={`${isBullet ? 'pl-4 flex gap-2' : ''}`}>
            {isBullet && <span className={`${isAi ? 'text-purple-500' : 'text-purple-200'} font-bold`}>•</span>}
            <span className="leading-relaxed">{renderedParts}</span>
          </div>
        );
      })}
    </div>
  );
};

interface AIChatViewProps {
  onBack: () => void;
  contacts: Contact[];
  records: SalePurchaseRecord[];
  persistedMessages: Message[];
  onMessagesUpdate: (msgs: Message[]) => void;
  onClearChat: () => void;
}

const AIChatView: React.FC<AIChatViewProps> = ({ onBack, contacts, records, persistedMessages, onMessagesUpdate, onClearChat }) => {
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Derive recent questions from message history for quick recall
  // Added explicit string[] typing to fix inference issues
  // Use Set<string> to ensure correct type inference for string[]
  const recentQueries: string[] = Array.from(new Set<string>(
    persistedMessages
      .filter(m => m.role === 'user')
      .map(m => m.text)
  )).reverse().slice(0, 5);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [persistedMessages, isTyping]);

  const generateAIResponse = async (userInput: string) => {
    setIsTyping(true);
    // Initialize GoogleGenAI with the API key from environment variables
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const receivable = contacts.reduce((acc, curr) => curr.balance > 0 ? acc + curr.balance : acc, 0);
    const payable = Math.abs(contacts.reduce((acc, curr) => curr.balance < 0 ? acc + curr.balance : acc, 0));
    const totalSales = records.filter(r => r.type === 'SALE').reduce((acc, curr) => acc + curr.amount, 0);

    const context = `
      Current Local Store Context:
      - Total Receivable: ${receivable} BDT
      - Total Payable: ${payable} BDT
      - Total Sales: ${totalSales} BDT
      - Total Contacts: ${contacts.length}

      User Inquiry: ${userInput}
    `;

    try {
      // Using gemini-3-pro-preview for advanced business strategy and web grounding
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: context,
        config: {
          tools: [{ googleSearch: {} }],
          systemInstruction: `You are a highly advanced AI Business Strategist for Bangladeshi shop owners.
          CAPABILITIES:
          1. Use Google Search to find real-time product prices, social media trends (Facebook/TikTok trends in BD), and market rankings.
          2. If the user asks about a product, provide its current market price, Google/E-commerce ranking, and technical specifications.
          3. Compare local store data with market trends to give growth advice.

          FORMATTING RULES:
          - Use **bold** for prices, percentages, and rankings.
          - Use bullet points for clear specifications.
          - Always respond in professional Bengali.
          - If information is found via search, mention the ranking status in Bangladesh.

          EXAMPLE OUTPUT:
          "বর্তমানে **Samsung Galaxy S23** বাংলাদেশে গুগল র‍্যাঙ্কিং-এ **৩য়** অবস্থানে আছে। 
          বর্তমান বাজারমূল্য: **৳৯৫,০০০**। 
          সোশ্যাল মিডিয়ায় এর চাহিদা গত সপ্তাহে **১৫%** বেড়েছে।"
          `
        }
      });

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

      // Accessing the text property directly from the response object
      onMessagesUpdate([...persistedMessages, { role: 'user', text: userInput }, { 
        role: 'ai', 
        text: response.text || 'দুঃখিত, কোনো তথ্য পাওয়া যায়নি।',
        sources: groundingChunks
      }]);
    } catch (error) {
      onMessagesUpdate([...persistedMessages, { role: 'user', text: userInput }, { role: 'ai', text: 'সার্ভারে সমস্যা হয়েছে। পুনরায় চেষ্টা করুন।' }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleSend = () => {
    if (!input.trim()) return;
    const userMsg = input;
    onMessagesUpdate([...persistedMessages, { role: 'user', text: userMsg }]);
    setInput('');
    generateAIResponse(userMsg);
  };

  const handleClear = () => {
    if (confirm('আপনি কি নিশ্চিত যে আপনি পুরো চ্যাট হিস্ট্রি মুছে ফেলতে চান?')) {
      onClearChat();
    }
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col h-[calc(100vh-64px)]">
      <header className="flex items-center justify-between p-4 bg-white border-b border-gray-100 shadow-sm sticky top-0 z-20">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="text-gray-600 active:scale-90 transition-transform"><ArrowLeft size={24} /></button>
          <div className="flex items-center gap-2">
            <div className="bg-purple-600 p-2 rounded-lg text-white shadow-lg shadow-purple-100">
              <Bot size={20} />
            </div>
            <div>
              <h2 className="text-sm font-bold text-gray-900 leading-none">স্মার্ট এআই অ্যাসিস্ট্যান্ট</h2>
              <div className="flex items-center gap-1 mt-0.5">
                <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">রিয়েল-টাইম সার্চ এনাবলড</span>
              </div>
            </div>
          </div>
        </div>
        <button 
          onClick={handleClear}
          className="p-2 text-gray-400 hover:text-red-600 transition-colors"
          title="চ্যাট ক্লিয়ার করুন"
        >
          <Trash2 size={20} />
        </button>
      </header>

      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {persistedMessages.map((m, i) => (
          <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`max-w-[90%] p-4 rounded-2xl text-[13px] shadow-sm transition-all ${
              m.role === 'user' 
                ? 'bg-purple-600 text-white rounded-br-none' 
                : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none'
            }`}>
              <FormattedText text={m.text} isAi={m.role === 'ai'} />

              {m.sources && m.sources.length > 0 && (
                <div className="mt-4 pt-3 border-t border-gray-50 space-y-2">
                  <div className="flex items-center gap-1.5 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                    <Globe size={10} /> তথ্যের উৎসসমূহ
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {m.sources.map((src, idx) => src.web && (
                      <a 
                        key={idx} 
                        href={src.web.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-1 bg-gray-50 px-2 py-1 rounded-md text-[10px] font-bold text-blue-600 border border-gray-100 hover:bg-blue-50 transition-colors"
                      >
                        <ExternalLink size={10} /> {src.web.title || 'Source'}
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white border border-gray-100 p-4 rounded-2xl flex flex-col gap-2 shadow-sm">
              <div className="flex gap-1.5 items-center">
                <div className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                <span className="text-[10px] text-gray-400 font-black ml-1 uppercase tracking-tighter">সার্চ ইঞ্জিন স্ক্যান করা হচ্ছে...</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-gray-100 space-y-3 sticky bottom-0 shadow-[0_-4px_15px_rgba(0,0,0,0.03)]">
        {/* Recall & Quick Tips */}
        <div className="space-y-2">
          {recentQueries.length > 0 && (
            <div className="flex items-center gap-2 px-1">
               <RotateCcw size={12} className="text-gray-400" />
               <div className="flex gap-2 overflow-x-auto no-scrollbar py-1">
                 {recentQueries.map((query: string, idx) => (
                   <button 
                     key={idx}
                     onClick={() => setInput(query)}
                     className="whitespace-nowrap bg-purple-50 text-purple-600 px-3 py-1.5 rounded-lg text-[10px] font-black border border-purple-100 active:scale-95 transition-all hover:bg-purple-100"
                   >
                     {query.length > 25 ? query.substring(0, 25) + '...' : query}
                   </button>
                 ))}
               </div>
            </div>
          )}

          <div className="flex gap-2 overflow-x-auto pb-1 no-scrollbar border-b border-gray-50 pb-2">
            <button 
              onClick={() => setInput('সয়াবিন তেলের বর্তমান বাজার দর কত?')}
              className="whitespace-nowrap bg-gray-50 hover:bg-purple-50 hover:text-purple-700 px-4 py-2.5 rounded-xl text-[11px] font-bold text-gray-600 border border-gray-100 transition-all flex items-center gap-2 active:scale-95"
            >
              <TrendingUp size={12} className="text-purple-600" /> বাজার দর
            </button>
            <button 
              onClick={() => setInput('বাংলাদেশে এখন কোন পণ্য বেশি সেল হচ্ছে?')}
              className="whitespace-nowrap bg-gray-50 hover:bg-purple-50 hover:text-purple-700 px-4 py-2.5 rounded-xl text-[11px] font-bold text-gray-600 border border-gray-100 transition-all flex items-center gap-2 active:scale-95"
            >
              <Zap size={12} className="text-orange-500" /> সেরা সেল
            </button>
            <button 
              onClick={() => setInput('iPhone 15 এর অনলাইন র‍্যাঙ্কিং কত?')}
              className="whitespace-nowrap bg-gray-50 hover:bg-purple-50 hover:text-purple-700 px-4 py-2.5 rounded-xl text-[11px] font-bold text-gray-600 border border-gray-100 transition-all flex items-center gap-2 active:scale-95"
            >
              <ShoppingBag size={12} className="text-blue-500" /> র‍্যাঙ্কিং চেক
            </button>
          </div>
        </div>

        <div className="flex gap-2">
          <input 
            type="text" 
            placeholder="প্রোডাক্টের নাম লিখে র‍্যাঙ্কিং জানুন..." 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            className="flex-1 bg-gray-100 border-2 border-transparent rounded-2xl px-5 py-4 text-sm font-bold text-gray-900 focus:bg-white focus:border-purple-600 focus:ring-4 focus:ring-purple-50 outline-none transition-all shadow-inner placeholder:text-gray-400"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className={`p-4 rounded-2xl shadow-lg active:scale-90 transition-all ${
              !input.trim() || isTyping ? 'bg-gray-300 text-gray-500' : 'bg-purple-600 text-white hover:bg-purple-700 shadow-purple-100'
            }`}
          >
            <Send size={24} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChatView;

import React, { useState, useEffect } from 'react';
import { 
  ArrowLeft, 
  CloudUpload, 
  CheckCircle2, 
  RefreshCw, 
  Database, 
  ShieldCheck, 
  LogOut,
  Mail,
  Lock,
  User,
  UserPlus,
  LogIn,
  Eye,
  EyeOff
} from 'lucide-react';

interface CloudBackupProps {
  onBack: () => void;
  data: any;
}

interface UserProfile {
  name: string;
  email: string;
  photo: string;
  provider: 'google' | 'manual';
}

const CloudBackup: React.FC<CloudBackupProps> = ({ onBack, data }) => {
  const [authMode, setAuthMode] = useState<'LOGIN_CHOICE' | 'SIGN_UP' | 'LOGIN_MANUAL'>('LOGIN_CHOICE');
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(() => {
    return localStorage.getItem('dokan_user_logged_in') === 'true';
  });
  const [user, setUser] = useState<UserProfile | null>(() => {
    const savedUser = localStorage.getItem('dokan_user_profile');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [lastSynced, setLastSynced] = useState<string | null>(() => localStorage.getItem('dokan_last_sync'));
  const [syncSuccess, setSyncSuccess] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  // Form states
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });

  const handleGoogleLogin = () => {
    setIsLoading(true);
    // Simulate Google OAuth logic
    setTimeout(() => {
      const mockUser: UserProfile = {
        name: 'Saiful Islam',
        email: 'saiful.telecom@gmail.com',
        photo: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Saiful',
        provider: 'google'
      };
      saveLogin(mockUser);
    }, 1500);
  };

  const handleManualAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.email || !formData.password) return;

    setIsLoading(true);
    setTimeout(() => {
      const mockUser: UserProfile = {
        name: formData.name || 'User',
        email: formData.email,
        photo: `https://api.dicebear.com/7.x/initials/svg?seed=${formData.name || 'U'}`,
        provider: 'manual'
      };
      saveLogin(mockUser);
    }, 1500);
  };

  const saveLogin = (profile: UserProfile) => {
    setUser(profile);
    setIsLoggedIn(true);
    setIsLoading(false);
    localStorage.setItem('dokan_user_logged_in', 'true');
    localStorage.setItem('dokan_user_profile', JSON.stringify(profile));
  };

  const handleLogout = () => {
    if (confirm('আপনি কি নিশ্চিত যে লগআউট করতে চান?')) {
      setIsLoggedIn(false);
      setUser(null);
      setAuthMode('LOGIN_CHOICE');
      localStorage.removeItem('dokan_user_logged_in');
      localStorage.removeItem('dokan_user_profile');
    }
  };

  const handleSync = () => {
    setIsSyncing(true);
    setSyncSuccess(false);

    setTimeout(() => {
      const now = new Date().toLocaleString('bn-BD', {
        hour: '2-digit',
        minute: '2-digit',
        day: '2-digit',
        month: 'long',
        year: 'numeric'
      });

      localStorage.setItem('dokan_last_sync', now);
      setLastSynced(now);
      setIsSyncing(false);
      setSyncSuccess(true);
      setTimeout(() => setSyncSuccess(false), 5000);
    }, 2500);
  };

  // 1. Choice Screen
  const renderChoiceScreen = () => (
    <div className="flex-1 p-8 flex flex-col items-center justify-center text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="w-20 h-20 bg-red-50 rounded-3xl flex items-center justify-center mb-6 shadow-sm border border-red-100">
        <CloudUpload size={40} className="text-red-600" />
      </div>
      <h3 className="text-2xl font-black text-gray-800 mb-2">ডাটা থাকবে সুরক্ষিত</h3>
      <p className="text-sm text-gray-500 mb-10 px-4 leading-relaxed">
        আপনার দোকানের হিসাব গুগল ড্রাইভে অটো-ব্যাকআপ নিতে এখনই একটি অ্যাকাউন্ট তৈরি করুন বা লগইন করুন।
      </p>

      <div className="w-full space-y-4">
        {/* Google Button */}
        <button 
          onClick={handleGoogleLogin}
          disabled={isLoading}
          className="w-full py-4 px-6 bg-white border-2 border-gray-100 rounded-2xl flex items-center justify-center gap-4 shadow-sm active:scale-95 transition-all hover:bg-gray-50 hover:border-red-100"
        >
          {isLoading ? (
            <RefreshCw className="animate-spin text-red-600" size={24} />
          ) : (
            <img src="https://www.google.com/favicon.ico" alt="Google" className="w-6 h-6" />
          )}
          <span className="font-bold text-gray-700">
            {isLoading ? 'অপেক্ষা করুন...' : 'Sign in with Google'}
          </span>
        </button>

        <div className="flex items-center gap-3 my-6">
          <div className="flex-1 h-px bg-gray-100"></div>
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">অথবা</span>
          <div className="flex-1 h-px bg-gray-100"></div>
        </div>

        <button 
          onClick={() => setAuthMode('SIGN_UP')}
          className="w-full py-4 px-6 bg-[#D32F2F] text-white rounded-2xl flex items-center justify-center gap-3 shadow-lg shadow-red-100 active:scale-95 transition-all hover:bg-red-700"
        >
          <UserPlus size={20} />
          <span className="font-bold">নতুন অ্যাকাউন্ট খুলুন</span>
        </button>

        <button 
          onClick={() => setAuthMode('LOGIN_MANUAL')}
          className="w-full py-4 px-6 bg-white border-2 border-gray-100 text-gray-600 rounded-2xl flex items-center justify-center gap-3 active:scale-95 transition-all hover:bg-gray-50"
        >
          <LogIn size={20} />
          <span className="font-bold">ইমেইল দিয়ে লগইন</span>
        </button>
      </div>
    </div>
  );

  // 2. Auth Form Screen (Login / Sign-up)
  const renderAuthForm = () => (
    <div className="flex-1 p-8 animate-in slide-in-from-right duration-300">
      <div className="mb-8">
        <h3 className="text-2xl font-black text-gray-800">
          {authMode === 'SIGN_UP' ? 'অ্যাকাউন্ট তৈরি করুন' : 'লগইন করুন'}
        </h3>
        <p className="text-sm text-gray-500 mt-1">আপনার প্রয়োজনীয় তথ্যগুলো নিচে দিন</p>
      </div>

      <form onSubmit={handleManualAuth} className="space-y-4">
        {authMode === 'SIGN_UP' && (
          <div className="relative group">
            <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-red-600" size={20} />
            <input 
              type="text" 
              placeholder="পুরো নাম" 
              required
              value={formData.name}
              onChange={e => setFormData({...formData, name: e.target.value})}
              className="w-full p-4 pl-12 bg-gray-50 border-2 border-transparent rounded-2xl outline-none text-gray-900 font-bold focus:bg-white focus:border-red-600 focus:ring-4 focus:ring-red-50 transition-all shadow-inner"
            />
          </div>
        )}

        <div className="relative group">
          <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-red-600" size={20} />
          <input 
            type="email" 
            placeholder="ইমেইল অ্যাড্রেস" 
            required
            value={formData.email}
            onChange={e => setFormData({...formData, email: e.target.value})}
            className="w-full p-4 pl-12 bg-gray-50 border-2 border-transparent rounded-2xl outline-none text-gray-900 font-bold focus:bg-white focus:border-red-600 focus:ring-4 focus:ring-red-50 transition-all shadow-inner"
          />
        </div>

        <div className="relative group">
          <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-red-600" size={20} />
          <input 
            type={showPassword ? "text" : "password"} 
            placeholder="পাসওয়ার্ড" 
            required
            value={formData.password}
            onChange={e => setFormData({...formData, password: e.target.value})}
            className="w-full p-4 pl-12 pr-12 bg-gray-50 border-2 border-transparent rounded-2xl outline-none text-gray-900 font-bold focus:bg-white focus:border-red-600 focus:ring-4 focus:ring-red-50 transition-all shadow-inner"
          />
          <button 
            type="button"
            onClick={() => setShowPassword(!showPassword)}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
          >
            {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
          </button>
        </div>

        <button 
          type="submit"
          disabled={isLoading}
          className="w-full py-5 bg-[#D32F2F] text-white rounded-full font-black text-lg shadow-xl shadow-red-100 active:scale-95 transition-all hover:bg-red-700 flex items-center justify-center gap-3"
        >
          {isLoading ? <RefreshCw className="animate-spin" size={24} /> : (authMode === 'SIGN_UP' ? 'রেজিস্ট্রেশন করুন' : 'লগইন করুন')}
        </button>

        <p className="text-center text-sm text-gray-500 mt-6">
