              alt="Profile" 
              className="w-14 h-14 rounded-full border-2 border-red-50 shadow-sm"
            />
            <div className={`absolute -bottom-1 -right-1 p-1 rounded-full border-2 border-white ${user?.provider === 'google' ? 'bg-blue-500' : 'bg-green-500'}`}>
              {user?.provider === 'google' ? <img src="https://www.google.com/favicon.ico" className="w-2.5 h-2.5" /> : <ShieldCheck size={10} className="text-white" />}
            </div>
         </div>
         <div className="text-left flex-1">
            <div className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">বর্তমান প্রোফাইল</div>
            <div className="text-base font-bold text-gray-900 leading-tight">{user?.name}</div>
            <div className="text-xs text-gray-500">{user?.email}</div>
         </div>
         <button onClick={handleLogout} className="p-2 text-gray-300 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all" title="লগআউট">
            <LogOut size={20} />
         </button>
      </div>

      {/* Backup Status List */}
      <div className="w-full space-y-3 mb-8">
         <div className="flex justify-between items-center p-4 bg-gray-50 border border-gray-100 rounded-2xl">
            <div className="flex items-center gap-3">
               <Database size={20} className="text-gray-400" />
               <span className="text-sm font-bold text-gray-700">ডাটা সাইজ</span>
            </div>
            <span className="text-sm font-black text-gray-900">৪২০ কেবি</span>
         </div>

         <div className="flex justify-between items-center p-4 bg-gray-50 border border-gray-100 rounded-2xl">
            <div className="flex items-center gap-3">
               <RefreshCw size={20} className="text-gray-400" />
               <span className="text-sm font-bold text-gray-700">শেষ ব্যাকআপ</span>
            </div>
            <span className="text-xs font-black text-[#D32F2F]">{lastSynced || 'কখনো করা হয়নি'}</span>
         </div>
      </div>

      {/* Success Alert */}
      {syncSuccess && (
        <div className="w-full bg-green-50 text-green-700 p-4 rounded-2xl flex items-center gap-3 mb-6 animate-in zoom-in-95 duration-300">
           <div className="bg-green-100 p-1.5 rounded-full"><CheckCircle2 size={20} /></div>
           <span className="text-sm font-bold">সফলভাবে গুগল ড্রাইভে সেভ হয়েছে!</span>
        </div>
      )}

      {/* Action Button */}
      <button 
        onClick={handleSync}
        disabled={isSyncing}
        className={`w-full py-5 rounded-full font-black text-lg text-white shadow-xl flex items-center justify-center gap-3 transition-all transform active:scale-[0.98] ${
          isSyncing ? 'bg-gray-400 cursor-not-allowed' : 'bg-[#D32F2F] hover:bg-red-700 shadow-red-100'
        }`}
      >
        {isSyncing ? <RefreshCw className="animate-spin" size={24} /> : <CloudUpload size={24} />}
        {isSyncing ? 'সিংকিং হচ্ছে...' : 'এখনই ব্যাকআপ নিন'}
      </button>

      <div className="mt-8 flex items-center gap-2 text-gray-200">
         <ShieldCheck size={16} />
         <span className="text-[10px] font-black uppercase tracking-widest">End-to-End Encrypted Storage</span>
      </div>
    </div>
  );

  return (
    <div className="bg-white min-h-full flex flex-col">
      <header className="flex items-center justify-between p-4 border-b border-gray-100 sticky top-0 bg-white z-20">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => {
              if (authMode !== 'LOGIN_CHOICE' && !isLoggedIn) setAuthMode('LOGIN_CHOICE');
              else onBack();
            }} 
            className="text-gray-600 active:scale-90 transition-transform"
          >
            <ArrowLeft size={24} />
          </button>
          <h2 className="text-lg font-bold">
            {isLoggedIn ? 'ক্লাউড প্রোফাইল' : (authMode === 'LOGIN_CHOICE' ? 'লগইন / রেজিস্ট্রেশন' : 'অ্যাকাউন্ট')}
          </h2>
        </div>
        {!isLoggedIn && authMode !== 'LOGIN_CHOICE' && (
          <button onClick={() => setAuthMode('LOGIN_CHOICE')} className="text-xs font-black text-gray-400">পিছনে</button>
        )}
      </header>

      {isLoggedIn ? renderLoggedInView() : (authMode === 'LOGIN_CHOICE' ? renderChoiceScreen() : renderAuthForm())}

      {/* Privacy Note Footer */}
      {!isLoggedIn && (
        <div className="p-6 bg-gray-50 border-t border-gray-100 flex items-center gap-3">
          <Lock size={18} className="text-gray-300" />
          <p className="text-[10px] text-gray-400 font-medium leading-relaxed">
            আপনার ডাটা শতভাগ গোপন রাখা হয়। আমরা আপনার জিমেইল অ্যাকাউন্টের শুধুমাত্র ড্রাইভ পারমিশন ব্যবহার করি আপনার নিজের ডাটা স্টোর করার জন্য।
