import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, 
  Wallet, 
  Menu, 
  BookOpen, 
  Search, 
  UserPlus, 
  Plus, 
  Minus, 
  ArrowLeft, 
  MoreVertical, 
  Calendar, 
  Camera, 
  ChevronRight,
  Filter,
  Download,
  Package,
  FileText,
  Bell,
  HelpCircle,
  QrCode,
  CloudUpload,
  MessageSquare,
  ChevronDown,
  Sparkles
} from 'lucide-react';
import { Contact, ContactType, ViewState, Transaction, SalePurchaseRecord, StockItem } from './types';
import TallyView from './components/TallyView';
import CashboxView from './components/CashboxView';
import AddContactForm from './components/AddContactForm';
import ContactDetails from './components/ContactDetails';
import Navigation from './components/Navigation';
import Sidebar from './components/Sidebar';
import BechaKenaView from './components/BechaKenaView';
import CloudBackup, { UserProfile } from './components/CloudBackup';
import AIChatView, { Message } from './components/AIChatView';
import SmartRecommendationsView from './components/SmartRecommendationsView';
import StockView from './components/StockView';

// এখা‌নে নিচের লিংকটি ইডিট ক‌রে আপনার Whatsapp নম্বর বা লিংক বসা‌তে পার‌বেন
const HELP_WHATSAPP_URL = 'https://wa.me/8801797464478';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('TALLY');

  // User Authentication State
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(() => {
    return localStorage.getItem('dokan_user_logged_in') === 'true';
  });
  const [user, setUser] = useState<UserProfile | null>(() => {
    const savedUser = localStorage.getItem('dokan_user_profile');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  const [contacts, setContacts] = useState<Contact[]>(() => {
    const saved = localStorage.getItem('dokan_contacts');
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        name: 'Subongkar Vai Galachipa',
        phone: '01700000001',
        type: ContactType.CUSTOMER,
        balance: 4000,
        lastActivity: '২ দিন আগে',
        transactions: []
      },
      {
        id: '2',
        name: 'Saiful Telecom caca',
        phone: '01700000002',
        type: ContactType.SUPPLIER,
        balance: -1230,
        lastActivity: '২ মাস আগে',
        transactions: []
      }
    ];
  });

  const [salePurchaseRecords, setSalePurchaseRecords] = useState<SalePurchaseRecord[]>(() => {
    const saved = localStorage.getItem('dokan_becha_kena');
    return saved ? JSON.parse(saved) : [];
  });

  const [stockItems, setStockItems] = useState<StockItem[]>(() => {
    const saved = localStorage.getItem('dokan_stock');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'চিনি', quantity: 50, unit: 'কেজি', buyingPrice: 120, sellingPrice: 140, lastUpdated: '১৭ জানুয়ারি ২০২৫' },
      { id: '2', name: 'সয়াবিন তেল', quantity: 20, unit: 'লিটার', buyingPrice: 160, sellingPrice: 180, lastUpdated: '১৬ জানুয়ারি ২০২৫' }
    ];
  });

  // AI Chat Messages state persisted for the session
  const [aiMessages, setAiMessages] = useState<Message[]>([
    { 
      role: 'ai', 
      text: 'আসসালামু আলাইকুম! আমি আপনার দোকানের এআই অ্যাসিস্ট্যান্ট।\n\nআমি এখন সরাসরি **গুগল সার্চ** এবং **সোশ্যাল মিডিয়া** থেকে রিয়েল-টাইম তথ্য দিতে পারি। কোনো পণ্যের **দাম**, **র‍্যাঙ্কিং** বা **মার্কেট ট্রেন্ড** সম্পর্কে জানতে চান?' 
    }
  ]);

  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingContact, setEditingContact] = useState<Contact | undefined>(undefined);

  useEffect(() => {
    localStorage.setItem('dokan_contacts', JSON.stringify(contacts));
  }, [contacts]);

  useEffect(() => {
    localStorage.setItem('dokan_becha_kena', JSON.stringify(salePurchaseRecords));
  }, [salePurchaseRecords]);

  useEffect(() => {
    localStorage.setItem('dokan_stock', JSON.stringify(stockItems));
  }, [stockItems]);

  const addContact = (updatedContact: Contact) => {
    const exists = contacts.find(c => c.id === updatedContact.id);
    if (exists) {
      setContacts(prev => prev.map(c => c.id === updatedContact.id ? updatedContact : c));
    } else {
      setContacts(prev => [...prev, updatedContact]);
    }
    setEditingContact(undefined);
    setCurrentView('TALLY');
  };

  const deleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
    setCurrentView('TALLY');
  };

  const addSalePurchaseRecord = (record: SalePurchaseRecord) => {
    setSalePurchaseRecords(prev => [...prev, record]);
  };

  const updateContactTransactions = (contactId: string, transaction: Transaction) => {
    setContacts(prev => prev.map(c => {
      if (c.id === contactId) {
        const newBalance = transaction.type === 'DUE_GIVEN' 
          ? c.balance + transaction.amount 
          : c.balance - transaction.amount;
        return {
          ...c,
          balance: newBalance,
          lastActivity: 'এখনই',
          transactions: [transaction, ...c.transactions]
        };
      }
      return c;
    }));
  };

  const handleUpdateStock = (updatedItems: StockItem[]) => {
    setStockItems(updatedItems);
  };

  const selectedContact = useMemo(() => 
    contacts.find(c => c.id === selectedContactId), 
    [contacts, selectedContactId]
  );

  const handleHelpClick = () => {
    window.open(HELP_WHATSAPP_URL, '_blank');
  };

  const clearAiMessages = () => {
    setAiMessages([{ 
      role: 'ai', 
      text: 'চ্যাট হিস্ট্রি মুছে ফেলা হয়েছে। আমি পুনরায় আপনাকে সাহায্য করার জন্য প্রস্তুত।' 
    }]);
  };

  const handleLoginSuccess = (profile: UserProfile) => {
    setUser(profile);
    setIsLoggedIn(true);
    localStorage.setItem('dokan_user_logged_in', 'true');
    localStorage.setItem('dokan_user_profile', JSON.stringify(profile));
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUser(null);
    localStorage.removeItem('dokan_user_logged_in');
    localStorage.removeItem('dokan_user_profile');
  };

  const renderView = () => {
    switch (currentView) {
      case 'TALLY':
        return (
          <TallyView 
            contacts={contacts} 
            onSelectContact={(id) => {
              setSelectedContactId(id);
              setCurrentView('CONTACT_DETAILS');
            }}
            onAddContact={() => {
              setEditingContact(undefined);
              setCurrentView('ADD_CONTACT');
            }}
            onNavigate={setCurrentView}
          />
        );
      case 'CASHBOX':
        return <CashboxView />;
      case 'ADD_CONTACT':
        return (
          <AddContactForm 
            onBack={() => setCurrentView(editingContact ? 'CONTACT_DETAILS' : 'TALLY')} 
            onSave={addContact} 
            editContact={editingContact}
          />
        );
      case 'CONTACT_DETAILS':
        return selectedContact ? (
          <ContactDetails 
            contact={selectedContact} 
            onBack={() => setCurrentView('TALLY')}
            onAddTransaction={(t) => updateContactTransactions(selectedContact.id, t)}
            onShowRecommendations={() => setCurrentView('AI_RECOMMENDATIONS')}
            onDeleteContact={deleteContact}
            onEditContact={(c) => {
              setEditingContact(c);
              setCurrentView('ADD_CONTACT');
            }}
          />
        ) : null;
      case 'BECHA_KENA':
        return (
          <BechaKenaView 
            records={salePurchaseRecords}
            onBack={() => setCurrentView('TALLY')}
            onAddRecord={addSalePurchaseRecord}
          />
        );
      case 'CLOUD_BACKUP':
        return (
          <CloudBackup 
            data={{ contacts, salePurchaseRecords }}
            onBack={() => setCurrentView('TALLY')}
            onLoginSuccess={handleLoginSuccess}
            onLogout={handleLogout}
            currentLoggedInState={isLoggedIn}
            currentUserProfile={user}
          />
        );
      case 'AI_CHAT':
        return (
          <AIChatView 
            contacts={contacts}
            records={salePurchaseRecords}
            onBack={() => setCurrentView('TALLY')}
            persistedMessages={aiMessages}
            onMessagesUpdate={setAiMessages}
            onClearChat={clearAiMessages}
          />
        );
      case 'AI_RECOMMENDATIONS':
        return (
          <SmartRecommendationsView 
            contact={selectedContact || null}
            allRecords={salePurchaseRecords}
            onBack={() => setCurrentView(selectedContact ? 'CONTACT_DETAILS' : 'TALLY')}
          />
        );
      case 'STOCK':
        return (
          <StockView 
            items={stockItems}
            onBack={() => setCurrentView('TALLY')}
            onUpdateStock={handleUpdateStock}
          />
        );
      default:
        return <div className="p-10 text-center">Work in Progress</div>;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen flex flex-col relative shadow-xl">
      {/* Header */}
      <header className="bg-[#D32F2F] text-white px-4 py-3 sticky top-0 z-40 shadow-md">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer active:opacity-80 transition-opacity" onClick={() => setIsSidebarOpen(true)}>
            <div className="bg-white/20 p-1 rounded-md flex items-center gap-2">
              {isLoggedIn && user ? (
                <img src={user.photo} className="w-5 h-5 rounded-full border border-white/40" alt="p" />
              ) : null}
              <span className="text-sm font-bold truncate max-w-[100px]">
                {isLoggedIn && user ? user.name.split(' ')[0].toLowerCase() : 'saiful telec...'}
              </span>
            </div>
            <ChevronDown size={16} />
          </div>

          <div className="flex items-center gap-4">
            <div 
              onClick={() => setCurrentView('AI_CHAT')}
              className="flex flex-col items-center cursor-pointer group"
            >
              <div className="relative">
                <Sparkles size={24} className="text-yellow-300 group-hover:scale-110 transition-transform" />
                <div className="absolute inset-0 bg-yellow-300 blur-sm opacity-20 group-hover:opacity-40"></div>
              </div>
              <span className="text-[10px] mt-1 text-white font-bold">এআই</span>
            </div>
            <div className="relative flex flex-col items-center cursor-pointer">
              <Bell size={24} />
              <span className="absolute -top-1 right-0 bg-white text-[#D32F2F] text-[10px] font-black rounded-full w-4 h-4 flex items-center justify-center border border-[#D32F2F]">99+</span>
              <span className="text-[10px] mt-1 text-white font-bold">ইনবক্স</span>
            </div>
            <div 
              onClick={handleHelpClick}
              className="flex flex-col items-center cursor-pointer active:scale-95 transition-transform"
            >
              <HelpCircle size={24} />
              <span className="text-[10px] mt-1 text-white font-bold">হেল্প</span>
            </div>
          </div>
        </div>
        <div className="mt-1 text-xs font-semibold opacity-90 tracking-wide">স্ট্যান্ডার্ড এডিশন</div>
      </header>

      {/* Sidebar */}
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        isLoggedIn={isLoggedIn}
        user={user}
        onNavigate={(view) => {
          setCurrentView(view);
          setIsSidebarOpen(false);
        }}
      />

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto pb-20 bg-gray-50">
        {renderView()}
      </main>

      {/* Bottom Navigation */}
      {['TALLY', 'CASHBOX', 'WALLET', 'MENU'].includes(currentView) && (
        <Navigation currentView={currentView} onNavigate={setCurrentView} />
      )}
    </div>
  );
};

export default App;

