               <span className="text-sm font-bold text-gray-700">সর্বশেষ ব্যাকআপ</span>
            </div>
            <span className="text-[11px] font-black text-red-600 bg-red-50 px-2 py-1 rounded-md">{lastSynced || 'এখনো হয়নি'}</span>
         </div>
      </div>

      {/* Success Alert */}
      {syncSuccess && (
        <div className="w-full bg-green-50 text-green-700 p-4.5 rounded-2xl flex items-center gap-3 mb-6 animate-in zoom-in-95 duration-300 border border-green-100">
           <div className="bg-green-100 p-1.5 rounded-full text-green-600"><CheckCircle2 size={22} /></div>
           <span className="text-sm font-black">সবগুলো ডাটা ক্লাউডে সেভ করা হয়েছে!</span>
        </div>
      )}

      {/* Action Button */}
      <button 
        onClick={handleSync}
        disabled={isSyncing}
        className={`w-full py-5 rounded-[2rem] font-black text-xl text-white shadow-2xl flex items-center justify-center gap-4 transition-all transform active:scale-[0.98] ${
          isSyncing ? 'bg-gray-400 cursor-not-allowed' : 'bg-[#D32F2F] hover:bg-red-700 shadow-red-100'
