        </button>
      </div>

      <div className="mt-8 w-full">
         <div className="flex justify-between items-center p-4 bg-gray-50 border border-gray-100 rounded-2xl">
            <div className="flex items-center gap-2 text-xs font-bold text-gray-500 uppercase tracking-widest">
               <Clock size={14} /> শেষ আপডেট
            </div>
            <span className="text-xs font-black text-red-600">{lastSynced || 'কখনো হয়নি'}</span>
         </div>
      </div>

      {syncSuccess && (
        <div className="w-full bg-green-50 text-green-700 p-4.5 rounded-2xl flex items-center gap-3 mt-6 animate-in zoom-in-95 border border-green-100 shadow-sm">
