  );

  const renderPickerScreen = () => (
    <div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-6 backdrop-blur-sm">
      <div className="bg-white w-full max-w-sm rounded-[2.5rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <img src="https://www.google.com/favicon.ico" className="w-5 h-5" alt="g" />
            <span className="font-bold text-gray-800">অ্যাকাউন্ট বেছে নিন</span>
          </div>
          <button onClick={() => setStage('CHOICE')}><X size={20} className="text-gray-400" /></button>
        </div>
        <div className="p-3">
          {['saiful.islam@gmail.com', 'dokan.business@gmail.com'].map((email, i) => (
            <button 
              key={i}
              onClick={() => handleSelectAccount(email)}
              className="w-full flex items-center gap-4 p-4 hover:bg-gray-50 rounded-2xl text-left transition-colors"
            >
              <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center text-red-600 font-bold uppercase">{email[0]}</div>
              <div className="text-sm font-bold text-gray-900">{email}</div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  const renderVerifyScreen = () => (
    <div className="flex-1 p-8 animate-in slide-in-from-right duration-300">
      <div className="mb-8">
        <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 mb-6">
          <Mail size={32} />
        </div>
        <h3 className="text-2xl font-black text-gray-900 leading-tight">ভেরিফিকেশন কোড</h3>
        <p className="text-sm text-gray-500 mt-2">
          আমরা <span className="font-bold text-gray-900">{selectedEmail}</span> ঠিকানায় একটি ৬ ডিজিটের কোড পাঠিয়েছি।
        </p>
      </div>
      <form onSubmit={handleVerifyCode} className="space-y-6">
        <div className="relative">
          <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input 
            type="text" 
            maxLength={6}
            placeholder="ভেরিফিকেশন কোড"
            value={verificationCode}
            onChange={(e) => setVerificationCode(e.target.value)}
            className="w-full p-5 pl-12 bg-gray-50 border-2 border-transparent rounded-2xl outline-none font-black text-2xl tracking-[0.5em] focus:border-blue-500 focus:bg-white transition-all text-center"
          />
        </div>
        <button 
          type="submit"
          disabled={verificationCode.length !== 6 || isLoading}
          className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-lg flex items-center justify-center gap-3 shadow-xl shadow-blue-100 disabled:bg-gray-200"
        >
          {isLoading ? <RefreshCw className="animate-spin" /> : 'ভেরিফাই ও লগইন'}
          {!isLoading && <ArrowRight size={20} />}
        </button>
        <div className="text-center">
          <button type="button" className="text-sm font-bold text-blue-600 hover:underline">কোড পাননি? আবার পাঠান</button>
        </div>
      </form>
    </div>
  );

  const renderLoggedInView = () => (
    <div className="flex-1 p-6 flex flex-col items-center animate-in fade-in duration-500">
      <div className={`w-32 h-32 rounded-[2.8rem] bg-red-50 flex items-center justify-center mb-6 relative border-4 border-white shadow-2xl ${isSyncing || isRestoring ? 'animate-pulse' : ''}`}>
