        </button>
      </div>

      <div className="mt-auto w-full pt-10">
        <button 
          onClick={() => { if(confirm('আপনি কি নিশ্চিত যে লগ আউট করতে চান?')) onLogout(); }} 
          className="w-full py-4 rounded-2xl border-2 border-red-50 text-red-600 font-black flex items-center justify-center gap-3 hover:bg-red-50 transition-all active:scale-95"
        >
          <LogOut size={20} /> লগ আউট করুন
        </button>
        <p className="text-[10px] text-gray-400 text-center font-bold uppercase mt-4 tracking-widest">Version 7.10.0 Secure</p>
      </div>
