          <input 
            type="text" 
            maxLength={6}
            placeholder="Code: 000000"
            value={verificationCode}
            onChange={(e) => setVerificationCode(e.target.value)}
            className="w-full p-5 pl-12 bg-gray-50 border-2 border-transparent rounded-2xl outline-none font-black text-2xl tracking-[0.5em] focus:border-blue-500 focus:bg-white transition-all text-center"
          />
        </div>
        <button 
          type="submit"
