      <h3 className="text-2xl font-black text-gray-900">গুগল ড্রাইভ সিঙ্কড</h3>
      <p className="text-xs text-green-600 font-bold mt-1 uppercase tracking-widest flex items-center gap-2 mb-8">
        <Clock size={12} /> অটো-ব্যাকআপ সচল
