            <div className="text-lg font-black text-gray-900 leading-tight truncate">{currentUserProfile?.name}</div>
            <div className="text-xs text-gray-500 truncate font-medium">{currentUserProfile?.email}</div>
         </div>
      </div>

      <div className="w-full space-y-4">
        {hasCloudBackup && (
          <button 
            onClick={handleLoadFromDrive}
            disabled={isRestoring || isSyncing}
            className="w-full bg-blue-600 text-white p-5 rounded-[1.8rem] flex items-center justify-center gap-4 shadow-xl shadow-blue-100 active:scale-95 transition-all"
          >
