  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 flex justify-around py-2 z-50">
      {tabs.map((tab) => (
        <button
          key={tab.id}
          onClick={() => onNavigate(tab.id as ViewState)}
          className={`flex flex-col items-center flex-1 transition-colors ${
            currentView === tab.id ? 'text-[#D32F2F]' : 'text-gray-500'
          }`}
        >
          <div className={`p-1 rounded-full ${currentView === tab.id ? 'bg-[#FFE9E9]' : ''}`}>
             <tab.icon size={22} fill={currentView === tab.id ? 'currentColor' : 'none'} />
          </div>
          <span className="text-xs mt-1 font-medium">{tab.label}</span>
        </button>
      ))}
    </nav>
  );
};

