import React, { useState, useMemo } from 'react';
import { 
  ArrowLeft, 
  Search, 
  Plus, 
  Edit2, 
  Save, 
  Trash2, 
  Calendar, 
  Package, 
  TrendingUp, 
  Info, 
  X, 
  History, 
  ArrowUpRight, 
  ArrowDownRight,
  ShoppingCart,
  PlusCircle,
  MinusCircle,
  AlertCircle
} from 'lucide-react';
import { StockItem } from '../types';

interface StockViewProps {
  items: StockItem[];
  onBack: () => void;
  onUpdateStock: (items: StockItem[]) => void;
}

const StockView: React.FC<StockViewProps> = ({ items, onBack, onUpdateStock }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<StockItem>>({});
  const [isAdding, setIsAdding] = useState(false);
  const [activeAction, setActiveAction] = useState<'NONE' | 'IMPORT' | 'SALE'>('NONE');
  const [selectedProductForAction, setSelectedProductForAction] = useState<StockItem | null>(null);
  const [actionQuantity, setActionQuantity] = useState('');

  const filteredItems = useMemo(() => {
    return items.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [items, searchTerm]);

  const totalBuyingValuation = useMemo(() => 
    items.reduce((acc, curr) => acc + (curr.quantity * curr.buyingPrice), 0),
    [items]
  );

  const totalSellingValuation = useMemo(() => 
    items.reduce((acc, curr) => acc + (curr.quantity * curr.sellingPrice), 0),
    [items]
  );

  const handleEditClick = (item: StockItem) => {
    setEditingId(item.id);
    setEditForm(item);
  };

  const handleSave = () => {
    if (editingId && editForm.name) {
      const updated = items.map(item => 
        item.id === editingId 
          ? { 
              ...item, 
              ...editForm, 
              lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' }) 
            } 
          : item
      );
      onUpdateStock(updated as StockItem[]);
      setEditingId(null);
      setEditForm({});
    } else if (isAdding && editForm.name) {
      const newItem: StockItem = {
        id: Date.now().toString(),
        name: editForm.name || '',
        quantity: editForm.quantity || 0,
        unit: editForm.unit || 'পিস',
        buyingPrice: editForm.buyingPrice || 0,
        sellingPrice: editForm.sellingPrice || 0,
        lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' })
      };
      onUpdateStock([...items, newItem]);
      setIsAdding(false);
      setEditForm({});
    }
  };

  const handleStockAction = () => {
    if (!selectedProductForAction || !actionQuantity) return;
    const qty = parseFloat(actionQuantity);

    const updated = items.map(item => {
      if (item.id === selectedProductForAction.id) {
        const newQty = activeAction === 'IMPORT' ? item.quantity + qty : item.quantity - qty;
        if (newQty < 0 && activeAction === 'SALE') {
          alert('দুঃখিত, স্টকে পর্যাপ্ত পণ্য নেই!');
          return item;
        }
        return {
          ...item,
          quantity: newQty,
          lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' })
        };
      }
      return item;
    });

    onUpdateStock(updated);
    setActiveAction('NONE');
    setSelectedProductForAction(null);
    setActionQuantity('');
  };

  const handleDelete = (id: string) => {
    if (confirm('আপনি কি এই পণ্যটি ডিলিট করতে চান?')) {
      onUpdateStock(items.filter(item => item.id !== id));
    }
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col pb-24">
      {/* Inventory Header */}
      <header className="p-4 bg-[#D32F2F] text-white">
        <div className="flex items-center gap-4 mb-6">
          <button onClick={onBack} className="p-1 active:scale-90 transition-transform"><ArrowLeft size={24} /></button>
          <h2 className="text-xl font-black">ইনভেন্টরি / পণ্য স্টক</h2>
        </div>

        <div className="grid grid-cols-2 gap-3 mb-2">
          <div className="bg-white/10 backdrop-blur-md p-4 rounded-2xl border border-white/20">
            <div className="text-[10px] font-bold opacity-70 uppercase tracking-widest mb-1">স্টক ভ্যালু (কেনা)</div>
            <div className="text-2xl font-black">৳{totalBuyingValuation.toLocaleString('bn-BD')}</div>
          </div>
          <div className="bg-white/10 backdrop-blur-md p-4 rounded-2xl border border-white/20">
            <div className="text-[10px] font-bold opacity-70 uppercase tracking-widest mb-1">ভবিষ্যৎ লাভ</div>
            <div className="text-2xl font-black text-yellow-300">৳{(totalSellingValuation - totalBuyingValuation).toLocaleString('bn-BD')}</div>
          </div>
        </div>
      </header>

      {/* Quick Actions Bar */}
      <div className="px-4 py-4 flex gap-3 -mt-6 z-10">
        <button 
          onClick={() => setActiveAction('IMPORT')}
          className="flex-1 bg-white shadow-lg p-4 rounded-2xl flex flex-col items-center gap-2 border border-gray-50 active:scale-95 transition-all group"
        >
          <div className="bg-green-100 p-2 rounded-xl text-green-600 group-hover:bg-green-600 group-hover:text-white transition-colors">
            <PlusCircle size={24} />
          </div>
          <span className="text-xs font-black text-gray-700">পণ্য ইমপোর্ট</span>
        </button>
        <button 
          onClick={() => setActiveAction('SALE')}
          className="flex-1 bg-white shadow-lg p-4 rounded-2xl flex flex-col items-center gap-2 border border-gray-50 active:scale-95 transition-all group"
        >
          <div className="bg-blue-100 p-2 rounded-xl text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-colors">
            <ShoppingCart size={24} />
          </div>
          <span className="text-xs font-black text-gray-700">পণ্য সেল</span>
        </button>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex-1 bg-white shadow-lg p-4 rounded-2xl flex flex-col items-center gap-2 border border-gray-50 active:scale-95 transition-all group"
        >
          <div className="bg-red-100 p-2 rounded-xl text-red-600 group-hover:bg-red-600 group-hover:text-white transition-colors">
            <Plus size={24} />
          </div>
          <span className="text-xs font-black text-gray-700">নতুন পণ্য</span>
        </button>
      </div>

      {/* Stock Action Modals (Simplified) */}
      {(activeAction !== 'NONE') && (
        <div className="fixed inset-0 bg-black/60 z-[100] flex items-end justify-center">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] p-6 animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black text-gray-900">
                {activeAction === 'IMPORT' ? 'পণ্য স্টকে যোগ করুন' : 'পণ্য স্টক থেকে কমান'}
              </h3>
              <button onClick={() => { setActiveAction('NONE'); setSelectedProductForAction(null); }} className="p-2 bg-gray-100 rounded-full"><X size={20} /></button>
            </div>

            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 block">পণ্য সিলেক্ট করুন</label>
                <div className="grid grid-cols-2 gap-2 max-h-40 overflow-y-auto p-1">
                  {items.map(item => (
                    <button 
                      key={item.id}
                      onClick={() => setSelectedProductForAction(item)}
                      className={`p-3 rounded-xl border-2 text-left transition-all ${selectedProductForAction?.id === item.id ? 'border-[#D32F2F] bg-red-50' : 'border-gray-100 hover:border-gray-200'}`}
                    >
                      <div className="text-xs font-bold truncate">{item.name}</div>
                      <div className="text-[10px] text-gray-400">স্টক: {item.quantity} {item.unit}</div>
                    </button>
                  ))}
                </div>
              </div>

              {selectedProductForAction && (
                <div className="animate-in fade-in zoom-in-95 duration-200">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 block">পরিমাণ লিখুন ({selectedProductForAction.unit})</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={actionQuantity}
                      onChange={(e) => setActionQuantity(e.target.value)}
                      placeholder="0.00"
                      className="w-full p-5 bg-gray-50 border-2 border-transparent rounded-2xl outline-none font-black text-2xl focus:border-[#D32F2F] focus:bg-white transition-all shadow-inner"
                      autoFocus
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 font-bold text-gray-400">{selectedProductForAction.unit}</div>
                  </div>
                  <button 
                    onClick={handleStockAction}
                    className={`w-full mt-6 py-5 rounded-2xl font-black text-lg text-white shadow-xl transition-all ${activeAction === 'IMPORT' ? 'bg-green-600 shadow-green-100' : 'bg-blue-600 shadow-blue-100'}`}
                  >
                    হিসাব আপডেট করুন
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Search List */}
      <div className="px-4 mb-4">
        <div className="relative group">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#D32F2F]" size={20} />
          <input 
            type="text" 
            placeholder="পণ্য খুঁজুন..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-white border-2 border-transparent rounded-2xl pl-12 pr-4 py-4 text-sm font-bold shadow-sm focus:border-[#D32F2F] outline-none transition-all"
          />
        </div>
      </div>

      {/* Stock Items List */}
      <div className="flex-1 px-4 space-y-3">
        {isAdding && (
          <div className="bg-white p-5 rounded-2xl border-2 border-red-100 space-y-4 shadow-xl">
             <input className="w-full p-4 bg-gray-50 rounded-xl font-bold outline-none border-2 border-transparent focus:border-red-400" placeholder="পণ্যের নাম" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} />
             <div className="flex gap-2">
                <input type="number" className="flex-1 p-4 bg-gray-50 rounded-xl font-bold outline-none border-2 border-transparent focus:border-red-400" placeholder="পরিমাণ" value={editForm.quantity || ''} onChange={e => setEditForm({...editForm, quantity: parseFloat(e.target.value)})} />
                <input className="w-24 p-4 bg-gray-50 rounded-xl font-bold outline-none border-2 border-transparent focus:border-red-400" placeholder="একক" value={editForm.unit || ''} onChange={e => setEditForm({...editForm, unit: e.target.value})} />
             </div>
             <div className="flex gap-2">
                <input type="number" className="flex-1 p-4 bg-gray-50 rounded-xl font-bold outline-none border-2 border-transparent focus:border-red-400" placeholder="কেনা দাম" value={editForm.buyingPrice || ''} onChange={e => setEditForm({...editForm, buyingPrice: parseFloat(e.target.value)})} />
                <input type="number" className="flex-1 p-4 bg-gray-50 rounded-xl font-bold outline-none border-2 border-transparent focus:border-red-400" placeholder="বিক্রি দাম" value={editForm.sellingPrice || ''} onChange={e => setEditForm({...editForm, sellingPrice: parseFloat(e.target.value)})} />
             </div>
             <button onClick={handleSave} className="w-full bg-red-600 text-white p-4 rounded-xl font-black">সেভ করুন</button>
             <button onClick={() => setIsAdding(false)} className="w-full text-gray-400 font-bold py-2">বাতিল</button>
          </div>
        )}

        {filteredItems.map(item => (
          <div key={item.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center justify-between group hover:border-[#D32F2F] transition-all">
            <div className="flex items-center gap-4">
               <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-black ${item.quantity < 5 ? 'bg-red-50 text-red-600' : 'bg-gray-50 text-gray-400'}`}>
                  {item.quantity < 5 ? <AlertCircle size={24} /> : item.name[0]}
               </div>
               <div>
                  <h4 className="font-bold text-gray-900">{item.name}</h4>
                  <div className="flex items-center gap-2 mt-0.5">
                     <span className={`text-[10px] font-black px-1.5 py-0.5 rounded ${item.quantity < 5 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                        স্টক: {item.quantity} {item.unit}
                     </span>
                     <span className="text-[10px] text-gray-400 font-bold italic">কেনা: ৳{item.buyingPrice}</span>
                  </div>
               </div>
            </div>
            <div className="text-right">
               <div className="text-sm font-black text-gray-900">৳{item.sellingPrice}</div>
               <div className="text-[9px] text-gray-400 font-bold uppercase tracking-tighter mt-0.5">প্রতি {item.unit}</div>

               <div className="flex gap-2 mt-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => handleEditClick(item)} className="p-1.5 bg-gray-100 rounded-lg text-blue-600"><Edit2 size={14} /></button>
                  <button onClick={() => handleDelete(item.id)} className="p-1.5 bg-gray-100 rounded-lg text-red-600"><Trash2 size={14} /></button>
               </div>
            </div>
          </div>
        ))}

        {filteredItems.length === 0 && !isAdding && (
          <div className="py-20 text-center">
             <div className="bg-gray-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-300">
                <Package size={40} />
             </div>
             <p className="text-gray-400 font-bold">কোনো পণ্য পাওয়া যায়নি!</p>
          </div>
        )}
      </div>

      <div className="p-6 bg-white border-t border-gray-100 flex gap-3 shadow-lg mt-8">
        <div className="bg-blue-50 p-2 rounded-lg h-fit text-blue-500">
          <Info size={18} />
        </div>
        <p className="text-[11px] text-gray-500 font-medium leading-relaxed">
          আপনার ইনভেন্টরি ম্যানেজ করতে পণ্য ইমপোর্ট বা সেল বাটন ব্যবহার করুন। স্টকে ৫টির কম পণ্য থাকলে অটোমেটিক **লাল সিগন্যাল** দেখা যাবে।
        </p>
      </div>
    </div>
  );
};

