            <button 
              onClick={() => setSelectedContactId('CASH_CUSTOMER')}
              className={`flex-1 py-3 rounded-xl font-bold text-xs border-2 transition-all ${selectedContactId === 'CASH_CUSTOMER' ? 'border-[#D32F2F] bg-red-50 text-[#D32F2F]' : 'border-gray-100 text-gray-500'}`}
            >
              নগদ কাস্টমার
            </button>
            <button 
              onClick={() => setSelectedContactId('')} // Prompt to choose
              className={`flex-1 py-3 rounded-xl font-bold text-xs border-2 transition-all ${selectedContactId !== 'CASH_CUSTOMER' && selectedContactId !== '' ? 'border-[#D32F2F] bg-red-50 text-[#D32F2F]' : 'border-gray-100 text-gray-500'}`}
            >
