                  <input 
                    type="text" 
                    placeholder="কাস্টমারের নাম খুঁজুন..." 
                    value={searchTermContact}
                    onChange={(e) => setSearchTermContact(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-gray-50 rounded-lg text-sm outline-none border border-transparent focus:border-red-400"
                  />
