        </button>
      </div>

      {/* Product Selector Modal */}
      {showProductSelector && (
        <div className="fixed inset-0 bg-black/60 z-[100] flex items-end justify-center">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] p-6 animate-in slide-in-from-bottom duration-300 h-[80vh] flex flex-col">
             <div className="flex justify-between items-center mb-6">
