                  <div className="flex-1">
                    <h4 className="font-bold text-gray-900 text-sm">{product?.name}</h4>
                    <p className="text-[10px] text-gray-400 font-bold">দর: ৳{item.price} | স্টক: {product?.quantity}</p>
                  </div>
                  <div className="flex items-center gap-4">
                    <div className="flex items-center bg-gray-100 rounded-full px-2 py-0.5">
                       <button onClick={() => updateQuantity(item.productId, -1)} className="p-1 text-red-600"><Minus size={16} /></button>
                       <span className="w-8 text-center font-black text-sm">{item.quantity}</span>
                       <button onClick={() => updateQuantity(item.productId, 1)} className="p-1 text-green-600"><Plus size={16} /></button>
