        {/* Payment Type Selection */}
        <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100">
           <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 block">পেমেন্ট করার পদ্ধতি</label>
           <div className="flex gap-4">
              <button 
                onClick={() => setIsCash(true)}
                className={`flex-1 p-4 rounded-2xl flex flex-col items-center gap-1.5 border-2 transition-all ${isCash ? 'border-green-600 bg-green-50 text-green-700' : 'border-gray-50 text-gray-400'}`}
              >
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${isCash ? 'border-green-600 bg-green-600 text-white shadow-md' : 'border-gray-200'}`}>
                   {isCash && <CheckCircle2 size={14} />}
                </div>
                <span className="font-black text-xs uppercase tracking-wider">নগদ বিক্রি</span>
              </button>
              <button 
                onClick={() => setIsCash(false)}
                className={`flex-1 p-4 rounded-2xl flex flex-col items-center gap-1.5 border-2 transition-all ${!isCash ? 'border-orange-500 bg-orange-50 text-orange-700' : 'border-gray-50 text-gray-400'}`}
              >
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${!isCash ? 'border-orange-500 bg-orange-500 text-white shadow-md' : 'border-gray-200'}`}>
                   {!isCash && <CheckCircle2 size={14} />}
                </div>
                <span className="font-black text-xs uppercase tracking-wider">বাকি বিক্রি</span>
              </button>
