            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">কাস্টমারের তথ্য</label>
            <button 
              onClick={handlePhonebookPicker}
              className="flex items-center gap-1.5 text-blue-600 text-[11px] font-black bg-blue-50 px-3 py-1.5 rounded-full hover:bg-blue-100 transition-colors"
            >
              <ContactIcon size={14} /> ফোনবুক
            </button>
          </div>

          {/* Search/Select Existing Contact */}
          <div className="relative">
            <div className="relative group">
               <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-red-500" size={18} />
               <input 
