              <div className="absolute top-full left-0 right-0 mt-2 bg-white border border-gray-100 rounded-2xl shadow-2xl z-[40] max-h-48 overflow-y-auto overflow-x-hidden animate-in fade-in zoom-in-95">
                {filteredContacts.length > 0 ? filteredContacts.map(c => (
                  <button 
                    key={c.id} 
                    onClick={() => handleSelectExistingContact(c)}
                    className="w-full text-left p-4 hover:bg-red-50 flex items-center justify-between border-b border-gray-50 last:border-0"
                  >
                    <div>
                      <div className="font-bold text-gray-900 text-sm">{c.name}</div>
                      <div className="text-[10px] text-gray-400 font-bold">{c.phone}</div>
                    </div>
                    <div className="bg-white p-1.5 rounded-lg border border-gray-100">
