            )}
          </div>

          <div className="h-px bg-gray-50"></div>

          {/* Manual Entry Fields */}
          <div className="space-y-3">
             <div className="relative group">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input 
