                  value={customerPhone}
                  onChange={(e) => setCustomerPhone(e.target.value)}
                  className="w-full pl-11 pr-4 py-3.5 bg-gray-50 border-2 border-transparent rounded-2xl outline-none font-bold text-sm focus:border-red-500 focus:bg-white transition-all shadow-inner"
