                <span className="font-black text-xs uppercase tracking-wider">নগদ বিক্রি</span>
              </button>
              <button 
                onClick={() => setIsCash(false)}
                className={`flex-1 p-4 rounded-2xl flex flex-col items-center gap-1.5 border-2 transition-all ${!isCash ? 'border-orange-500 bg-orange-50 text-orange-700' : 'border-gray-50 text-gray-400'}`}
              >
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${!isCash ? 'border-orange-500 bg-orange-500 text-white shadow-md' : 'border-gray-200'}`}>
                   {!isCash && <CheckCircle2 size={14} />}
                </div>
                <span className="font-black text-xs uppercase tracking-wider">বাকি বিক্রি</span>
              </button>
           </div>
        </div>

        <button 
          onClick={handleConfirm}
          className="w-full bg-[#D32F2F] text-white py-5 rounded-[2rem] font-black text-lg shadow-2xl shadow-red-200 flex items-center justify-center gap-3 active:scale-95 transition-all mb-4"
        >
          <ShoppingCart size={24} /> বিক্রি নিশ্চিত করুন
