    return saleRecords.filter(r => r.type === 'SALE' && r.date === todayStr);
  }, [saleRecords, todayStr]);

  const todayTotalAmount = todaySales.reduce((acc, curr) => acc + curr.amount, 0);

  const receivableTotal = contacts.reduce((acc, curr) => curr.balance > 0 ? acc + curr.balance : acc, 0);
  const payableTotal = Math.abs(contacts.reduce((acc, curr) => curr.balance < 0 ? acc + curr.balance : acc, 0));

  const filteredContacts = contacts.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.phone.includes(searchTerm);
    if (filterMode === 'RECEIVABLE') return matchesSearch && c.balance > 0;
    if (filterMode === 'PAYABLE') return matchesSearch && c.balance < 0;
    return matchesSearch;
  });

  return (
    <div className="flex flex-col bg-gray-50 min-h-full">
      {/* Today's Sales Summary Card */}
      <div className="mx-4 mt-4 bg-white rounded-[2rem] border border-gray-100 shadow-xl shadow-gray-100/50 overflow-hidden">
