              <div className="py-4 text-center text-gray-300 italic text-xs">আজ এখনো কোনো বিক্রি হয়নি</div>
            )}
            {todaySales.length > 3 && (
              <div className="text-center text-[10px] font-bold text-gray-400 pt-1">আরো {todaySales.length - 3}টি বিক্রি...</div>
