import React, { useState, useMemo, useEffect } from 'react';
import { 
  ArrowLeft, 
  Search, 
  User, 
  Package, 
  Plus, 
  Minus, 
  Trash2, 
  ShoppingCart, 
  CheckCircle2, 
  X, 
  MapPin, 
  Phone,
  Contact as ContactIcon,
  ChevronDown,
  LayoutGrid
} from 'lucide-react';
import { Contact, StockItem, ContactType } from '../types';

interface SaleEntryViewProps {
  contacts: Contact[];
  stockItems: StockItem[];
  onBack: () => void;
  onConfirmSale: (data: { 
    contactId: string; 
    customerName: string;
    customerPhone: string;
    customerAddress: string;
    items: { productId: string; name: string; quantity: number; price: number }[]; 
    total: number; 
    isCash: boolean;
  }) => void;
}

const SaleEntryView: React.FC<SaleEntryViewProps> = ({ contacts, stockItems, onBack, onConfirmSale }) => {
  const [selectedContactId, setSelectedContactId] = useState<string>('CASH_CUSTOMER');
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [cart, setCart] = useState<{ productId: string; quantity: number; price: number }[]>([]);
  const [isCash, setIsCash] = useState(true);
  const [searchTermContact, setSearchTermContact] = useState('');
  const [searchTermProduct, setSearchTermProduct] = useState('');
  const [showProductSelector, setShowProductSelector] = useState(false);
  const [showContactDropdown, setShowContactDropdown] = useState(false);

  const filteredContacts = useMemo(() => {
    return contacts.filter(c => 
      c.type === ContactType.CUSTOMER && 
      (c.name.toLowerCase().includes(searchTermContact.toLowerCase()) || c.phone.includes(searchTermContact))
    );
  }, [contacts, searchTermContact]);

  const filteredProducts = useMemo(() => {
    return stockItems.filter(p => p.name.toLowerCase().includes(searchTermProduct.toLowerCase()));
  }, [stockItems, searchTermProduct]);

  const handleSelectExistingContact = (contact: Contact) => {
    setSelectedContactId(contact.id);
    setCustomerName(contact.name);
    setCustomerPhone(contact.phone);
    setShowContactDropdown(false);
    setSearchTermContact('');
  };

  const handlePhonebookPicker = async () => {
    if (window.self !== window.top) {
      alert('নিরাপত্তার কারণে আইফ্রেম থেকে ফোনবুক এক্সেস করা সম্ভব নয়।');
      return;
    }
    try {
      const nav = navigator as any;
      if (nav.contacts && typeof nav.contacts.select === 'function') {
        const props = ['name', 'tel'];
        const opts = { multiple: false };
        const contactsResult = await nav.contacts.select(props, opts);
        if (contactsResult && contactsResult.length > 0) {
          const selected = contactsResult[0];
          if (selected.name && selected.name.length > 0) setCustomerName(selected.name[0]);
          if (selected.tel && selected.tel.length > 0) setCustomerPhone(selected.tel[0].replace(/[^\d+]/g, ''));
        }
      }
    } catch (err) {}
  };

  const addToCart = (product: StockItem) => {
    const existing = cart.find(item => item.productId === product.id);
    if (existing) {
      setCart(cart.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { productId: product.id, quantity: 1, price: product.sellingPrice }]);
    }
    setShowProductSelector(false);
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.productId === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        const stock = stockItems.find(p => p.id === productId)?.quantity || 0;
        if (newQty > stock) { alert(`স্টক শেষ! (সর্বোচ্চ: ${stock})`); return item; }
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (productId: string) => setCart(cart.filter(item => item.productId !== productId));
  const totalAmount = cart.reduce((acc, item) => acc + (item.quantity * item.price), 0);

  const handleConfirm = () => {
    if (!customerName.trim() || !customerPhone.trim()) return alert('নাম ও ফোন নম্বর দিন!');
    if (cart.length === 0) return alert('পণ্য যোগ করুন!');
    onConfirmSale({
      contactId: selectedContactId,
      customerName,
      customerPhone,
      customerAddress,
      items: cart.map(item => ({ ...item, name: stockItems.find(p => p.id === item.productId)?.name || 'অজানা' })),
      total: totalAmount,
      isCash
    });
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col pb-24 animate-in slide-in-from-right duration-300">
      <header className="flex items-center gap-4 p-4 bg-[#D32F2F] text-white sticky top-0 z-30 shadow-md">
        <button onClick={onBack} className="p-1 active:scale-90 transition-transform"><ArrowLeft size={24} /></button>
        <h2 className="text-lg font-black">নতুন মেমো / বিক্রি</h2>
      </header>

      <div className="p-4 space-y-3">
        {/* Compact Customer Info Section */}
        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm space-y-3">
          <div className="flex justify-between items-center px-1">
             <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">কাস্টমার তথ্য</label>
             <button onClick={handlePhonebookPicker} className="text-[10px] font-black text-blue-600 flex items-center gap-1">
                <ContactIcon size={12} /> ফোনবুক
             </button>
          </div>

          <div className="relative">
             <div className="flex gap-2">
                <div className="flex-1 relative">
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={14} />
                   <input 
                    type="text" 
                    placeholder="নাম লিখুন বা খুঁজুন..." 
                    value={customerName || searchTermContact}
                    onChange={(e) => {
                      setCustomerName(e.target.value);
                      setSearchTermContact(e.target.value);
                      setShowContactDropdown(true);
                      if (selectedContactId !== 'CASH_CUSTOMER' && selectedContactId !== '') setSelectedContactId('');
                    }}
                    onFocus={() => setShowContactDropdown(true)}
                    className="w-full pl-9 pr-4 py-3 bg-gray-50 border border-transparent rounded-2xl outline-none font-bold text-sm focus:border-red-500 focus:bg-white transition-all shadow-inner"
                  />
                </div>
                <div className="w-1/3 relative">
                   <input 
                    type="tel" 
                    placeholder="ফোন" 
                    value={customerPhone}
                    onChange={(e) => setCustomerPhone(e.target.value)}
                    className="w-full px-3 py-3 bg-gray-50 border border-transparent rounded-2xl outline-none font-bold text-sm focus:border-red-500 focus:bg-white transition-all shadow-inner"
                  />
                </div>
             </div>

             {showContactDropdown && searchTermContact && (
              <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-100 rounded-2xl shadow-2xl z-[40] max-h-40 overflow-y-auto animate-in fade-in zoom-in-95">
                {filteredContacts.map(c => (
                  <button key={c.id} onClick={() => handleSelectExistingContact(c)} className="w-full text-left p-3 hover:bg-red-50 flex items-center justify-between border-b border-gray-50 last:border-0">
                    <div>
                      <div className="font-bold text-gray-900 text-xs">{c.name}</div>
                      <div className="text-[9px] text-gray-400 font-bold">{c.phone}</div>
                    </div>
                    <ChevronDown size={14} className="text-gray-300" />
                  </button>
                ))}
              </div>
            )}
          </div>

          <input 
            type="text" 
            placeholder="ঠিকানা (ঐচ্ছিক)" 
            value={customerAddress}
            onChange={(e) => setCustomerAddress(e.target.value)}
            className="w-full px-4 py-2.5 bg-gray-50 border border-transparent rounded-2xl outline-none font-bold text-[13px] focus:border-red-500 focus:bg-white transition-all shadow-inner"
          />
        </div>

        {/* Product Selection List */}
        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex flex-col min-h-[150px]">
          <div className="flex justify-between items-center mb-4 px-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">পণ্যের তালিকা ({cart.length})</label>
            <button onClick={() => setShowProductSelector(true)} className="bg-red-600 text-white p-2 px-4 rounded-full text-[10px] font-black flex items-center gap-1 active:scale-95 transition-all">
              <Plus size={14} /> পণ্য যোগ
            </button>
          </div>

          <div className="flex-1 space-y-3">
            {cart.map(item => {
              const product = stockItems.find(p => p.id === item.productId);
              return (
                <div key={item.productId} className="flex items-center justify-between border-b border-gray-50 pb-2 last:border-0">
                  <div className="flex-1 min-w-0 pr-2">
                    <h4 className="font-bold text-gray-900 text-xs truncate">{product?.name}</h4>
                    <p className="text-[9px] text-gray-400 font-bold uppercase">৳{item.price} × {item.quantity}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="flex items-center bg-gray-50 rounded-full border border-gray-100 p-0.5">
                       <button onClick={() => updateQuantity(item.productId, -1)} className="p-1 text-red-500"><Minus size={12} /></button>
                       <span className="w-5 text-center font-black text-[11px]">{item.quantity}</span>
                       <button onClick={() => updateQuantity(item.productId, 1)} className="p-1 text-green-500"><Plus size={12} /></button>
                    </div>
                    <div className="w-12 text-right font-black text-gray-900 text-xs">৳{item.quantity * item.price}</div>
                    <button onClick={() => removeFromCart(item.productId)} className="text-gray-300 ml-1"><Trash2 size={14} /></button>
                  </div>
                </div>
              );
            })}
            {cart.length === 0 && (
              <div className="flex-1 flex flex-col items-center justify-center py-6 opacity-20">
                <Package size={32} className="mb-1" />
                <p className="text-[10px] font-bold">পণ্য যোগ হয়নি</p>
              </div>
            )}
          </div>

          <div className="mt-4 pt-3 border-t border-dashed border-gray-100 flex justify-between items-center px-1">
            <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">সর্বমোট</span>
            <span className="text-2xl font-black text-gray-900">৳{totalAmount.toLocaleString('bn-BD')}</span>
          </div>
        </div>

        {/* Payment & Action */}
        <div className="flex gap-2 items-center bg-white p-3 rounded-3xl border border-gray-100 shadow-sm">
           <div className="flex-1 flex gap-1 p-1 bg-gray-50 rounded-2xl">
              <button onClick={() => setIsCash(true)} className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase transition-all ${isCash ? 'bg-white text-green-600 shadow-sm' : 'text-gray-400'}`}>নগদ</button>
              <button onClick={() => setIsCash(false)} className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase transition-all ${!isCash ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-400'}`}>বাকি</button>
           </div>
           <button onClick={handleConfirm} className="flex-[1.5] bg-[#D32F2F] text-white py-4 rounded-2xl font-black text-sm shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2">
              <ShoppingCart size={18} /> মেমো সেভ করুন
           </button>
        </div>
      </div>

      {/* Product Selector */}
      {showProductSelector && (
        <div className="fixed inset-0 bg-black/60 z-[100] flex items-end justify-center backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] p-6 animate-in slide-in-from-bottom duration-300 h-[70vh] flex flex-col">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-gray-900">পণ্য সিলেক্ট করুন</h3>
                <button onClick={() => setShowProductSelector(false)} className="p-2 bg-gray-50 rounded-full"><X size={18} /></button>
             </div>
             <div className="relative mb-4">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                <input type="text" placeholder="পণ্যের নাম খুঁজুন..." value={searchTermProduct} onChange={(e) => setSearchTermProduct(e.target.value)} className="w-full pl-9 pr-4 py-3 bg-gray-50 rounded-2xl outline-none font-bold text-sm" autoFocus />
             </div>
             <div className="flex-1 overflow-y-auto space-y-2 no-scrollbar">
                {filteredProducts.map(p => (
                  <button key={p.id} onClick={() => addToCart(p)} className="w-full flex items-center justify-between p-4 bg-gray-50 rounded-2xl hover:bg-red-50 transition-all text-left">
                    <div>
                      <div className="font-bold text-gray-900 text-sm">{p.name}</div>
                      <div className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter">স্টক: {p.quantity} {p.unit}</div>
                    </div>
                    <div className="text-right">
                       <div className="text-sm font-black text-red-600">৳{p.sellingPrice}</div>
                    </div>
                  </button>
                ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

