  });

  const [contacts, setContacts] = useState<Contact[]>(() => {
    const saved = localStorage.getItem('dokan_contacts');
    return saved ? JSON.parse(saved) : [];
  });

  const [salePurchaseRecords, setSalePurchaseRecords] = useState<SalePurchaseRecord[]>(() => {
    const saved = localStorage.getItem('dokan_becha_kena');
    return saved ? JSON.parse(saved) : [];
  });

  const [stockItems, setStockItems] = useState<StockItem[]>(() => {
    const saved = localStorage.getItem('dokan_stock');
    return saved ? JSON.parse(saved) : [];
  });

  const [aiMessages, setAiMessages] = useState<Message[]>([
    { 
      role: 'ai', 
      text: 'আসসালামু আলাইকুম! আমি আপনার দোকানের এআই অ্যাসিস্ট্যান্ট।' 
    }
  ]);

  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingContact, setEditingContact] = useState<Contact | undefined>(undefined);

  // Persistence to LocalStorage
  useEffect(() => {
    localStorage.setItem('dokan_contacts', JSON.stringify(contacts));
  }, [contacts]);

  useEffect(() => {
    localStorage.setItem('dokan_becha_kena', JSON.stringify(salePurchaseRecords));
  }, [salePurchaseRecords]);

  useEffect(() => {
    localStorage.setItem('dokan_stock', JSON.stringify(stockItems));
  }, [stockItems]);

  // Automatic Background Backup (Simulated)
  useEffect(() => {
    if (isLoggedIn) {
      const timeout = setTimeout(() => {
        const now = new Date().toLocaleString('bn-BD');
        localStorage.setItem('dokan_google_drive_file', JSON.stringify({ contacts, salePurchaseRecords, stockItems }));
        localStorage.setItem('dokan_last_sync', now);
      }, 5000); 
      return () => clearTimeout(timeout);
    }
  }, [isLoggedIn, contacts, salePurchaseRecords, stockItems]);

  const handleRestoreData = (restoredData: any) => {
    setIsSyncing(true);
    setTimeout(() => {
      if (restoredData.contacts) setContacts(restoredData.contacts);
      if (restoredData.salePurchaseRecords) setSalePurchaseRecords(restoredData.salePurchaseRecords);
      if (restoredData.stockItems) setStockItems(restoredData.stockItems);
      setIsSyncing(false);
      setCurrentView('TALLY');
    }, 2000);
  };

  const addContact = (updatedContact: Contact) => {
    const exists = contacts.find(c => c.id === updatedContact.id);
    if (exists) {
      setContacts(prev => prev.map(c => c.id === updatedContact.id ? updatedContact : c));
    } else {
      setContacts(prev => [...prev, updatedContact]);
    }
    setEditingContact(undefined);
    setCurrentView('TALLY');
  };

  const deleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
    setCurrentView('TALLY');
  };

  const addSalePurchaseRecord = (record: SalePurchaseRecord) => {
    setSalePurchaseRecords(prev => [...prev, record]);
  };

  const updateContactTransactions = (contactId: string, transaction: Transaction) => {
    setContacts(prev => prev.map(c => {
      if (c.id === contactId) {
        const newBalance = transaction.type === 'DUE_GIVEN' 
          ? c.balance + transaction.amount 
          : c.balance - transaction.amount;
        return {
          ...c,
          balance: newBalance,
          lastActivity: 'এখনই',
          transactions: [transaction, ...c.transactions]
        };
      }
      return c;
    }));
  };

  const handleUpdateStock = (updatedItems: StockItem[]) => {
    setStockItems(updatedItems);
  };

  const handleConfirmSale = (saleData: { 
    contactId: string; 
    customerName: string;
    customerPhone: string;
    customerAddress: string;
    items: { productId: string; name: string; quantity: number; price: number }[]; 
    total: number; 
    isCash: boolean;
  }) => {
    const date = new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });

    // 1. Subtract stock
    const updatedStock = stockItems.map(p => {
      const soldItem = saleData.items.find(si => si.productId === p.id);
      if (soldItem) {
        return { ...p, quantity: p.quantity - soldItem.quantity };
      }
      return p;
    });
    setStockItems(updatedStock);

    // 2. Record sale with full customer details
    const record: SalePurchaseRecord = {
      id: Date.now().toString(),
      type: 'SALE',
      amount: saleData.total,
      description: saleData.items.map(i => `${i.name} (${i.quantity})`).join(', '),
      date,
      isCash: saleData.isCash,
      customerName: saleData.customerName,
      customerPhone: saleData.customerPhone,
      customerAddress: saleData.customerAddress,
      items: saleData.items
    };
    setSalePurchaseRecords(prev => [...prev, record]);

    // 3. Handle Credit/Due sale to contact
    if (!saleData.isCash && saleData.contactId !== 'CASH_CUSTOMER' && saleData.contactId !== '') {
      const transaction: Transaction = {
        id: (Date.now() + 1).toString(),
        type: 'DUE_GIVEN',
        amount: saleData.total,
        description: `বিক্রি: ${record.description}`,
        date
      };
      updateContactTransactions(saleData.contactId, transaction);
    } else if (!saleData.isCash && (saleData.contactId === 'CASH_CUSTOMER' || saleData.contactId === '')) {
       // If credit sale but no existing contact, create one
       const newContactId = Date.now().toString();
       const newContact: Contact = {
          id: newContactId,
          name: saleData.customerName,
          phone: saleData.customerPhone,
          type: ContactType.CUSTOMER,
          balance: saleData.total,
          lastActivity: 'এখনই',
          transactions: [{
            id: (Date.now() + 2).toString(),
            type: 'DUE_GIVEN',
            amount: saleData.total,
            description: `বিক্রি: ${record.description}`,
            date
          }]
       };
       setContacts(prev => [...prev, newContact]);
    }

    setCurrentView('TALLY');
    alert(`অর্ডার সফল! ${saleData.customerName}-এর নামে ${saleData.total} টাকার মেমো তৈরি হয়েছে।`);
  };

  const selectedContact = useMemo(() => 
    contacts.find(c => c.id === selectedContactId), 
    [contacts, selectedContactId]
  );

  const handleHelpClick = () => {
    window.open(HELP_WHATSAPP_URL, '_blank');
  };

  const handleLoginSuccess = (profile: UserProfile) => {
    setUser(profile);
    setIsLoggedIn(true);
    localStorage.setItem('dokan_user_logged_in', 'true');
    localStorage.setItem('dokan_user_profile', JSON.stringify(profile));
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUser(null);
    localStorage.removeItem('dokan_user_logged_in');
    localStorage.removeItem('dokan_user_profile');
    setCurrentView('TALLY');
    setIsSidebarOpen(false);
  };

  const handleNavigation = (view: ViewState) => {
    if (view === 'MENU') {
      setIsSidebarOpen(true);
    } else {
      setCurrentView(view);
    }
  };

  const renderView = () => {
    if (isSyncing) {
      return (
        <div className="flex-1 flex flex-col items-center justify-center p-10 text-center space-y-6">
          <div className="relative">
             <div className="w-20 h-20 border-4 border-red-50 border-t-red-600 rounded-full animate-spin"></div>
             <div className="absolute inset-0 flex items-center justify-center">
                <img src="https://www.google.com/favicon.ico" alt="g" className="w-6 h-6 animate-pulse" />
             </div>
          </div>
          <div>
            <h3 className="text-xl font-black text-gray-900 leading-tight">ড্রাইভ থেকে ডাটা লোড হচ্ছে...</h3>
            <p className="text-sm text-gray-400 font-bold mt-2 uppercase tracking-widest">দয়া করে অপেক্ষা করুন</p>
          </div>
        </div>
      );
    }

    switch (currentView) {
      case 'TALLY':
        return <TallyView contacts={contacts} saleRecords={salePurchaseRecords} onSelectContact={id => { setSelectedContactId(id); setCurrentView('CONTACT_DETAILS'); }} onAddContact={() => { setEditingContact(undefined); setCurrentView('ADD_CONTACT'); }} onNavigate={handleNavigation} />;
      case 'CASHBOX': return <CashboxView />;
      case 'ADD_CONTACT': return <AddContactForm onBack={() => setCurrentView(editingContact ? 'CONTACT_DETAILS' : 'TALLY')} onSave={addContact} editContact={editingContact} />;
      case 'CONTACT_DETAILS': return selectedContact ? <ContactDetails contact={selectedContact} onBack={() => setCurrentView('TALLY')} onAddTransaction={t => updateContactTransactions(selectedContact.id, t)} onDeleteContact={deleteContact} onEditContact={c => { setEditingContact(c); setCurrentView('ADD_CONTACT'); }} /> : null;
      case 'BECHA_KENA': return <BechaKenaView records={salePurchaseRecords} onBack={() => setCurrentView('TALLY')} onAddRecord={addSalePurchaseRecord} />;
      case 'CLOUD_BACKUP': return <CloudBackup data={{ contacts, salePurchaseRecords, stockItems }} onBack={() => setCurrentView('TALLY')} onLoginSuccess={handleLoginSuccess} onLogout={handleLogout} onRestore={handleRestoreData} currentLoggedInState={isLoggedIn} currentUserProfile={user} />;
      case 'AI_CHAT': return <AIChatView contacts={contacts} records={salePurchaseRecords} onBack={() => setCurrentView('TALLY')} persistedMessages={aiMessages} onMessagesUpdate={setAiMessages} onClearChat={() => setAiMessages([])} />;
      case 'STOCK': return <StockView items={stockItems} onBack={() => setCurrentView('TALLY')} onUpdateStock={handleUpdateStock} />;
      case 'SALE_ENTRY': return <SaleEntryView contacts={contacts} stockItems={stockItems} onBack={() => setCurrentView('TALLY')} onConfirmSale={handleConfirmSale} />;
      default: return <TallyView contacts={contacts} saleRecords={salePurchaseRecords} onSelectContact={() => {}} onAddContact={() => {}} onNavigate={handleNavigation} />;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen flex flex-col relative shadow-xl">
      <header className="bg-[#D32F2F] text-white px-4 py-3 sticky top-0 z-40 shadow-md">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer active:opacity-80 transition-opacity" onClick={() => setIsSidebarOpen(true)}>
            <div className="bg-white/20 p-1 rounded-md flex items-center gap-2">
              {isLoggedIn && user ? <img src={user.photo} className="w-5 h-5 rounded-full border border-white/40 object-cover" alt="p" /> : <div className="w-5 h-5 rounded-full bg-white/20 flex items-center justify-center text-[10px] font-bold">অ</div>}
              <span className="text-sm font-bold truncate max-w-[100px]">{isLoggedIn && user ? user.name.split(' ')[0].toLowerCase() : 'অতিথি'}</span>
            </div>
            <ChevronDown size={16} />
          </div>
          <div className="flex items-center gap-4">
            <div onClick={() => setCurrentView('AI_CHAT')} className="flex flex-col items-center cursor-pointer"><Sparkles size={24} className="text-yellow-300" /><span className="text-[10px] mt-1 text-white font-bold">এআই</span></div>
            <div className="relative flex flex-col items-center cursor-pointer"><Bell size={24} /><span className="text-[10px] mt-1 text-white font-bold">ইনবক্স</span></div>
            <div onClick={handleHelpClick} className="flex flex-col items-center cursor-pointer"><HelpCircle size={24} /><span className="text-[10px] mt-1 text-white font-bold">হেল্প</span></div>
          </div>
        </div>
      </header>
      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} isLoggedIn={isLoggedIn} user={user} onNavigate={view => { setCurrentView(view); setIsSidebarOpen(false); }} onLogout={handleLogout} />
      <main className="flex-1 overflow-y-auto pb-20 bg-gray-50">{renderView()}</main>
      {['TALLY', 'CASHBOX', 'STOCK'].includes(currentView) || currentView === 'TALLY' ? (
        <Navigation currentView={currentView} onNavigate={handleNavigation} />
      ) : null}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  ArrowLeft, 
  Search, 
  User, 
  Package, 
  Plus, 
  Minus, 
  Trash2, 
  ShoppingCart, 
  CheckCircle2, 
  X, 
  MapPin, 
  Phone,
  Contact as ContactIcon,
  ChevronDown,
  LayoutGrid
} from 'lucide-react';
import { Contact, StockItem, ContactType } from '../types';

interface SaleEntryViewProps {
  contacts: Contact[];
  stockItems: StockItem[];
  onBack: () => void;
  onConfirmSale: (data: { 
    contactId: string; 
    customerName: string;
    customerPhone: string;
    customerAddress: string;
    items: { productId: string; name: string; quantity: number; price: number }[]; 
    total: number; 
    isCash: boolean;
  }) => void;
}

const SaleEntryView: React.FC<SaleEntryViewProps> = ({ contacts, stockItems, onBack, onConfirmSale }) => {
  const [selectedContactId, setSelectedContactId] = useState<string>('CASH_CUSTOMER');
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [cart, setCart] = useState<{ productId: string; quantity: number; price: number }[]>([]);
  const [isCash, setIsCash] = useState(true);
  const [searchTermContact, setSearchTermContact] = useState('');
  const [searchTermProduct, setSearchTermProduct] = useState('');
  const [showProductSelector, setShowProductSelector] = useState(false);
  const [showContactDropdown, setShowContactDropdown] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowContactDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const filteredContacts = useMemo(() => {
    return contacts.filter(c => 
      c.type === ContactType.CUSTOMER && 
      (c.name.toLowerCase().includes(searchTermContact.toLowerCase()) || c.phone.includes(searchTermContact))
    );
  }, [contacts, searchTermContact]);

  const filteredProducts = useMemo(() => {
    return stockItems.filter(p => p.name.toLowerCase().includes(searchTermProduct.toLowerCase()));
  }, [stockItems, searchTermProduct]);

  const handleSelectExistingContact = (contact: Contact) => {
    setSelectedContactId(contact.id);
    setCustomerName(contact.name);
    setCustomerPhone(contact.phone);
    setShowContactDropdown(false);
    setSearchTermContact('');
  };

  const handlePhonebookPicker = async () => {
    if (window.self !== window.top) {
      alert('নিরাপত্তার কারণে আইফ্রেম থেকে ফোনবুক এক্সেস করা সম্ভব নয়।');
      return;
    }
    try {
      const nav = navigator as any;
      if (nav.contacts && typeof nav.contacts.select === 'function') {
        const props = ['name', 'tel'];
        const opts = { multiple: false };
        const contactsResult = await nav.contacts.select(props, opts);
        if (contactsResult && contactsResult.length > 0) {
          const selected = contactsResult[0];
          if (selected.name && selected.name.length > 0) setCustomerName(selected.name[0]);
          if (selected.tel && selected.tel.length > 0) setCustomerPhone(selected.tel[0].replace(/[^\d+]/g, ''));
        }
      }
    } catch (err) {}
  };

  const addToCart = (product: StockItem) => {
    const existing = cart.find(item => item.productId === product.id);
    if (existing) {
      setCart(cart.map(item => item.productId === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { productId: product.id, quantity: 1, price: product.sellingPrice }]);
    }
    setShowProductSelector(false);
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.productId === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        const stock = stockItems.find(p => p.id === productId)?.quantity || 0;
        if (newQty > stock) { alert(`স্টক শেষ! (সর্বোচ্চ: ${stock})`); return item; }
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (productId: string) => setCart(cart.filter(item => item.productId !== productId));
  const totalAmount = cart.reduce((acc, item) => acc + (item.quantity * item.price), 0);

  const handleConfirm = () => {
    if (!customerName.trim() || !customerPhone.trim()) return alert('নাম ও ফোন নম্বর দিন!');
    if (cart.length === 0) return alert('পণ্য যোগ করুন!');
    onConfirmSale({
      contactId: selectedContactId,
      customerName,
      customerPhone,
      customerAddress,
      items: cart.map(item => ({ ...item, name: stockItems.find(p => p.id === item.productId)?.name || 'অজানা' })),
      total: totalAmount,
      isCash
    });
  };

  return (
    <div className="bg-gray-50 min-h-full flex flex-col pb-24 animate-in slide-in-from-right duration-300">
      <header className="flex items-center gap-4 p-4 bg-[#D32F2F] text-white sticky top-0 z-30 shadow-md">
        <button onClick={onBack} className="p-1 active:scale-90 transition-transform"><ArrowLeft size={24} /></button>
        <h2 className="text-lg font-black">নতুন মেমো / বিক্রি</h2>
      </header>

      <div className="p-4 space-y-3">
        {/* Compact Customer Info Section */}
        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm space-y-3 relative" ref={dropdownRef}>
          <div className="flex justify-between items-center px-1">
             <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">কাস্টমার তথ্য</label>
             <button onClick={handlePhonebookPicker} className="text-[10px] font-black text-blue-600 flex items-center gap-1">
                <ContactIcon size={12} /> ফোনবুক
             </button>
          </div>

          <div className="relative">
             <div className="flex gap-2">
                <div className="flex-1 relative">
                   <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={14} />
                   <input 
                    type="text" 
                    placeholder="নাম লিখে খুঁজুন..." 
                    value={customerName}
                    onChange={(e) => {
                      setCustomerName(e.target.value);
                      setSearchTermContact(e.target.value);
                      setShowContactDropdown(true);
                      if (selectedContactId !== 'CASH_CUSTOMER' && selectedContactId !== '') setSelectedContactId('');
                    }}
                    onClick={() => setShowContactDropdown(true)}
                    onFocus={() => setShowContactDropdown(true)}
                    className="w-full pl-9 pr-4 py-3 bg-gray-50 border border-transparent rounded-2xl outline-none font-bold text-sm focus:border-red-500 focus:bg-white transition-all shadow-inner"
                  />
                </div>
                <div className="w-1/3 relative">
                   <input 
                    type="tel" 
                    placeholder="ফোন" 
                    value={customerPhone}
                    onChange={(e) => setCustomerPhone(e.target.value)}
                    className="w-full px-3 py-3 bg-gray-50 border border-transparent rounded-2xl outline-none font-bold text-sm focus:border-red-500 focus:bg-white transition-all shadow-inner"
                  />
                </div>
             </div>

             {showContactDropdown && (
              <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-100 rounded-2xl shadow-2xl z-[50] max-h-56 overflow-y-auto animate-in fade-in zoom-in-95 ring-1 ring-black/5">
                <div className="sticky top-0 bg-gray-50 px-3 py-1.5 text-[9px] font-black text-gray-400 uppercase tracking-widest border-b border-gray-100">
                  আপনার কন্টাক্ট লিস্ট ({filteredContacts.length})
                </div>
                {filteredContacts.length > 0 ? filteredContacts.map(c => (
                  <button 
                    key={c.id} 
                    onClick={() => handleSelectExistingContact(c)} 
                    className="w-full text-left p-3.5 hover:bg-red-50 flex items-center justify-between border-b border-gray-50 last:border-0 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center font-black text-[10px] text-gray-400">
                        {c.name[0]}
                      </div>
                      <div>
                        <div className="font-bold text-gray-900 text-xs">{c.name}</div>
                        <div className="text-[9px] text-gray-400 font-bold">{c.phone}</div>
                      </div>
                    </div>
                    <ChevronDown size={14} className="text-gray-300 -rotate-90" />
                  </button>
                )) : (
                  <div className="p-6 text-center">
                    <p className="text-[10px] font-bold text-gray-400 italic">নতুন কাস্টমার হিসেবে এন্ট্রি হবে</p>
                  </div>
                )}
              </div>
            )}
          </div>

          <input 
            type="text" 
            placeholder="ঠিকানা (ঐচ্ছিক)" 
            value={customerAddress}
            onChange={(e) => setCustomerAddress(e.target.value)}
            className="w-full px-4 py-2.5 bg-gray-50 border border-transparent rounded-2xl outline-none font-bold text-[13px] focus:border-red-500 focus:bg-white transition-all shadow-inner"
          />
        </div>

        {/* Product Selection List */}
        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex flex-col min-h-[150px]">
          <div className="flex justify-between items-center mb-4 px-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">পণ্যের তালিকা ({cart.length})</label>
            <button onClick={() => setShowProductSelector(true)} className="bg-red-600 text-white p-2 px-4 rounded-full text-[10px] font-black flex items-center gap-1 active:scale-95 transition-all">
              <Plus size={14} /> পণ্য যোগ
            </button>
          </div>

          <div className="flex-1 space-y-3">
            {cart.map(item => {
              const product = stockItems.find(p => p.id === item.productId);
              return (
                <div key={item.productId} className="flex items-center justify-between border-b border-gray-50 pb-2 last:border-0">
                  <div className="flex-1 min-w-0 pr-2">
                    <h4 className="font-bold text-gray-900 text-xs truncate">{product?.name}</h4>
                    <p className="text-[9px] text-gray-400 font-bold uppercase">৳{item.price} × {item.quantity}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="flex items-center bg-gray-50 rounded-full border border-gray-100 p-0.5">
                       <button onClick={() => updateQuantity(item.productId, -1)} className="p-1 text-red-500"><Minus size={12} /></button>
                       <span className="w-5 text-center font-black text-[11px]">{item.quantity}</span>
                       <button onClick={() => updateQuantity(item.productId, 1)} className="p-1 text-green-500"><Plus size={12} /></button>
                    </div>
                    <div className="w-12 text-right font-black text-gray-900 text-xs">৳{item.quantity * item.price}</div>
                    <button onClick={() => removeFromCart(item.productId)} className="text-gray-300 ml-1"><Trash2 size={14} /></button>
                  </div>
                </div>
              );
            })}
            {cart.length === 0 && (
              <div className="flex-1 flex flex-col items-center justify-center py-6 opacity-20">
                <Package size={32} className="mb-1" />
                <p className="text-[10px] font-bold">পণ্য যোগ হয়নি</p>
              </div>
            )}
          </div>

          <div className="mt-4 pt-3 border-t border-dashed border-gray-100 flex justify-between items-center px-1">
            <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">সর্বমোট</span>
            <span className="text-2xl font-black text-gray-900">৳{totalAmount.toLocaleString('bn-BD')}</span>
          </div>
        </div>

        {/* Payment & Action */}
        <div className="flex gap-2 items-center bg-white p-3 rounded-3xl border border-gray-100 shadow-sm">
           <div className="flex-1 flex gap-1 p-1 bg-gray-50 rounded-2xl">
              <button onClick={() => setIsCash(true)} className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase transition-all ${isCash ? 'bg-white text-green-600 shadow-sm' : 'text-gray-400'}`}>নগদ</button>
              <button onClick={() => setIsCash(false)} className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase transition-all ${!isCash ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-400'}`}>বাকি</button>
           </div>
           <button onClick={handleConfirm} className="flex-[1.5] bg-[#D32F2F] text-white py-4 rounded-2xl font-black text-sm shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2">
              <ShoppingCart size={18} /> মেমো সেভ করুন
           </button>
        </div>
      </div>

      {/* Product Selector */}
      {showProductSelector && (
        <div className="fixed inset-0 bg-black/60 z-[100] flex items-end justify-center backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] p-6 animate-in slide-in-from-bottom duration-300 h-[70vh] flex flex-col">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-gray-900">পণ্য সিলেক্ট করুন</h3>
                <button onClick={() => setShowProductSelector(false)} className="p-2 bg-gray-100 rounded-full"><X size={18} /></button>
             </div>
             <div className="relative mb-4">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                <input type="text" placeholder="পণ্যের নাম খুঁজুন..." value={searchTermProduct} onChange={(e) => setSearchTermProduct(e.target.value)} className="w-full pl-9 pr-4 py-3 bg-gray-50 rounded-2xl outline-none font-bold text-sm" autoFocus />
             </div>
             <div className="flex-1 overflow-y-auto space-y-2 no-scrollbar">
                {filteredProducts.map(p => (
                  <button key={p.id} onClick={() => addToCart(p)} className="w-full flex items-center justify-between p-4 bg-gray-50 rounded-2xl hover:bg-red-50 transition-all text-left">
                    <div>
                      <div className="font-bold text-gray-900 text-sm">{p.name}</div>
                      <div className="text-[10px] text-gray-400 font-bold uppercase tracking-tighter">স্টক: {p.quantity} {p.unit}</div>
                    </div>
                    <div className="text-right">
                       <div className="text-sm font-black text-red-600">৳{p.sellingPrice}</div>
                    </div>
                  </button>
                ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SaleEntryView;

