import React, { useState, useEffect, useRef } from 'react';
import { 
  ArrowLeft, 
  CloudUpload, 
  CheckCircle2, 
  RefreshCw, 
  Database, 
  ShieldCheck, 
  LogOut, 
  Sparkles, 
  DownloadCloud, 
  Clock, 
  User, 
  X, 
  ShieldAlert, 
  Mail, 
  Lock, 
  ArrowRight, 
  UserPlus, 
  BellRing, 
  Store, 
  MapPin, 
  Camera, 
  Save 
} from 'lucide-react';
import { ShopSettings } from '../types';

export interface UserProfile {
  name: string;
  email: string;
  id: string; 
  photo: string;
  provider: 'google';
}

interface CloudBackupProps {
  onBack: () => void;
  data: any;
  onLoginSuccess: (profile: UserProfile) => void;
  onLogout: () => void;
  onRestore: (data: any) => void;
  currentLoggedInState: boolean;
  currentUserProfile: UserProfile | null;
  shopSettings: ShopSettings;
  onUpdateShopSettings: (settings: ShopSettings) => void;
}

type AuthStage = 'CHOICE' | 'PICKER' | 'MANUAL_EMAIL' | 'VERIFY' | 'LOGGED_IN';

const CloudBackup: React.FC<CloudBackupProps> = ({ 
  onBack, 
  data, 
  onLoginSuccess, 
  onLogout, 
  onRestore,
  currentLoggedInState, 
  currentUserProfile,
  shopSettings,
  onUpdateShopSettings
}) => {
  const [stage, setStage] = useState<AuthStage>(currentLoggedInState ? 'LOGGED_IN' : 'CHOICE');
  const [selectedEmail, setSelectedEmail] = useState<string>('');
  const [manualEmail, setManualEmail] = useState<string>('');
  const [verificationCode, setVerificationCode] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [isRestoring, setIsRestoring] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showNotification, setShowNotification] = useState(false);
  const [lastSynced, setLastSynced] = useState<string | null>(() => localStorage.getItem('dokan_last_sync'));
  const [syncSuccess, setSyncSuccess] = useState(false);
  const [hasCloudBackup, setHasCloudBackup] = useState(false);

  // Local state for settings editing
  const [tempShopName, setTempShopName] = useState(shopSettings.shopName);
  const [tempShopAddress, setTempShopAddress] = useState(shopSettings.shopAddress);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (currentLoggedInState) {
      setStage('LOGGED_IN');
      const backup = localStorage.getItem('dokan_google_drive_file');
      if (backup) setHasCloudBackup(true);
    } else {
      setStage('CHOICE');
    }
  }, [currentLoggedInState]);

  const triggerSimulatedEmail = () => {
    setTimeout(() => {
      setShowNotification(true);
      setTimeout(() => setShowNotification(false), 8000);
    }, 500);
  };

  const handleOpenAccountPicker = () => {
    setIsLoading(true);
    setTimeout(() => {
      setStage('PICKER');
      setIsLoading(false);
    }, 800);
  };

  const handleSelectAccount = (email: string) => {
    setSelectedEmail(email);
    setIsLoading(true);
    setTimeout(() => {
      setStage('VERIFY');
      setIsLoading(false);
      triggerSimulatedEmail();
    }, 1200);
  };

  const handleManualEmailSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualEmail.toLowerCase().endsWith('@gmail.com')) {
      alert('অনুগ্রহ করে একটি সঠিক জিমেইল অ্যাড্রেস দিন।');
      return;
    }
    setSelectedEmail(manualEmail);
    setIsLoading(true);
    setTimeout(() => {
      setStage('VERIFY');
      setIsLoading(false);
      triggerSimulatedEmail();
    }, 1200);
  };

  const handleVerifyCode = (e: React.FormEvent) => {
    e.preventDefault();
    if (verificationCode !== '123456') {
      alert('ভুল কোড!');
      return;
    }

    setIsLoading(true);
    setTimeout(() => {
      const mockUser: UserProfile = {
        name: selectedEmail.split('@')[0].split('.').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' '),
        email: selectedEmail,
        id: selectedEmail,
        photo: `https://api.dicebear.com/7.x/avataaars/svg?seed=${selectedEmail}`,
        provider: 'google'
      };
      onLoginSuccess(mockUser);
      setStage('LOGGED_IN');
      setIsLoading(false);
      setShowNotification(false);
    }, 1500);
  };

  const handleSyncToDrive = () => {
    setIsSyncing(true);
    setSyncSuccess(false);
    setTimeout(() => {
      const now = new Date().toLocaleString('bn-BD');
      localStorage.setItem('dokan_google_drive_file', JSON.stringify(data));
      localStorage.setItem('dokan_last_sync', now);
      setLastSynced(now);
      setIsSyncing(false);
      setSyncSuccess(true);
      setHasCloudBackup(true);
      setTimeout(() => setSyncSuccess(false), 5000);
    }, 2000);
  };

  const handleLoadFromDrive = () => {
    setIsRestoring(true);
    const backup = localStorage.getItem('dokan_google_drive_file');
    setTimeout(() => {
      if (backup) {
        onRestore(JSON.parse(backup));
        setIsRestoring(false);
