  const [salePurchaseRecords, setSalePurchaseRecords] = useState<SalePurchaseRecord[]>(() => {
    const saved = localStorage.getItem('dokan_becha_kena');
    return saved ? JSON.parse(saved) : [];
  });

  const [stockItems, setStockItems] = useState<StockItem[]>(() => {
    const saved = localStorage.getItem('dokan_stock');
    return saved ? JSON.parse(saved) : [];
  });

  const [aiMessages, setAiMessages] = useState<Message[]>([
    { 
      role: 'ai', 
      text: 'আসসালামু আলাইকুম! আমি আপনার দোকানের এআই অ্যাসিস্ট্যান্ট।' 
    }
  ]);

  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingContact, setEditingContact] = useState<Contact | undefined>(undefined);

  // Persistence to LocalStorage
  useEffect(() => {
    localStorage.setItem('dokan_contacts', JSON.stringify(contacts));
  }, [contacts]);

  useEffect(() => {
    localStorage.setItem('dokan_becha_kena', JSON.stringify(salePurchaseRecords));
  }, [salePurchaseRecords]);

  useEffect(() => {
    localStorage.setItem('dokan_stock', JSON.stringify(stockItems));
  }, [stockItems]);

  useEffect(() => {
    localStorage.setItem('dokan_shop_settings', JSON.stringify(shopSettings));
  }, [shopSettings]);

  // Automatic Background Backup (Simulated)
  useEffect(() => {
    if (isLoggedIn) {
      const timeout = setTimeout(() => {
        const now = new Date().toLocaleString('bn-BD');
        localStorage.setItem('dokan_google_drive_file', JSON.stringify({ contacts, salePurchaseRecords, stockItems, shopSettings }));
        localStorage.setItem('dokan_last_sync', now);
      }, 5000); 
      return () => clearTimeout(timeout);
    }
  }, [isLoggedIn, contacts, salePurchaseRecords, stockItems, shopSettings]);

  const handleRestoreData = (restoredData: any) => {
    setIsSyncing(true);
    setTimeout(() => {
      if (restoredData.contacts) setContacts(restoredData.contacts);
      if (restoredData.salePurchaseRecords) setSalePurchaseRecords(restoredData.salePurchaseRecords);
      if (restoredData.stockItems) setStockItems(restoredData.stockItems);
      if (restoredData.shopSettings) setShopSettings(restoredData.shopSettings);
      setIsSyncing(false);
      setCurrentView('TALLY');
    }, 2000);
  };

  const addContact = (updatedContact: Contact) => {
    const exists = contacts.find(c => c.id === updatedContact.id);
    if (exists) {
      setContacts(prev => prev.map(c => c.id === updatedContact.id ? updatedContact : c));
    } else {
      setContacts(prev => [...prev, updatedContact]);
    }
    setEditingContact(undefined);
    setCurrentView('TALLY');
  };

  const deleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
    setCurrentView('TALLY');
  };

  const addSalePurchaseRecord = (record: SalePurchaseRecord) => {
    setSalePurchaseRecords(prev => [...prev, record]);
  };

  const updateContactTransactions = (contactId: string, transaction: Transaction) => {
    setContacts(prev => prev.map(c => {
      if (c.id === contactId) {
        const newBalance = transaction.type === 'DUE_GIVEN' 
          ? c.balance + transaction.amount 
          : c.balance - transaction.amount;
        return {
          ...c,
          balance: newBalance,
          lastActivity: 'এখনই',
          transactions: [transaction, ...c.transactions]
        };
      }
      return c;
    }));
  };

  const handleUpdateStock = (updatedItems: StockItem[]) => {
    setStockItems(updatedItems);
  };

  const handleConfirmSale = (saleData: { 
    contactId: string; 
    customerName: string;
    customerPhone: string;
    customerAddress: string;
    items: { productId: string; name: string; quantity: number; price: number }[]; 
    total: number; 
    isCash: boolean;
  }): SalePurchaseRecord => {
    const date = new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });

    // 1. Subtract stock
    const updatedStock = stockItems.map(p => {
      const soldItem = saleData.items.find(si => si.productId === p.id);
      if (soldItem) {
        return { ...p, quantity: p.quantity - soldItem.quantity };
      }
      return p;
    });
    setStockItems(updatedStock);

    // 2. Record sale with full customer details
    const record: SalePurchaseRecord = {
      id: Date.now().toString(),
      type: 'SALE',
      amount: saleData.total,
      description: saleData.items.map(i => `${i.name} (${i.quantity})`).join(', '),
      date,
      isCash: saleData.isCash,
      customerName: saleData.customerName,
      customerPhone: saleData.customerPhone,
      customerAddress: saleData.customerAddress,
      items: saleData.items
    };
    setSalePurchaseRecords(prev => [...prev, record]);

    // 3. Handle Credit/Due sale to contact
    if (!saleData.isCash && saleData.contactId !== 'CASH_CUSTOMER' && saleData.contactId !== '') {
      const transaction: Transaction = {
        id: (Date.now() + 1).toString(),
        type: 'DUE_GIVEN',
        amount: saleData.total,
        description: `বিক্রি: ${record.description}`,
        date
      };
      updateContactTransactions(saleData.contactId, transaction);
    } else if (!saleData.isCash && (saleData.contactId === 'CASH_CUSTOMER' || saleData.contactId === '')) {
       // If credit sale but no existing contact, create one
       const newContactId = Date.now().toString();
       const newContact: Contact = {
          id: newContactId,
          name: saleData.customerName,
          phone: saleData.customerPhone,
          type: ContactType.CUSTOMER,
          balance: saleData.total,
          lastActivity: 'এখনই',
          transactions: [{
            id: (Date.now() + 2).toString(),
            type: 'DUE_GIVEN',
            amount: saleData.total,
            description: `বিক্রি: ${record.description}`,
            date
          }]
       };
       setContacts(prev => [...prev, newContact]);
    }

    return record;
  };

  const selectedContact = useMemo(() => 
    contacts.find(c => c.id === selectedContactId), 
    [contacts, selectedContactId]
  );

  const handleHelpClick = () => {
    window.open(HELP_WHATSAPP_URL, '_blank');
  };

  const handleLoginSuccess = (profile: UserProfile) => {
    setUser(profile);
    setIsLoggedIn(true);
    localStorage.setItem('dokan_user_logged_in', 'true');
    localStorage.setItem('dokan_user_profile', JSON.stringify(profile));
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUser(null);
    setShopSettings(defaultShopSettings); // Reset shop settings on logout
    localStorage.removeItem('dokan_user_logged_in');
    localStorage.removeItem('dokan_user_profile');
    localStorage.removeItem('dokan_shop_settings'); // Also clear from local storage
    setCurrentView('TALLY');
    setIsSidebarOpen(false);
  };

  const handleNavigation = (view: ViewState) => {
    if (view === 'MENU') {
      setIsSidebarOpen(true);
    } else {
      setCurrentView(view);
    }
  };

  const renderView = () => {
    if (isSyncing) {
      return (
        <div className="flex-1 flex flex-col items-center justify-center p-10 text-center space-y-6">
          <div className="relative">
             <div className="w-20 h-20 border-4 border-red-50 border-t-red-600 rounded-full animate-spin"></div>
             <div className="absolute inset-0 flex items-center justify-center">
                <img src="https://www.google.com/favicon.ico" alt="g" className="w-6 h-6 animate-pulse" />
             </div>
          </div>
          <div>
            <h3 className="text-xl font-black text-gray-900 leading-tight">ড্রাইভ থেকে ডাটা লোড হচ্ছে...</h3>
            <p className="text-sm text-gray-400 font-bold mt-2 uppercase tracking-widest">দয়া করে অপেক্ষা করুন</p>
          </div>
        </div>
      );
    }

    switch (currentView) {
      case 'TALLY':
        return <TallyView contacts={contacts} saleRecords={salePurchaseRecords} onSelectContact={id => { setSelectedContactId(id); setCurrentView('CONTACT_DETAILS'); }} onAddContact={() => { setEditingContact(undefined); setCurrentView('ADD_CONTACT'); }} onNavigate={handleNavigation} />;
      case 'CASHBOX': return <CashboxView />;
      case 'ADD_CONTACT': return <AddContactForm onBack={() => setCurrentView(editingContact ? 'CONTACT_DETAILS' : 'TALLY')} onSave={addContact} editContact={editingContact} />;
      case 'CONTACT_DETAILS': return selectedContact ? <ContactDetails contact={selectedContact} onBack={() => setCurrentView('TALLY')} onAddTransaction={t => updateContactTransactions(selectedContact.id, t)} onDeleteContact={deleteContact} onEditContact={c => { setEditingContact(c); setCurrentView('ADD_CONTACT'); }} /> : null;
      case 'BECHA_KENA': return <BechaKenaView records={salePurchaseRecords} onBack={() => setCurrentView('TALLY')} onAddRecord={addSalePurchaseRecord} />;
      case 'CLOUD_BACKUP': return <CloudBackup data={{ contacts, salePurchaseRecords, stockItems, shopSettings }} onBack={() => setCurrentView('TALLY')} onLoginSuccess={handleLoginSuccess} onLogout={handleLogout} onRestore={handleRestoreData} currentLoggedInState={isLoggedIn} currentUserProfile={user} shopSettings={shopSettings} onUpdateShopSettings={setShopSettings} />;
      case 'AI_CHAT': return <AIChatView contacts={contacts} records={salePurchaseRecords} onBack={() => setCurrentView('TALLY')} persistedMessages={aiMessages} onMessagesUpdate={setAiMessages} onClearChat={() => setAiMessages([])} />;
      case 'STOCK': return <StockView items={stockItems} onBack={() => setCurrentView('TALLY')} onUpdateStock={handleUpdateStock} />;
      case 'SALE_ENTRY': return <SaleEntryView contacts={contacts} stockItems={stockItems} onBack={() => setCurrentView('TALLY')} onConfirmSale={handleConfirmSale} shopSettings={shopSettings} />;
      default: return <TallyView contacts={contacts} saleRecords={salePurchaseRecords} onSelectContact={() => {}} onAddContact={() => {}} onNavigate={handleNavigation} />;
    }
  };

  const headerPhoto = shopSettings.shopLogo || (isLoggedIn && user ? user.photo : null);

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen flex flex-col relative shadow-xl">
      <header className="bg-[#D32F2F] text-white px-4 py-3 sticky top-0 z-40 shadow-md">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer active:opacity-80 transition-opacity" onClick={() => setIsSidebarOpen(true)}>
            <div className="bg-white/20 p-1 rounded-md flex items-center gap-2">
              {headerPhoto ? <img src={headerPhoto} className="w-5 h-5 rounded-full border border-white/40 object-cover" alt="p" /> : <div className="w-5 h-5 rounded-full bg-white/20 flex items-center justify-center text-[10px] font-bold"><Store size={12} /></div>}
              <span className="text-sm font-bold truncate max-w-[120px]">{shopSettings.shopName || (isLoggedIn && user ? user.name.split(' ')[0] : 'অতিথি')}</span>
            </div>
            <ChevronDown size={16} />
          </div>
          <div className="flex items-center gap-4">
            <div onClick={() => setCurrentView('AI_CHAT')} className="flex flex-col items-center cursor-pointer"><Sparkles size={24} className="text-yellow-300" /><span className="text-[10px] mt-1 text-white font-bold">এআই</span></div>
            <div className="relative flex flex-col items-center cursor-pointer"><Bell size={24} /><span className="text-[10px] mt-1 text-white font-bold">ইনবক্স</span></div>
            <div onClick={handleHelpClick} className="flex flex-col items-center cursor-pointer"><HelpCircle size={24} /><span className="text-[10px] mt-1 text-white font-bold">হেল্প</span></div>
          </div>
        </div>
      </header>
      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} isLoggedIn={isLoggedIn} user={user} shopSettings={shopSettings} onNavigate={view => { setCurrentView(view); setIsSidebarOpen(false); }} onLogout={handleLogout} />
      <main className="flex-1 overflow-y-auto pb-20 bg-gray-50">{renderView()}</main>
      {['TALLY', 'CASHBOX', 'STOCK'].includes(currentView) || currentView === 'TALLY' ? (
        <Navigation currentView={currentView} onNavigate={handleNavigation} />
      ) : null}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  ArrowLeft, 
  CloudUpload, 
  CheckCircle2, 
  RefreshCw, 
  Database, 
  ShieldCheck, 
  LogOut, 
  Sparkles, 
  DownloadCloud, 
  Clock, 
  User, 
  X, 
  ShieldAlert, 
  Mail, 
  Lock, 
  ArrowRight, 
  UserPlus, 
  BellRing, 
  Store, 
  MapPin, 
  Camera, 
  Save,
  Phone
} from 'lucide-react';
import { ShopSettings } from '../types';

export interface UserProfile {
  name: string;
  email: string;
  id: string; 
  photo: string;
  provider: 'google';
}

interface CloudBackupProps {
  onBack: () => void;
  data: any;
  onLoginSuccess: (profile: UserProfile) => void;
  onLogout: () => void;
  onRestore: (data: any) => void;
  currentLoggedInState: boolean;
  currentUserProfile: UserProfile | null;
  shopSettings: ShopSettings;
  onUpdateShopSettings: (settings: ShopSettings) => void;
}

type AuthStage = 'CHOICE' | 'PICKER' | 'MANUAL_EMAIL' | 'VERIFY' | 'LOGGED_IN';

const CloudBackup: React.FC<CloudBackupProps> = ({ 
  onBack, 
  data, 
  onLoginSuccess, 
  onLogout, 
  onRestore,
  currentLoggedInState, 
  currentUserProfile,
  shopSettings,
  onUpdateShopSettings
}) => {
  const [stage, setStage] = useState<AuthStage>(currentLoggedInState ? 'LOGGED_IN' : 'CHOICE');
  const [selectedEmail, setSelectedEmail] = useState<string>('');
  const [manualEmail, setManualEmail] = useState<string>('');
  const [verificationCode, setVerificationCode] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [isRestoring, setIsRestoring] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showNotification, setShowNotification] = useState(false);
  const [lastSynced, setLastSynced] = useState<string | null>(() => localStorage.getItem('dokan_last_sync'));
  const [syncSuccess, setSyncSuccess] = useState(false);
  const [hasCloudBackup, setHasCloudBackup] = useState(false);

  // Local state for settings editing
  const [tempShopName, setTempShopName] = useState(shopSettings.shopName);
  const [tempShopAddress, setTempShopAddress] = useState(shopSettings.shopAddress);
  const [tempShopPhone, setTempShopPhone] = useState(shopSettings.shopPhone || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (currentLoggedInState) {
      setStage('LOGGED_IN');
      const backup = localStorage.getItem('dokan_google_drive_file');
      if (backup) setHasCloudBackup(true);
    } else {
      setStage('CHOICE');
    }
  }, [currentLoggedInState]);

  useEffect(() => {
    setTempShopName(shopSettings.shopName);
    setTempShopAddress(shopSettings.shopAddress);
    setTempShopPhone(shopSettings.shopPhone || '');
  }, [shopSettings]);

  const triggerSimulatedEmail = () => {
    setTimeout(() => {
      setShowNotification(true);
      setTimeout(() => setShowNotification(false), 8000);
    }, 500);
  };

  const handleOpenAccountPicker = () => {
    setIsLoading(true);
    setTimeout(() => {
      setStage('PICKER');
      setIsLoading(false);
    }, 800);
  };

  const handleSelectAccount = (email: string) => {
    setSelectedEmail(email);
    setIsLoading(true);
    setTimeout(() => {
      setStage('VERIFY');
      setIsLoading(false);
      triggerSimulatedEmail();
    }, 1200);
  };

  const handleManualEmailSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualEmail.toLowerCase().endsWith('@gmail.com')) {
      alert('অনুগ্রহ করে একটি সঠিক জিমেইল অ্যাড্রেস দিন।');
      return;
    }
    setSelectedEmail(manualEmail);
    setIsLoading(true);
    setTimeout(() => {
      setStage('VERIFY');
      setIsLoading(false);
      triggerSimulatedEmail();
    }, 1200);
  };

  const handleVerifyCode = (e: React.FormEvent) => {
    e.preventDefault();
    if (verificationCode !== '123456') {
      alert('ভুল কোড!');
      return;
    }

    setIsLoading(true);
    setTimeout(() => {
      const mockUser: UserProfile = {
        name: selectedEmail.split('@')[0].split('.').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' '),
        email: selectedEmail,
        id: selectedEmail,
        photo: `https://api.dicebear.com/7.x/avataaars/svg?seed=${selectedEmail}`,
        provider: 'google'
      };
      onLoginSuccess(mockUser);
      setStage('LOGGED_IN');
      setIsLoading(false);
      setShowNotification(false);
    }, 1500);
  };

  const handleSyncToDrive = () => {
    setIsSyncing(true);
    setSyncSuccess(false);
    setTimeout(() => {
      const now = new Date().toLocaleString('bn-BD');
      localStorage.setItem('dokan_google_drive_file', JSON.stringify(data));
      localStorage.setItem('dokan_last_sync', now);
      setLastSynced(now);
      setIsSyncing(false);
      setSyncSuccess(true);
      setHasCloudBackup(true);
      setTimeout(() => setSyncSuccess(false), 5000);
    }, 2000);
  };

  const handleLoadFromDrive = () => {
    setIsRestoring(true);
    const backup = localStorage.getItem('dokan_google_drive_file');
    setTimeout(() => {
      if (backup) {
        onRestore(JSON.parse(backup));
        setIsRestoring(false);
        alert('গুগল ড্রাইভ থেকে ডাটা সফলভাবে রিস্টোর হয়েছে।');
      } else {
        setIsRestoring(false);
        alert('কোনো ব্যাকআপ ফাইল পাওয়া যায়নি।');
      }
    }, 2000);
  };

  const handleSaveSettings = () => {
    onUpdateShopSettings({
      ...shopSettings,
      shopName: tempShopName,
      shopAddress: tempShopAddress,
      shopPhone: tempShopPhone
    });
    alert('সেটিংস সফলভাবে সেভ হয়েছে!');
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdateShopSettings({
          ...shopSettings,
          shopLogo: reader.result as string
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const renderNotification = () => (
    <div className={`fixed top-4 left-1/2 -translate-x-1/2 w-[90%] max-w-sm z-[110] transition-all duration-500 transform ${showNotification ? 'translate-y-0 opacity-100' : '-translate-y-20 opacity-0 pointer-events-none'}`}>
      <div className="bg-gray-900 text-white p-4 rounded-2xl shadow-2xl border border-gray-800 flex items-start gap-4">
        <div className="bg-red-600 p-2 rounded-xl shrink-0">
          <Mail size={20} className="text-white" />
        </div>
        <div className="flex-1">
          <div className="flex justify-between items-center mb-1">
            <span className="text-[10px] font-black text-red-400 uppercase tracking-widest">Google Security</span>
            <button onClick={() => setShowNotification(false)}><X size={14} className="text-gray-500" /></button>
          </div>
          <p className="text-xs font-bold leading-relaxed">ভেরিফিকেশন কোড: <span className="text-lg text-yellow-400 ml-1 tracking-[0.2em] font-black">123456</span></p>
        </div>
      </div>
    </div>
  );

  const renderChoiceScreen = () => (
    <div className="flex-1 p-8 flex flex-col items-center justify-center text-center animate-in fade-in duration-500">
      <div className="w-24 h-24 bg-red-50 rounded-[2.5rem] flex items-center justify-center shadow-2xl border border-red-100 mb-8 relative">
        <CloudUpload size={48} className="text-red-600" />
        <div className="absolute -top-1 -right-1 bg-blue-500 p-2 rounded-xl border-2 border-white shadow-lg">
          <ShieldCheck size={16} className="text-white" />
        </div>
      </div>
      <h3 className="text-2xl font-black text-gray-900 mb-3">ডাটা ব্যাকআপ ও সিকিউরিটি</h3>
      <p className="text-sm text-gray-500 mb-10 leading-relaxed font-medium">
        আপনার জিমেইল ভেরিফাই করে গুগল ড্রাইভে সব ডাটা সুরক্ষিত রাখুন। ফোন হারালেও ডাটা হারাবে না।
      </p>
      <button 
        onClick={handleOpenAccountPicker}
        disabled={isLoading}
        className="w-full py-4.5 bg-white border-2 border-gray-100 rounded-2xl flex items-center justify-center gap-4 shadow-sm active:scale-95 transition-all hover:bg-gray-50 hover:border-blue-200"
      >
        {isLoading ? <RefreshCw className="animate-spin text-blue-600" /> : <img src="https://www.google.com/favicon.ico" className="w-6 h-6" alt="g" />}
        <span className="font-black text-gray-700">Sign in with Google</span>
      </button>
    </div>
  );

  const renderPickerScreen = () => (
    <div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-6 backdrop-blur-sm">
      <div className="bg-white w-full max-w-sm rounded-[2.5rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <img src="https://www.google.com/favicon.ico" className="w-5 h-5" alt="g" />
            <span className="font-bold text-gray-800">অ্যাকাউন্ট বেছে নিন</span>
          </div>
          <button onClick={() => setStage('CHOICE')}><X size={20} className="text-gray-400" /></button>
        </div>
        <div className="p-3">
          {['test.user@gmail.com'].map((email, i) => (
            <button key={i} onClick={() => handleSelectAccount(email)} className="w-full flex items-center gap-4 p-4 hover:bg-gray-50 rounded-2xl text-left transition-colors border border-transparent hover:border-gray-100">
              <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center text-red-600 font-bold uppercase">{email[0]}</div>
              <div className="text-sm font-bold text-gray-900">{email}</div>
            </button>
          ))}
          <button onClick={() => setStage('MANUAL_EMAIL')} className="w-full flex items-center gap-4 p-4 hover:bg-red-50 rounded-2xl text-left transition-colors border border-transparent hover:border-red-100 mt-2 text-red-600">
            <div className="w-10 h-10 bg-white border-2 border-dashed border-red-200 rounded-full flex items-center justify-center"><UserPlus size={20} /></div>
            <div className="text-sm font-black">নতুন জিমেইল যোগ করুন</div>
          </button>
        </div>
      </div>
    </div>
  );

  const renderManualEmailScreen = () => (
    <div className="flex-1 p-8 animate-in fade-in duration-500">
      <button onClick={() => setStage('PICKER')} className="mb-8 text-gray-400 flex items-center gap-2 font-bold">
        <ArrowLeft size={20} /> ফিরে যান
