      amount: parseFloat(amount),
      description,
      date: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' }),
      isCash
    };
    onAddRecord(newRecord);
    setAmount('');
    setDescription('');
