                      {record.isCash ? 'নগদ' : 'বাকি'}
                    </span>
                  </div>
                  <p className="text-xs text-gray-400">{record.description || 'বিবরণ নেই'} • {record.date}</p>
                </div>
                <div className={`text-right font-black ${record.type === 'SALE' ? 'text-green-600' : 'text-red-600'}`}>
                  {record.type === 'SALE' ? '+' : '-'} {record.amount.toLocaleString('bn-BD')}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

