  X, 
  ShieldAlert, 
  Mail, 
  Lock, 
  ArrowRight, 
  UserPlus, 
  BellRing, 
  Store, 
  MapPin, 
  Camera, 
  Save,
  Phone
} from 'lucide-react';
import { ShopSettings } from '../types';

export interface UserProfile {
  name: string;
  email: string;
  id: string; 
  photo: string;
  provider: 'google';
}

interface CloudBackupProps {
  onBack: () => void;
  data: any;
  onLoginSuccess: (profile: UserProfile) => void;
  onLogout: () => void;
  onRestore: (data: any) => void;
  currentLoggedInState: boolean;
  currentUserProfile: UserProfile | null;
  shopSettings: ShopSettings;
  onUpdateShopSettings: (settings: ShopSettings) => void;
}

type AuthStage = 'CHOICE' | 'PICKER' | 'MANUAL_EMAIL' | 'VERIFY' | 'LOGGED_IN';

const CloudBackup: React.FC<CloudBackupProps> = ({ 
  onBack, 
  data, 
  onLoginSuccess, 
  onLogout, 
  onRestore,
  currentLoggedInState, 
  currentUserProfile,
  shopSettings,
  onUpdateShopSettings
}) => {
  const [stage, setStage] = useState<AuthStage>(currentLoggedInState ? 'LOGGED_IN' : 'CHOICE');
