  const triggerSimulatedEmail = () => {
    setTimeout(() => {
      setShowNotification(true);
      setTimeout(() => setShowNotification(false), 8000);
    }, 500);
  };

  const handleOpenAccountPicker = () => {
    setIsLoading(true);
