interface StockViewProps {
  items: StockItem[];
  onBack: () => void;
  onUpdateStock: (items: StockItem[]) => void;
}

const StockView: React.FC<StockViewProps> = ({ items, onBack, onUpdateStock }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<StockItem>>({});
  const [isAdding, setIsAdding] = useState(false);
  const [activeAction, setActiveAction] = useState<'NONE' | 'IMPORT' | 'SALE'>('NONE');
  const [selectedProductForAction, setSelectedProductForAction] = useState<StockItem | null>(null);
  const [actionQuantity, setActionQuantity] = useState('');

  const filteredItems = useMemo(() => {
    return items.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [items, searchTerm]);

  const totalBuyingValuation = useMemo(() => 
    items.reduce((acc, curr) => acc + (curr.quantity * curr.buyingPrice), 0),
    [items]
  );

  const totalSellingValuation = useMemo(() => 
    items.reduce((acc, curr) => acc + (curr.quantity * curr.sellingPrice), 0),
    [items]
  );

  const handleEditClick = (item: StockItem) => {
    setEditingId(item.id);
    setEditForm(item);
  };

  const handleSave = () => {
    if ((editingId || isAdding) && editForm.name) {
      if (isAdding) {
        const newItem: StockItem = {
          id: Date.now().toString(),
          name: editForm.name || '',
          quantity: editForm.quantity || 0,
          unit: editForm.unit || 'পিস',
          buyingPrice: editForm.buyingPrice || 0,
          sellingPrice: editForm.sellingPrice || 0,
          lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' })
        };
        onUpdateStock([...items, newItem]);
        setIsAdding(false);
      } else {
        const updated = items.map(item => 
          item.id === editingId 
            ? { ...item, ...editForm, lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' }) } 
            : item
        );
        onUpdateStock(updated);
        setEditingId(null);
      }
      setEditForm({});
    }
  };

  const handleStockAction = () => {
    if (!selectedProductForAction || !actionQuantity) return;
    const qty = parseFloat(actionQuantity);

    const updated = items.map(item => {
      if (item.id === selectedProductForAction.id) {
        const newQty = activeAction === 'IMPORT' ? item.quantity + qty : item.quantity - qty;
        if (newQty < 0 && activeAction === 'SALE') {
          alert('স্টকে পর্যাপ্ত পণ্য নেই!');
          return item;
        }
        return {
          ...item,
          quantity: newQty,
          lastUpdated: new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' })
        };
      }
      return item;
    });

    onUpdateStock(updated);
    setActiveAction('NONE');
    setSelectedProductForAction(null);
    setActionQuantity('');
  };

  const handleDelete = (id: string) => {
    if (confirm('পণ্যটি ডিলিট করতে চান?')) {
      onUpdateStock(items.filter(item => item.id !== id));
    }
  };

  const inputClasses = "w-full p-4 bg-white border-2 border-gray-300 rounded-2xl outline-none text-gray-900 font-bold focus:border-red-600 focus:ring-4 focus:ring-red-50 transition-all shadow-sm text-lg placeholder:text-gray-400";

  return (
    <div className="bg-gray-50 min-h-full flex flex-col pb-24">
      {/* Dynamic Header */}
      <header className="p-5 bg-gradient-to-br from-red-700 to-red-800 text-white rounded-b-[2.5rem] shadow-lg">
        <div className="flex items-center gap-4 mb-6">
          <button onClick={onBack} className="p-2 bg-white/10 rounded-full active:scale-90 transition-transform"><ArrowLeft size={24} /></button>
          <h2 className="text-2xl font-black">স্টক ইনভেন্টরি</h2>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="bg-white/15 backdrop-blur-md p-4 rounded-3xl border border-white/20">
            <div className="flex items-center gap-2 mb-1">
               <Layers size={14} className="text-red-200" />
               <span className="text-[10px] font-black uppercase tracking-widest text-red-100">স্টক ভ্যালু (কেনা)</span>
            </div>
            <div className="text-2xl font-black">৳{totalBuyingValuation.toLocaleString('bn-BD')}</div>
          </div>
          <div className="bg-white/15 backdrop-blur-md p-4 rounded-3xl border border-white/20">
            <div className="flex items-center gap-2 mb-1">
               <TrendingUp size={14} className="text-yellow-200" />
               <span className="text-[10px] font-black uppercase tracking-widest text-yellow-100">সম্ভাব্য লাভ</span>
            </div>
            <div className="text-2xl font-black text-yellow-300">৳{(totalSellingValuation - totalBuyingValuation).toLocaleString('bn-BD')}</div>
          </div>
        </div>
      </header>

      {/* Main Action Bar */}
      <div className="px-5 -mt-8 mb-4">
        <div className="grid grid-cols-3 gap-3">
           <button onClick={() => setIsAdding(true)} className="bg-white shadow-xl p-4 rounded-3xl flex flex-col items-center gap-2 border-2 border-red-50 active:scale-95 transition-all">
             <div className="w-12 h-12 bg-red-50 rounded-2xl flex items-center justify-center">
               <Plus size={24} className="text-red-600" />
             </div>
             <span className="text-xs font-black text-gray-700">নতুন পণ্য</span>
           </button>
           <button onClick={() => setActiveAction('IMPORT')} className="bg-white shadow-xl p-4 rounded-3xl flex flex-col items-center gap-2 border-2 border-green-50 active:scale-95 transition-all">
             <div className="w-12 h-12 bg-green-50 rounded-2xl flex items-center justify-center">
               <ArrowDownLeft size={24} className="text-green-600" />
             </div>
             <span className="text-xs font-black text-gray-700">স্টক ইন</span>
           </button>
           <button onClick={() => setActiveAction('SALE')} className="bg-white shadow-xl p-4 rounded-3xl flex flex-col items-center gap-2 border-2 border-blue-50 active:scale-95 transition-all">
             <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center">
               <ArrowUpRight size={24} className="text-blue-600" />
             </div>
             <span className="text-xs font-black text-gray-700">স্টক আউট</span>
           </button>
        </div>
      </div>

      {/* Search Bar */}
      <div className="px-5 mb-4">
        <div className="relative group">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-red-600 transition-colors" size={20} />
          <input 
            type="text" 
            placeholder="পণ্যের নাম দিয়ে খুঁজুন..." 
            value={searchTerm} 
            onChange={(e) => setSearchTerm(e.target.value)} 
            className="w-full bg-white border-2 border-gray-200 rounded-[2rem] pl-12 pr-4 py-4 text-base font-bold shadow-sm focus:border-red-600 focus:ring-4 focus:ring-red-50 outline-none transition-all" 
          />
        </div>
      </div>

      {/* List Container */}
      <div className="flex-1 px-5 space-y-4">
        {isAdding && (
          <div className="bg-white p-6 rounded-[2.5rem] border-2 border-red-600 space-y-5 shadow-2xl animate-in zoom-in-95 duration-200">
             <div className="flex justify-between items-center mb-2">
                <h3 className="font-black text-lg text-gray-900">নতুন পণ্য যোগ করুন</h3>
                <button onClick={() => setIsAdding(false)} className="p-2 bg-gray-100 rounded-full text-gray-400"><X size={18} /></button>
             </div>
             <div className="space-y-4">
                <div className="relative">
                  <Tag className="absolute left-4 top-4 text-gray-400" size={18} />
                  <input className={inputClasses} placeholder="পণ্যের নাম" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} autoFocus />
                </div>
                <div className="grid grid-cols-2 gap-3">
                   <input type="number" className={inputClasses} placeholder="পরিমাণ" value={editForm.quantity || ''} onChange={e => setEditForm({...editForm, quantity: parseFloat(e.target.value)})} />
                   <input className={inputClasses} placeholder="একক (যেমন: পিস)" value={editForm.unit || ''} onChange={e => setEditForm({...editForm, unit: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-3">
                   <input type="number" className={inputClasses} placeholder="কেনা মূল্য" value={editForm.buyingPrice || ''} onChange={e => setEditForm({...editForm, buyingPrice: parseFloat(e.target.value)})} />
                   <input type="number" className={inputClasses} placeholder="বিক্রি মূল্য" value={editForm.sellingPrice || ''} onChange={e => setEditForm({...editForm, sellingPrice: parseFloat(e.target.value)})} />
                </div>
                <button onClick={handleSave} className="w-full bg-red-600 text-white p-5 rounded-2xl font-black text-lg shadow-xl shadow-red-100 active:scale-95 transition-all">
                  পণ্য সেভ করুন
                </button>
             </div>
          </div>
        )}

        {filteredItems.length === 0 && !isAdding && (
          <div className="py-20 text-center opacity-30">
            <Package size={64} className="mx-auto mb-4 text-gray-300" />
            <p className="font-black text-gray-400 uppercase tracking-widest">স্টক খালি</p>
          </div>
        )}

        {filteredItems.map(item => (
          <div key={item.id} className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm flex items-center justify-between group hover:border-red-200 hover:shadow-md transition-all">
            <div className="flex items-center gap-4">
               <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-xl transition-colors ${item.quantity <= 5 ? 'bg-red-50 text-red-600' : 'bg-gray-50 text-gray-400'}`}>
                  {item.name[0]}
               </div>
               <div>
                  <h4 className="font-black text-gray-900 leading-tight">{item.name}</h4>
                  <div className="flex items-center gap-2 mt-1">
                    <span className={`text-xs font-black px-2 py-0.5 rounded-full ${item.quantity <= 5 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                      {item.quantity} {item.unit}
                    </span>
                    {item.quantity <= 5 && <AlertCircle size={14} className="text-red-500 animate-pulse" />}
                  </div>
               </div>
            </div>
            <div className="text-right">
               <div className="text-sm font-black text-gray-900 mb-2">৳{item.sellingPrice.toLocaleString('bn-BD')}</div>
               <div className="flex gap-2 justify-end">
                  <button onClick={() => handleEditClick(item)} className="p-2.5 bg-gray-50 text-blue-600 rounded-xl hover:bg-blue-50 active:scale-90 transition-all"><Edit2 size={16} /></button>
                  <button onClick={() => handleDelete(item.id)} className="p-2.5 bg-gray-50 text-red-600 rounded-xl hover:bg-red-50 active:scale-90 transition-all"><Trash2 size={16} /></button>
               </div>
            </div>
          </div>
        ))}
      </div>

      {/* Action Modal for Stock In / Stock Out */}
      {(activeAction !== 'NONE') && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-end justify-center backdrop-blur-sm transition-all">
          <div className="bg-white w-full max-w-md rounded-t-[3rem] p-8 animate-in slide-in-from-bottom duration-300 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <div className="flex items-center gap-3">
                 <div className={`p-3 rounded-2xl ${activeAction === 'IMPORT' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                    {activeAction === 'IMPORT' ? <PlusCircle size={28} /> : <MinusCircle size={28} />}
                 </div>
                 <h3 className="text-2xl font-black text-gray-900">
                    {activeAction === 'IMPORT' ? 'স্টক ক্রয় (ইন)' : 'স্টক বিক্রি (আউট)'}
                 </h3>
              </div>
              <button onClick={() => { setActiveAction('NONE'); setSelectedProductForAction(null); setActionQuantity(''); }} className="p-3 bg-gray-100 rounded-full text-gray-500 hover:bg-gray-200 transition-colors">
                 <X size={20} />
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2 mb-2 block">পণ্য নির্বাচন করুন</label>
                <div className="grid grid-cols-2 gap-3 max-h-48 overflow-y-auto p-1 no-scrollbar">
                  {items.map(item => (
                    <button 
                      key={item.id} 
                      onClick={() => setSelectedProductForAction(item)} 
                      className={`p-4 rounded-2xl border-2 text-left transition-all ${selectedProductForAction?.id === item.id ? 'border-red-600 bg-red-50' : 'border-gray-100 bg-gray-50'}`}
                    >
                      <div className="text-sm font-black text-gray-800 truncate">{item.name}</div>
                      <div className="text-[10px] font-bold text-gray-400 mt-1">বর্তমান: {item.quantity} {item.unit}</div>
                    </button>
                  ))}
                </div>
              </div>

              {selectedProductForAction && (
                <div className="animate-in fade-in slide-in-from-top-4 duration-300">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2 mb-2 block">কতটুকু {activeAction === 'IMPORT' ? 'যোগ' : 'বিয়োগ'} করবেন?</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={actionQuantity} 
                      onChange={(e) => setActionQuantity(e.target.value)} 
                      placeholder="0.00" 
                      className={`${inputClasses} text-3xl font-black text-center border-red-200 py-6`} 
                      autoFocus 
                    />
                    <div className="absolute right-6 top-1/2 -translate-y-1/2 font-black text-gray-300 text-lg uppercase">{selectedProductForAction.unit}</div>
                  </div>
                  <button 
                    onClick={handleStockAction} 
                    disabled={!actionQuantity}
                    className={`w-full mt-8 py-5 rounded-[2rem] font-black text-xl text-white shadow-2xl active:scale-95 transition-all ${activeAction === 'IMPORT' ? 'bg-green-600 shadow-green-100' : 'bg-red-600 shadow-red-100'} ${!actionQuantity ? 'opacity-50 grayscale' : ''}`}
                  >
                    নিশ্চিত করুন
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Edit Modal (Simple overlay for editing name/prices) */}
      {editingId && (
        <div className="fixed inset-0 bg-black/70 z-[100] flex items-center justify-center p-6 backdrop-blur-sm">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-xl font-black text-gray-900 mb-6 flex items-center gap-2">
                 <Edit2 size={20} className="text-blue-600" /> তথ্য এডিট করুন
              </h3>
              <div className="space-y-4">
                 <input className={inputClasses} placeholder="নাম" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} />
                 <div className="grid grid-cols-2 gap-3">
                   <input type="number" className={inputClasses} placeholder="কেনা" value={editForm.buyingPrice || ''} onChange={e => setEditForm({...editForm, buyingPrice: parseFloat(e.target.value)})} />
                   <input type="number" className={inputClasses} placeholder="বিক্রি" value={editForm.sellingPrice || ''} onChange={e => setEditForm({...editForm, sellingPrice: parseFloat(e.target.value)})} />
                 </div>
                 <div className="flex gap-3 pt-4">
                    <button onClick={() => setEditingId(null)} className="flex-1 p-4 bg-gray-100 text-gray-600 rounded-2xl font-black active:scale-95">বাতিল</button>
                    <button onClick={handleSave} className="flex-1 p-4 bg-blue-600 text-white rounded-2xl font-black active:scale-95 shadow-lg shadow-blue-100">আপডেট</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default StockView;

export enum ContactType {
  CUSTOMER = 'CUSTOMER',
  SUPPLIER = 'SUPPLIER'
}

export interface Transaction {
  id: string;
  type: 'DUE_GIVEN' | 'RECEIVED';
  amount: number;
  description: string;
  date: string;
}

export interface Contact {
  id: string;
  name: string;
  phone: string;
  type: ContactType;
  balance: number; // Positive means receivable (from customer), Negative means payable (to supplier)
  lastActivity: string;
  transactions: Transaction[];
}

export interface SalePurchaseRecord {
  id: string;
  type: 'SALE' | 'PURCHASE';
  amount: number;
  description: string;
  date: string;
  isCash: boolean;
  customerName?: string;
  customerPhone?: string;
  customerAddress?: string;
  items?: { productId: string; name: string; quantity: number; price: number }[];
}

export interface StockItem {
  id: string;
  name: string;
  serialNumber?: string;
  quantity: number;
  unit: string;
  buyingPrice: number;
  sellingPrice: number;
  lastUpdated: string;
}

export interface StockTransaction {
  id: string;
  itemId: string;
  itemName: string;
  type: 'IN' | 'OUT';
  quantity: number;
  price: number;
  date: string;
  partyName: string; // Supplier for IN, Customer for OUT
}

export interface ShopSettings {
  shopName: string;
  shopAddress: string;
  shopPhone?: string;
  shopLogo?: string;
}

export type ViewState = 'TALLY' | 'CASHBOX' | 'WALLET' | 'MENU' | 'ADD_CONTACT' | 'CONTACT_DETAILS' | 'BECHA_KENA' | 'CLOUD_BACKUP' | 'AI_CHAT' | 'AI_RECOMMENDATIONS' | 'STOCK' | 'SALE_ENTRY';

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, 
  Wallet, 
  Menu, 
  BookOpen, 
  Search, 
  UserPlus, 
  Plus, 
  Minus, 
  ArrowLeft, 
  MoreVertical, 
  Calendar, 
  Camera, 
  ChevronRight,
  Filter,
  Download,
  Package,
  FileText,
  Bell,
  HelpCircle,
  QrCode,
  CloudUpload,
  MessageSquare,
  ChevronDown,
  Sparkles,
  Store
} from 'lucide-react';
import { Contact, ContactType, ViewState, Transaction, SalePurchaseRecord, StockItem, StockTransaction, ShopSettings } from './types';
import TallyView from './components/TallyView';
import CashboxView from './components/CashboxView';
import AddContactForm from './components/AddContactForm';
import ContactDetails from './components/ContactDetails';
import Navigation from './components/Navigation';
import Sidebar from './components/Sidebar';
import BechaKenaView from './components/BechaKenaView';
import CloudBackup, { UserProfile } from './components/CloudBackup';
import AIChatView, { Message } from './components/AIChatView';
import SmartRecommendationsView from './components/SmartRecommendationsView';
import StockView from './components/StockView';
import SaleEntryView from './components/SaleEntryView';

const HELP_WHATSAPP_URL = 'https://wa.me/8801797464478';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('TALLY');
  const [isSyncing, setIsSyncing] = useState(false);

  const defaultShopSettings: ShopSettings = { shopName: 'গেস্ট', shopAddress: '', shopPhone: '' };

  const [shopSettings, setShopSettings] = useState<ShopSettings>(() => {
    const saved = localStorage.getItem('dokan_shop_settings');
    return saved ? JSON.parse(saved) : defaultShopSettings;
  });

  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(() => {
    return localStorage.getItem('dokan_user_logged_in') === 'true';
  });
  const [user, setUser] = useState<UserProfile | null>(() => {
    const savedUser = localStorage.getItem('dokan_user_profile');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  const [contacts, setContacts] = useState<Contact[]>(() => {
    const saved = localStorage.getItem('dokan_contacts');
    return saved ? JSON.parse(saved) : [];
  });

  const [salePurchaseRecords, setSalePurchaseRecords] = useState<SalePurchaseRecord[]>(() => {
    const saved = localStorage.getItem('dokan_becha_kena');
    return saved ? JSON.parse(saved) : [];
  });

  const [stockItems, setStockItems] = useState<StockItem[]>(() => {
    const saved = localStorage.getItem('dokan_stock');
    return saved ? JSON.parse(saved) : [];
  });

  const [stockTransactions, setStockTransactions] = useState<StockTransaction[]>(() => {
    const saved = localStorage.getItem('dokan_stock_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [aiMessages, setAiMessages] = useState<Message[]>([
    { 
      role: 'ai', 
      text: 'আসসালামু আলাইকুম! আমি আপনার দোকানের এআই অ্যাসিস্ট্যান্ট।' 
    }
  ]);

  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingContact, setEditingContact] = useState<Contact | undefined>(undefined);

  useEffect(() => {
    localStorage.setItem('dokan_contacts', JSON.stringify(contacts));
  }, [contacts]);

  useEffect(() => {
    localStorage.setItem('dokan_becha_kena', JSON.stringify(salePurchaseRecords));
  }, [salePurchaseRecords]);

  useEffect(() => {
    localStorage.setItem('dokan_stock', JSON.stringify(stockItems));
    localStorage.setItem('dokan_stock_transactions', JSON.stringify(stockTransactions));
  }, [stockItems, stockTransactions]);

  useEffect(() => {
    localStorage.setItem('dokan_shop_settings', JSON.stringify(shopSettings));
  }, [shopSettings]);

  const handleRestoreData = (restoredData: any) => {
    setIsSyncing(true);
    setTimeout(() => {
      if (restoredData.contacts) setContacts(restoredData.contacts);
      if (restoredData.salePurchaseRecords) setSalePurchaseRecords(restoredData.salePurchaseRecords);
      if (restoredData.stockItems) setStockItems(restoredData.stockItems);
      if (restoredData.stockTransactions) setStockTransactions(restoredData.stockTransactions);
      if (restoredData.shopSettings) setShopSettings(restoredData.shopSettings);
      setIsSyncing(false);
      setCurrentView('TALLY');
    }, 2000);
  };

  const addContact = (updatedContact: Contact) => {
    const exists = contacts.find(c => c.id === updatedContact.id);
    if (exists) {
      setContacts(prev => prev.map(c => c.id === updatedContact.id ? updatedContact : c));
    } else {
      setContacts(prev => [...prev, updatedContact]);
    }
    setEditingContact(undefined);
    setCurrentView('TALLY');
  };

  const deleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
    setCurrentView('TALLY');
  };

  const addSalePurchaseRecord = (record: SalePurchaseRecord) => {
    setSalePurchaseRecords(prev => [...prev, record]);
  };

  const updateContactTransactions = (contactId: string, transaction: Transaction) => {
    setContacts(prev => prev.map(c => {
      if (c.id === contactId) {
        const newBalance = transaction.type === 'DUE_GIVEN' 
          ? c.balance + transaction.amount 
          : c.balance - transaction.amount;
        return {
          ...c,
          balance: newBalance,
          lastActivity: 'এখনই',
          transactions: [transaction, ...c.transactions]
        };
      }
      return c;
    }));
  };

  const handleUpdateStock = (updatedItems: StockItem[], updatedTransactions: StockTransaction[]) => {
    setStockItems(updatedItems);
    setStockTransactions(updatedTransactions);
  };

  const handleConfirmSale = (saleData: { 
    contactId: string; 
    customerName: string;
    customerPhone: string;
    customerAddress: string;
    items: { productId: string; name: string; quantity: number; price: number }[]; 
    total: number; 
    isCash: boolean;
  }): SalePurchaseRecord => {
    const date = new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });

    const updatedStock = stockItems.map(p => {
      const soldItem = saleData.items.find(si => si.productId === p.id);
      if (soldItem) {
        return { ...p, quantity: p.quantity - soldItem.quantity };
      }
      return p;
    });
    setStockItems(updatedStock);

    const record: SalePurchaseRecord = {
      id: Date.now().toString(),
      type: 'SALE',
      amount: saleData.total,
      description: saleData.items.map(i => `${i.name} (${i.quantity})`).join(', '),
      date,
      isCash: saleData.isCash,
      customerName: saleData.customerName,
      customerPhone: saleData.customerPhone,
      customerAddress: saleData.customerAddress,
      items: saleData.items
    };
    setSalePurchaseRecords(prev => [...prev, record]);

    if (!saleData.isCash && saleData.contactId !== 'CASH_CUSTOMER' && saleData.contactId !== '') {
      const transaction: Transaction = {
        id: (Date.now() + 1).toString(),
        type: 'DUE_GIVEN',
        amount: saleData.total,
        description: `বিক্রি: ${record.description}`,
        date
      };
      updateContactTransactions(saleData.contactId, transaction);
    } else if (!saleData.isCash && (saleData.contactId === 'CASH_CUSTOMER' || saleData.contactId === '')) {
       const newContactId = Date.now().toString();
       const newContact: Contact = {
          id: newContactId,
          name: saleData.customerName,
          phone: saleData.customerPhone,
          type: ContactType.CUSTOMER,
          balance: saleData.total,
          lastActivity: 'এখনই',
          transactions: [{
            id: (Date.now() + 2).toString(),
            type: 'DUE_GIVEN',
            amount: saleData.total,
            description: `বিক্রি: ${record.description}`,
            date
          }]
       };
       setContacts(prev => [...prev, newContact]);
    }

    return record;
  };

  const selectedContact = useMemo(() => 
    contacts.find(c => c.id === selectedContactId), 
    [contacts, selectedContactId]
  );

  const handleHelpClick = () => {
    window.open(HELP_WHATSAPP_URL, '_blank');
  };

  const handleLoginSuccess = (profile: UserProfile) => {
    setUser(profile);
    setIsLoggedIn(true);
    localStorage.setItem('dokan_user_logged_in', 'true');
    localStorage.setItem('dokan_user_profile', JSON.stringify(profile));
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUser(null);
    setShopSettings(defaultShopSettings); 
    localStorage.removeItem('dokan_user_logged_in');
    localStorage.removeItem('dokan_user_profile');
    localStorage.removeItem('dokan_shop_settings'); 
    setCurrentView('TALLY');
    setIsSidebarOpen(false);
  };

  const handleNavigation = (view: ViewState) => {
    if (view === 'MENU') {
      setIsSidebarOpen(true);
    } else {
      setCurrentView(view);
    }
  };

  const renderView = () => {
    if (isSyncing) {
      return (
        <div className="flex-1 flex flex-col items-center justify-center p-10 text-center space-y-6">
          <div className="relative">
             <div className="w-20 h-20 border-4 border-red-50 border-t-red-600 rounded-full animate-spin"></div>
             <div className="absolute inset-0 flex items-center justify-center">
                <img src="https://www.google.com/favicon.ico" alt="g" className="w-6 h-6 animate-pulse" />
             </div>
          </div>
          <div>
            <h3 className="text-xl font-black text-gray-900 leading-tight">ড্রাইভ থেকে ডাটা লোড হচ্ছে...</h3>
            <p className="text-sm text-gray-400 font-bold mt-2 uppercase tracking-widest">দয়া করে অপেক্ষা করুন</p>
          </div>
        </div>
      );
    }

    switch (currentView) {
      case 'TALLY':
        return <TallyView contacts={contacts} saleRecords={salePurchaseRecords} onSelectContact={id => { setSelectedContactId(id); setCurrentView('CONTACT_DETAILS'); }} onAddContact={() => { setEditingContact(undefined); setCurrentView('ADD_CONTACT'); }} onNavigate={handleNavigation} />;
      case 'CASHBOX': return <CashboxView />;
      case 'ADD_CONTACT': return <AddContactForm onBack={() => setCurrentView(editingContact ? 'CONTACT_DETAILS' : 'TALLY')} onSave={addContact} editContact={editingContact} />;
      case 'CONTACT_DETAILS': return selectedContact ? <ContactDetails contact={selectedContact} onBack={() => setCurrentView('TALLY')} onAddTransaction={t => updateContactTransactions(selectedContact.id, t)} onDeleteContact={deleteContact} onEditContact={c => { setEditingContact(c); setCurrentView('ADD_CONTACT'); }} /> : null;
      case 'BECHA_KENA': return <BechaKenaView records={salePurchaseRecords} onBack={() => setCurrentView('TALLY')} onAddRecord={addSalePurchaseRecord} />;
      case 'CLOUD_BACKUP': return <CloudBackup data={{ contacts, salePurchaseRecords, stockItems, shopSettings, stockTransactions }} onBack={() => setCurrentView('TALLY')} onLoginSuccess={handleLoginSuccess} onLogout={handleLogout} onRestore={handleRestoreData} currentLoggedInState={isLoggedIn} currentUserProfile={user} shopSettings={shopSettings} onUpdateShopSettings={setShopSettings} />;
      case 'AI_CHAT': return <AIChatView contacts={contacts} records={salePurchaseRecords} onBack={() => setCurrentView('TALLY')} persistedMessages={aiMessages} onMessagesUpdate={setAiMessages} onClearChat={() => setAiMessages([])} />;
      case 'STOCK': return <StockView items={stockItems} transactions={stockTransactions} onBack={() => setCurrentView('TALLY')} onUpdateStock={handleUpdateStock} />;
      case 'SALE_ENTRY': return <SaleEntryView contacts={contacts} stockItems={stockItems} onBack={() => setCurrentView('TALLY')} onConfirmSale={handleConfirmSale} shopSettings={shopSettings} />;
      default: return <TallyView contacts={contacts} saleRecords={salePurchaseRecords} onSelectContact={() => {}} onAddContact={() => {}} onNavigate={handleNavigation} />;
    }
  };

  const displayShopName = isLoggedIn && shopSettings.shopName !== 'গেস্ট' ? shopSettings.shopName : 'গেস্ট';
  const headerPhoto = isLoggedIn ? (shopSettings.shopLogo || (user ? user.photo : null)) : null;

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen flex flex-col relative shadow-xl">
      <header className="bg-[#D32F2F] text-white px-4 py-3 sticky top-0 z-40 shadow-md">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer active:opacity-80 transition-opacity" onClick={() => setIsSidebarOpen(true)}>
            <div className="bg-white/20 p-1 rounded-md flex items-center gap-2">
              {headerPhoto ? <img src={headerPhoto} className="w-5 h-5 rounded-full border border-white/40 object-cover" alt="p" /> : <div className="w-5 h-5 rounded-full bg-white/20 flex items-center justify-center text-[10px] font-bold"><Store size={12} /></div>}
              <span className="text-sm font-bold truncate max-w-[120px]">{displayShopName}</span>
            </div>
            <ChevronDown size={16} />
          </div>
          <div className="flex items-center gap-4">
            <div onClick={() => setCurrentView('AI_CHAT')} className="flex flex-col items-center cursor-pointer"><Sparkles size={24} className="text-yellow-300" /><span className="text-[10px] mt-1 text-white font-bold">এআই</span></div>
            <div className="relative flex flex-col items-center cursor-pointer"><Bell size={24} /><span className="text-[10px] mt-1 text-white font-bold">ইনবক্স</span></div>
            <div onClick={handleHelpClick} className="flex flex-col items-center cursor-pointer"><HelpCircle size={24} /><span className="text-[10px] mt-1 text-white font-bold">হেল্প</span></div>
          </div>
        </div>
      </header>
      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} isLoggedIn={isLoggedIn} user={user} shopSettings={shopSettings} onNavigate={view => { setCurrentView(view); setIsSidebarOpen(false); }} onLogout={handleLogout} />
      <main className="flex-1 overflow-y-auto pb-20 bg-gray-50">{renderView()}</main>
      {['TALLY', 'CASHBOX', 'STOCK'].includes(currentView) || currentView === 'TALLY' ? (
        <Navigation currentView={currentView} onNavigate={handleNavigation} />
      ) : null}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  ArrowLeft, 
  Search, 
  Plus, 
  Edit2, 
  Save, 
  Trash2, 
  Package, 
  TrendingUp, 
  X, 
  ShoppingCart,
  PlusCircle,
  MinusCircle,
  AlertCircle,
  Layers,
  Tag,
  ArrowDownLeft,
  ArrowUpRight,
  Eye,
  EyeOff,
  History,
  ChevronDown,
  User,
  Truck
} from 'lucide-react';
import { StockItem, StockTransaction } from '../types';

interface StockViewProps {
  items: StockItem[];
  transactions: StockTransaction[];
  onBack: () => void;
  onUpdateStock: (items: StockItem[], transactions: StockTransaction[]) => void;
}

const StockView: React.FC<StockViewProps> = ({ items, transactions, onBack, onUpdateStock }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<StockItem>>({});
  const [isAdding, setIsAdding] = useState(false);
  const [activeAction, setActiveAction] = useState<'NONE' | 'IMPORT' | 'SALE'>('NONE');
  const [showHistory, setShowHistory] = useState(false);
  const [showPriceMap, setShowPriceMap] = useState<Record<string, boolean>>({});

  const [selectedProductForAction, setSelectedProductForAction] = useState<StockItem | null>(null);
  const [actionQuantity, setActionQuantity] = useState('');
  const [partyName, setPartyName] = useState('');
  const [actionSearchTerm, setActionSearchTerm] = useState('');
  const [showActionDropdown, setShowActionDropdown] = useState(false);

  const actionDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (actionDropdownRef.current && !actionDropdownRef.current.contains(event.target as Node)) {
        setShowActionDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const filteredItems = useMemo(() => {
    return items.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      (item.serialNumber && item.serialNumber.toLowerCase().includes(searchTerm.toLowerCase()))
    );
  }, [items, searchTerm]);

  const filteredActionItems = useMemo(() => {
    return items.filter(item => 
      item.name.toLowerCase().includes(actionSearchTerm.toLowerCase())
    );
  }, [items, actionSearchTerm]);

  const totalBuyingValuation = useMemo(() => 
    items.reduce((acc, curr) => acc + (curr.quantity * curr.buyingPrice), 0),
    [items]
  );

  const totalSellingValuation = useMemo(() => 
    items.reduce((acc, curr) => acc + (curr.quantity * curr.sellingPrice), 0),
    [items]
  );

  const togglePriceVisibility = (id: string) => {
    setShowPriceMap(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const handleEditClick = (item: StockItem) => {
    setEditingId(item.id);
    setEditForm(item);
  };

  const handleSave = () => {
    if ((editingId || isAdding) && editForm.name) {
      const today = new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });
      if (isAdding) {
        const newItem: StockItem = {
          id: Date.now().toString(),
          name: editForm.name || '',
          serialNumber: editForm.serialNumber || '',
          quantity: editForm.quantity || 0,
          unit: editForm.unit || 'পিস',
          buyingPrice: editForm.buyingPrice || 0,
          sellingPrice: editForm.sellingPrice || 0,
          lastUpdated: today
        };
        onUpdateStock([...items, newItem], transactions);
        setIsAdding(false);
      } else {
        const updated = items.map(item => 
          item.id === editingId 
            ? { ...item, ...editForm, lastUpdated: today } 
            : item
        );
        onUpdateStock(updated, transactions);
        setEditingId(null);
      }
      setEditForm({});
    }
  };

  const handleStockAction = () => {
    if (!selectedProductForAction || !actionQuantity || !partyName) {
      alert('সব তথ্য সঠিকভাবে দিন!');
      return;
    }
    const qty = parseFloat(actionQuantity);
    const today = new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });

    let updatedItems = items.map(item => {
      if (item.id === selectedProductForAction.id) {
        const newQty = activeAction === 'IMPORT' ? item.quantity + qty : item.quantity - qty;
        if (newQty < 0 && activeAction === 'SALE') {
          alert('স্টকে পর্যাপ্ত পণ্য নেই!');
          return item;
        }
        return { ...item, quantity: newQty, lastUpdated: today };
      }
      return item;
    });

    const newTransaction: StockTransaction = {
      id: Date.now().toString(),
      itemId: selectedProductForAction.id,
      itemName: selectedProductForAction.name,
      type: activeAction === 'IMPORT' ? 'IN' : 'OUT',
      quantity: qty,
      price: activeAction === 'IMPORT' ? selectedProductForAction.buyingPrice : selectedProductForAction.sellingPrice,
      date: today,
      partyName
    };

    onUpdateStock(updatedItems, [newTransaction, ...transactions]);
    resetActionStates();
  };

  const deleteTransaction = (id: string) => {
    if (confirm('হিস্টোরি থেকে ডিলিট করতে চান? (এটি স্টক এডজাস্ট করবে না)')) {
      onUpdateStock(items, transactions.filter(t => t.id !== id));
    }
  };

  const resetActionStates = () => {
    setActiveAction('NONE');
    setSelectedProductForAction(null);
    setActionQuantity('');
    setPartyName('');
    setActionSearchTerm('');
    setShowActionDropdown(false);
  };

  const handleDeleteItem = (id: string) => {
    if (confirm('পণ্যটি সম্পূর্ণ ডিলিট করতে চান?')) {
      onUpdateStock(items.filter(item => item.id !== id), transactions);
    }
  };

  const inputClasses = "w-full p-4 bg-white border-2 border-gray-300 rounded-2xl outline-none text-gray-900 font-bold focus:border-red-600 focus:ring-4 focus:ring-red-50 transition-all shadow-sm text-lg placeholder:text-gray-400";

  return (
    <div className="bg-gray-50 min-h-full flex flex-col pb-24 animate-in fade-in duration-300">
      {/* Header with Stock Valuation */}
      <header className="p-5 bg-gradient-to-br from-red-700 to-red-800 text-white rounded-b-[2.5rem] shadow-lg sticky top-0 z-20">
        <div className="flex items-center gap-4 mb-6">
          <button onClick={onBack} className="p-2 bg-white/10 rounded-full active:scale-90 transition-transform"><ArrowLeft size={24} /></button>
          <h2 className="text-2xl font-black">স্টক ইনভেন্টরি</h2>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div onClick={() => setShowHistory(true)} className="bg-white/15 backdrop-blur-md p-4 rounded-3xl border border-white/20 active:scale-95 transition-all cursor-pointer">
            <div className="flex items-center gap-2 mb-1">
               <Layers size={14} className="text-red-200" />
               <span className="text-[10px] font-black uppercase tracking-widest text-red-100">স্টক ভ্যালু (কেনা)</span>
            </div>
            <div className="text-2xl font-black">৳{totalBuyingValuation.toLocaleString('bn-BD')}</div>
            <div className="text-[9px] font-bold text-red-100/50 mt-1 uppercase tracking-tighter">হিস্টোরি দেখতে ক্লিক করুন</div>
          </div>
          <div className="bg-white/15 backdrop-blur-md p-4 rounded-3xl border border-white/20">
            <div className="flex items-center gap-2 mb-1">
               <TrendingUp size={14} className="text-yellow-200" />
               <span className="text-[10px] font-black uppercase tracking-widest text-yellow-100">সম্ভাব্য লাভ</span>
            </div>
            <div className="text-2xl font-black text-yellow-300">৳{(totalSellingValuation - totalBuyingValuation).toLocaleString('bn-BD')}</div>
          </div>
        </div>
      </header>

      {/* Action Bar */}
      <div className="px-5 -mt-8 mb-4">
        <div className="grid grid-cols-3 gap-3">
           <button onClick={() => setIsAdding(true)} className="bg-white shadow-xl p-4 rounded-3xl flex flex-col items-center gap-2 border-2 border-red-50 active:scale-95 transition-all">
             <div className="w-12 h-12 bg-red-50 rounded-2xl flex items-center justify-center">
               <Plus size={24} className="text-red-600" />
             </div>
             <span className="text-xs font-black text-gray-700">নতুন পণ্য</span>
           </button>
           <button onClick={() => setActiveAction('IMPORT')} className="bg-white shadow-xl p-4 rounded-3xl flex flex-col items-center gap-2 border-2 border-green-50 active:scale-95 transition-all">
             <div className="w-12 h-12 bg-green-50 rounded-2xl flex items-center justify-center">
               <ArrowDownLeft size={24} className="text-green-600" />
             </div>
             <span className="text-xs font-black text-gray-700">স্টক ইন</span>
           </button>
           <button onClick={() => setActiveAction('SALE')} className="bg-white shadow-xl p-4 rounded-3xl flex flex-col items-center gap-2 border-2 border-blue-50 active:scale-95 transition-all">
             <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center">
               <ArrowUpRight size={24} className="text-blue-600" />
             </div>
             <span className="text-xs font-black text-gray-700">স্টক আউট</span>
           </button>
        </div>
      </div>

      {/* Search Filter */}
      <div className="px-5 mb-4">
        <div className="relative group">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-red-600 transition-colors" size={20} />
          <input 
            type="text" 
            placeholder="নাম বা সিরিয়াল দিয়ে খুঁজুন..." 
            value={searchTerm} 
            onChange={(e) => setSearchTerm(e.target.value)} 
            className="w-full bg-white border-2 border-gray-200 rounded-[2rem] pl-12 pr-4 py-4 text-base font-bold shadow-sm focus:border-red-600 focus:ring-4 focus:ring-red-50 outline-none transition-all" 
          />
        </div>
      </div>

      {/* Product List */}
      <div className="flex-1 px-5 space-y-4">
        {isAdding && (
          <div className="bg-white p-6 rounded-[2.5rem] border-2 border-red-600 space-y-5 shadow-2xl animate-in zoom-in-95 duration-200">
             <div className="flex justify-between items-center mb-2">
                <h3 className="font-black text-lg text-gray-900 uppercase">নতুন পণ্য যোগ</h3>
                <button onClick={() => setIsAdding(false)} className="p-2 bg-gray-100 rounded-full text-gray-400"><X size={18} /></button>
             </div>
             <div className="space-y-4">
                <div className="relative">
                   <Tag className="absolute left-4 top-4 text-gray-400" size={18} />
                   <input className={inputClasses} placeholder="পণ্যের নাম" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} autoFocus />
                </div>
                <div className="relative">
                   <span className="absolute left-4 top-4 text-xs font-black text-gray-400">#</span>
                   <input className={`${inputClasses} pl-10`} placeholder="সিরিয়াল নাম্বার (ঐচ্ছিক)" value={editForm.serialNumber || ''} onChange={e => setEditForm({...editForm, serialNumber: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-3">
                   <input type="number" className={inputClasses} placeholder="পরিমাণ" value={editForm.quantity || ''} onChange={e => setEditForm({...editForm, quantity: parseFloat(e.target.value)})} />
                   <input className={inputClasses} placeholder="একক (যেমন: পিস)" value={editForm.unit || ''} onChange={e => setEditForm({...editForm, unit: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-3">
                   <input type="number" className={inputClasses} placeholder="কেনা মূল্য" value={editForm.buyingPrice || ''} onChange={e => setEditForm({...editForm, buyingPrice: parseFloat(e.target.value)})} />
                   <input type="number" className={inputClasses} placeholder="বিক্রি মূল্য" value={editForm.sellingPrice || ''} onChange={e => setEditForm({...editForm, sellingPrice: parseFloat(e.target.value)})} />
                </div>
                <button onClick={handleSave} className="w-full bg-red-600 text-white p-5 rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all">
                  পণ্য সেভ করুন
                </button>
             </div>
          </div>
        )}

        {filteredItems.map(item => (
          <div key={item.id} className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm flex items-center justify-between group">
            <div className="flex items-center gap-4">
               <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-xl bg-gray-50 text-gray-400`}>
                  {item.name[0]}
               </div>
               <div className="max-w-[150px]">
                  <h4 className="font-black text-gray-900 leading-tight truncate">{item.name}</h4>
                  <div className="flex flex-col gap-1 mt-1">
                    <span className="text-[10px] font-bold text-gray-400">{item.serialNumber ? `S/N: ${item.serialNumber}` : 'সিরিয়াল নেই'}</span>
                    <span className={`text-[10px] font-black px-2 py-0.5 rounded-full w-fit ${item.quantity <= 5 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                      {item.quantity} {item.unit} স্টকে
                    </span>
                  </div>
               </div>
            </div>
            <div className="text-right">
               <div className="flex items-center justify-end gap-2 mb-2">
                 <div className="flex flex-col items-end">
                    <div className="text-xs font-black text-gray-900">৳{item.sellingPrice}</div>
                    <div className="flex items-center gap-1 text-[9px] font-bold text-gray-400">
                      কেনা: {showPriceMap[item.id] ? `৳${item.buyingPrice}` : '***'}
                      <button onClick={() => togglePriceVisibility(item.id)} className="ml-1 text-red-600">
                        {showPriceMap[item.id] ? <EyeOff size={10} /> : <Eye size={10} />}
                      </button>
                    </div>
                 </div>
               </div>
               <div className="flex gap-2 justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => handleEditClick(item)} className="p-2 bg-gray-50 text-blue-600 rounded-xl"><Edit2 size={14} /></button>
                  <button onClick={() => handleDeleteItem(item.id)} className="p-2 bg-gray-50 text-red-600 rounded-xl"><Trash2 size={14} /></button>
               </div>
            </div>
          </div>
        ))}
      </div>

      {/* Action Modal (Stock In / Out) */}
      {(activeAction !== 'NONE') && (
        <div className="fixed inset-0 bg-black/80 z-[100] flex items-end justify-center backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-t-[3rem] p-8 animate-in slide-in-from-bottom duration-300 shadow-2xl overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
               <div className="flex items-center gap-3">
                  <div className={`p-3 rounded-2xl ${activeAction === 'IMPORT' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                     {activeAction === 'IMPORT' ? <ArrowDownLeft size={28} /> : <ArrowUpRight size={28} />}
                  </div>
                  <h3 className="text-2xl font-black text-gray-900">
                     {activeAction === 'IMPORT' ? 'স্টক ইন (পার্সেস)' : 'স্টক আউট (সেল)'}
                  </h3>
               </div>
               <button onClick={resetActionStates} className="p-2 bg-gray-100 rounded-full text-gray-400"><X size={20} /></button>
            </div>

            <div className="space-y-6" ref={actionDropdownRef}>
               {/* Search Box for Product Selection */}
               <div className="relative">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2 mb-2 block">পণ্য খুঁজুন ও সিলেক্ট করুন</label>
                  <div className="relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                    <input 
                      type="text" 
                      placeholder="পণ্য টাইপ করুন..." 
                      value={selectedProductForAction ? selectedProductForAction.name : actionSearchTerm}
                      onChange={(e) => {
                        setActionSearchTerm(e.target.value);
                        setShowActionDropdown(true);
                        if (selectedProductForAction) setSelectedProductForAction(null);
                      }}
                      onFocus={() => setShowActionDropdown(true)}
                      className={inputClasses + " pl-12"}
                    />
                    {selectedProductForAction && <button onClick={() => setSelectedProductForAction(null)} className="absolute right-4 top-1/2 -translate-y-1/2 text-red-600"><X size={18} /></button>}
                  </div>

                  {showActionDropdown && !selectedProductForAction && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white border border-gray-100 rounded-2xl shadow-2xl z-50 max-h-48 overflow-y-auto no-scrollbar">
                       {filteredActionItems.map(item => (
                         <button key={item.id} onClick={() => { setSelectedProductForAction(item); setShowActionDropdown(false); }} className="w-full text-left p-4 hover:bg-red-50 flex items-center justify-between border-b border-gray-50 last:border-0">
