                          </div>
                       </div>
                    </div>

                    <div>
                      <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2 mb-2 block">
                        {activeAction === 'IMPORT' ? 'সাপ্লায়ারের নাম' : 'কাস্টমারের নাম'}
                      </label>
                      <div className="relative">
                        {activeAction === 'IMPORT' ? <Truck className="absolute left-4 top-4 text-gray-400" size={18} /> : <User className="absolute left-4 top-4 text-gray-400" size={18} />}
                        <input type="text" placeholder="নাম লিখুন..." value={partyName} onChange={(e) => setPartyName(e.target.value)} className={inputClasses + " pl-12"} />
                      </div>
