                    <button onClick={handleStockAction} className="w-full py-5 rounded-[2rem] font-black text-xl text-white shadow-2xl active:scale-95 transition-all bg-red-600 shadow-red-100">
                      নিশ্চিত করুন
                    </button>
                 </div>
               )}
            </div>
          </div>
        </div>
      )}

      {/* History Modal */}
      {showHistory && (
        <div className="fixed inset-0 bg-black/80 z-[100] flex flex-col items-center justify-center p-4 backdrop-blur-md">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-6 shadow-2xl h-[80vh] flex flex-col">
              <div className="flex justify-between items-center mb-6 px-2">
                 <div className="flex items-center gap-2">
                    <History size={20} className="text-[#D32F2F]" />
                    <h3 className="text-xl font-black text-gray-900">পার্সেস ও সেল হিস্টোরি</h3>
                 </div>
                 <button onClick={() => setShowHistory(false)} className="p-2 bg-gray-100 rounded-full"><X size={20} /></button>
              </div>

              <div className="flex-1 overflow-y-auto space-y-3 no-scrollbar pr-1">
                 {transactions.length === 0 ? (
                   <div className="text-center py-20 opacity-30">
                      <History size={48} className="mx-auto mb-2" />
                      <p className="font-bold">কোনো হিস্টোরি নেই</p>
                   </div>
                 ) : (
                   transactions.map(t => (
                    <div key={t.id} className="p-4 bg-gray-50 rounded-2xl border border-gray-100 relative group">
                       <div className="flex justify-between items-start mb-2">
                          <span className={`text-[9px] font-black px-2 py-0.5 rounded-full ${t.type === 'IN' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                             {t.type === 'IN' ? 'পার্সেস' : 'বিক্রি'}
                          </span>
                          <span className="text-[9px] font-bold text-gray-400 uppercase">{t.date}</span>
                       </div>
                       <div className="font-black text-gray-800 text-sm mb-1">{t.itemName}</div>
                       <div className="flex justify-between items-end">
                          <div className="text-[10px] text-gray-500 font-bold">
                             {t.type === 'IN' ? 'সাপ্লায়ার: ' : 'কাস্টমার: '} <span className="text-gray-900">{t.partyName}</span>
                          </div>
                          <div className="text-right">
                             <div className="text-xs font-black text-gray-900">{t.quantity} × ৳{t.price}</div>
                             <div className={`text-sm font-black ${t.type === 'IN' ? 'text-red-600' : 'text-green-600'}`}>৳{(t.quantity * t.price).toLocaleString('bn-BD')}</div>
                          </div>
                       </div>
                       <button onClick={() => deleteTransaction(t.id)} className="absolute -top-2 -right-2 p-1.5 bg-white shadow-md rounded-full text-red-600 opacity-0 group-hover:opacity-100 transition-opacity">
                          <Trash2 size={12} />
                       </button>
                    </div>
                   ))
                 )}
              </div>
           </div>
        </div>
      )}

      {/* Product Edit Modal */}
      {editingId && (
        <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center p-6 backdrop-blur-sm">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-xl font-black text-gray-900 mb-6 flex items-center gap-2">
                 <Edit2 size={20} className="text-blue-600" /> তথ্য এডিট
              </h3>
              <div className="space-y-4">
                 <input className={inputClasses} placeholder="পণ্যের নাম" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} />
                 <input className={inputClasses} placeholder="সিরিয়াল নাম্বার" value={editForm.serialNumber || ''} onChange={e => setEditForm({...editForm, serialNumber: e.target.value})} />
                 <div className="grid grid-cols-2 gap-3">
                   <input type="number" className={inputClasses} placeholder="কেনা মূল্য" value={editForm.buyingPrice || ''} onChange={e => setEditForm({...editForm, buyingPrice: parseFloat(e.target.value)})} />
                   <input type="number" className={inputClasses} placeholder="বিক্রি মূল্য" value={editForm.sellingPrice || ''} onChange={e => setEditForm({...editForm, sellingPrice: parseFloat(e.target.value)})} />
                 </div>
                 <div className="flex gap-3 pt-4">
                    <button onClick={() => setEditingId(null)} className="flex-1 p-4 bg-gray-100 text-gray-600 rounded-2xl font-black active:scale-95">বাতিল</button>
                    <button onClick={handleSave} className="flex-1 p-4 bg-blue-600 text-white rounded-2xl font-black active:scale-95 shadow-lg">আপডেট</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

