  const [editForm, setEditForm] = useState<Partial<StockItem>>({});
  const [isAdding, setIsAdding] = useState(false);
  const [activeAction, setActiveAction] = useState<'NONE' | 'IMPORT' | 'SALE'>('NONE');
  const [showHistory, setShowHistory] = useState(false);
  const [showPriceMap, setShowPriceMap] = useState<Record<string, boolean>>({});
  const [showSupplierDetail, setShowSupplierDetail] = useState<string | null>(null); // Stores supplier name

  const [selectedProductForAction, setSelectedProductForAction] = useState<StockItem | null>(null);
  const [actionQuantity, setActionQuantity] = useState('');
  const [partyName, setPartyName] = useState('');
  const [actionSearchTerm, setActionSearchTerm] = useState('');
  const [showActionDropdown, setShowActionDropdown] = useState(false);
  const [showPartyDropdown, setShowPartyDropdown] = useState(false);

  const actionDropdownRef = useRef<HTMLDivElement>(null);
  const partyDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (actionDropdownRef.current && !actionDropdownRef.current.contains(event.target as Node)) {
        setShowActionDropdown(false);
      }
      if (partyDropdownRef.current && !partyDropdownRef.current.contains(event.target as Node)) {
        setShowPartyDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const filteredItems = useMemo(() => {
    return items.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      (item.serialNumber && item.serialNumber.toLowerCase().includes(searchTerm.toLowerCase()))
    );
  }, [items, searchTerm]);

  const filteredActionItems = useMemo(() => {
    return items.filter(item => 
      item.name.toLowerCase().includes(actionSearchTerm.toLowerCase())
    );
  }, [items, actionSearchTerm]);

  const filteredSuppliers = useMemo(() => {
    return contacts.filter(c => 
      c.type === ContactType.SUPPLIER && 
      c.name.toLowerCase().includes(partyName.toLowerCase())
    );
  }, [contacts, partyName]);

  const totalBuyingValuation = useMemo(() => 
    items.reduce((acc, curr) => acc + (curr.quantity * curr.buyingPrice), 0),
    [items]
  );

  const totalSellingValuation = useMemo(() => 
    items.reduce((acc, curr) => acc + (curr.quantity * curr.sellingPrice), 0),
    [items]
  );

  const togglePriceVisibility = (id: string) => {
    setShowPriceMap(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const handleEditClick = (item: StockItem) => {
    setEditingId(item.id);
    setEditForm(item);
  };

  const handleSave = () => {
    if ((editingId || isAdding) && editForm.name) {
      const today = new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });
      if (isAdding) {
        const newItem: StockItem = {
          id: Date.now().toString(),
          name: editForm.name || '',
          serialNumber: editForm.serialNumber || '',
          quantity: editForm.quantity || 0,
          unit: editForm.unit || 'পিস',
          buyingPrice: editForm.buyingPrice || 0,
          sellingPrice: editForm.sellingPrice || 0,
          lastUpdated: today
        };
        onUpdateStock([...items, newItem], transactions);
        setIsAdding(false);
      } else {
        const updated = items.map(item => 
          item.id === editingId 
            ? { ...item, ...editForm, lastUpdated: today } 
            : item
        );
        onUpdateStock(updated, transactions);
        setEditingId(null);
      }
      setEditForm({});
    }
  };

  const handleStockAction = () => {
    if (!selectedProductForAction || !actionQuantity || !partyName) {
      alert('সব তথ্য সঠিকভাবে দিন!');
      return;
    }
    const qty = parseFloat(actionQuantity);
    const today = new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });

    let updatedItems = items.map(item => {
      if (item.id === selectedProductForAction.id) {
        const newQty = activeAction === 'IMPORT' ? item.quantity + qty : item.quantity - qty;
        if (newQty < 0 && activeAction === 'SALE') {
          alert('স্টকে পর্যাপ্ত পণ্য নেই!');
          return item;
        }
        return { ...item, quantity: newQty, lastUpdated: today };
      }
      return item;
    });

    const newTransaction: StockTransaction = {
      id: Date.now().toString(),
      itemId: selectedProductForAction.id,
      itemName: selectedProductForAction.name,
      type: activeAction === 'IMPORT' ? 'IN' : 'OUT',
      quantity: qty,
      price: activeAction === 'IMPORT' ? selectedProductForAction.buyingPrice : selectedProductForAction.sellingPrice,
      date: today,
      partyName
    };

    onUpdateStock(updatedItems, [newTransaction, ...transactions]);
    resetActionStates();
  };

  const deleteTransaction = (id: string) => {
    if (confirm('হিস্টোরি থেকে ডিলিট করতে চান? (এটি স্টক এডজাস্ট করবে না)')) {
      onUpdateStock(items, transactions.filter(t => t.id !== id));
    }
  };

  const resetActionStates = () => {
    setActiveAction('NONE');
    setSelectedProductForAction(null);
    setActionQuantity('');
    setPartyName('');
    setActionSearchTerm('');
    setShowActionDropdown(false);
    setShowPartyDropdown(false);
  };

  const handleDeleteItem = (id: string) => {
    if (confirm('পণ্যটি সম্পূর্ণ ডিলিট করতে চান?')) {
      onUpdateStock(items.filter(item => item.id !== id), transactions);
    }
  };

  const getSupplierOfItem = (itemId: string) => {
    const lastInTx = transactions.find(t => t.itemId === itemId && t.type === 'IN');
    return lastInTx ? lastInTx.partyName : 'অজানা সাপ্লায়ার';
  };

  const inputClasses = "w-full p-4 bg-white border-2 border-gray-300 rounded-2xl outline-none text-gray-900 font-bold focus:border-red-600 focus:ring-4 focus:ring-red-50 transition-all shadow-sm text-lg placeholder:text-gray-400";

  return (
    <div className="bg-gray-50 min-h-full flex flex-col pb-24 animate-in fade-in duration-300">
      {/* COMPACT HEADER */}
      <header className="p-4 bg-gradient-to-br from-red-700 to-red-800 text-white rounded-b-[2rem] shadow-md sticky top-0 z-20">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <button onClick={onBack} className="p-1.5 bg-white/10 rounded-full active:scale-90 transition-transform"><ArrowLeft size={20} /></button>
            <h2 className="text-lg font-black tracking-tight">স্টক ইনভেন্টরি</h2>
          </div>
          <button onClick={() => setShowHistory(true)} className="p-2 bg-white/10 rounded-xl text-xs font-bold flex items-center gap-2">
            <History size={16} /> হিস্টোরি
          </button>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div className="bg-white/15 p-2 px-3 rounded-2xl border border-white/10">
            <span className="text-[8px] font-black uppercase text-red-100/70 block">স্টক ভ্যালু</span>
            <div className="text-base font-black">৳{totalBuyingValuation.toLocaleString('bn-BD')}</div>
          </div>
          <div className="bg-white/15 p-2 px-3 rounded-2xl border border-white/10 text-right">
            <span className="text-[8px] font-black uppercase text-yellow-100/70 block">সম্ভাব্য লাভ</span>
            <div className="text-base font-black text-yellow-300">৳{(totalSellingValuation - totalBuyingValuation).toLocaleString('bn-BD')}</div>
          </div>
        </div>
      </header>

      {/* QUICK ACTIONS */}
      <div className="px-4 -mt-6 mb-4">
        <div className="grid grid-cols-3 gap-2">
           <button onClick={() => setIsAdding(true)} className="bg-white shadow-md p-3 rounded-2xl flex flex-col items-center gap-1 border border-gray-100 active:scale-95 transition-all">
             <Plus size={20} className="text-red-600" />
             <span className="text-[9px] font-black text-gray-600 uppercase">নতুন পণ্য</span>
           </button>
           <button onClick={() => setActiveAction('IMPORT')} className="bg-white shadow-md p-3 rounded-2xl flex flex-col items-center gap-1 border border-gray-100 active:scale-95 transition-all">
             <ArrowDownLeft size={20} className="text-green-600" />
             <span className="text-[9px] font-black text-gray-600 uppercase">স্টক ইন</span>
           </button>
           <button onClick={() => setActiveAction('SALE')} className="bg-white shadow-md p-3 rounded-2xl flex flex-col items-center gap-1 border border-gray-100 active:scale-95 transition-all">
             <ArrowUpRight size={20} className="text-blue-600" />
             <span className="text-[9px] font-black text-gray-600 uppercase">স্টক আউট</span>
           </button>
        </div>
      </div>

      {/* SEARCH BAR */}
      <div className="px-4 mb-3">
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" 
            placeholder="নাম বা সিরিয়াল দিয়ে খুঁজুন..." 
            value={searchTerm} 
            onChange={(e) => setSearchTerm(e.target.value)} 
            className="w-full bg-white border-2 border-gray-200 rounded-2xl pl-11 pr-4 py-3.5 text-sm font-bold shadow-sm focus:border-red-600 outline-none transition-all" 
          />
        </div>
      </div>

      {/* LARGER PRODUCT LIST */}
      <div className="flex-1 px-4 space-y-2 pb-10">
        {filteredItems.map(item => (
          <div key={item.id} className="bg-white p-3 px-4 rounded-2xl border border-gray-100 shadow-sm flex items-center justify-between group active:bg-gray-50">
            <div className="flex items-center gap-3">
               <div className="w-10 h-10 rounded-xl bg-gray-50 flex items-center justify-center font-black text-gray-400 text-sm">
                  {item.name[0]}
               </div>
               <div className="max-w-[120px]">
                  <h4 className="font-black text-gray-900 text-sm leading-tight truncate">{item.name}</h4>
                  <div className="flex items-center gap-1.5 mt-0.5">
                    <span className={`text-[9px] font-black px-1.5 py-0.5 rounded ${item.quantity <= 5 ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-700'}`}>
                      {item.quantity} {item.unit}
                    </span>
                    {item.serialNumber && <span className="text-[8px] font-bold text-gray-400"># {item.serialNumber}</span>}
                  </div>
               </div>
            </div>
            <div className="text-right">
               <div className="flex flex-col items-end">
                  <div className="text-sm font-black text-gray-900">৳{item.sellingPrice}</div>
                  <div className="flex items-center gap-1 text-[8px] font-bold text-gray-400">
                    কেনা: {showPriceMap[item.id] ? `৳${item.buyingPrice}` : '***'}
                    <button onClick={() => togglePriceVisibility(item.id)} className="ml-1 text-red-600">
                      {showPriceMap[item.id] ? <EyeOff size={10} /> : <Eye size={10} />}
                    </button>
                  </div>
                  {showPriceMap[item.id] && (
                    <button 
                      onClick={() => setShowSupplierDetail(getSupplierOfItem(item.id))}
                      className="text-[8px] font-black text-blue-600 mt-0.5 uppercase tracking-tighter hover:underline"
                    >
                      সাপ্লায়ার: {getSupplierOfItem(item.id)}
                    </button>
                  )}
               </div>
               <div className="flex gap-2 justify-end mt-1 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => handleEditClick(item)} className="p-1.5 text-blue-600"><Edit2 size={12} /></button>
                  <button onClick={() => handleDeleteItem(item.id)} className="p-1.5 text-red-600"><Trash2 size={12} /></button>
               </div>
            </div>
          </div>
        ))}
      </div>

      {/* EXPANDED ACTION MODAL (STOCK IN / OUT) */}
      {(activeAction !== 'NONE') && (
        <div className="fixed inset-0 bg-black/90 z-[100] flex items-center justify-center backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 animate-in zoom-in-95 duration-300 shadow-2xl relative">
            <button onClick={resetActionStates} className="absolute top-6 right-6 p-2 bg-gray-100 rounded-full text-gray-500 hover:bg-gray-200 transition-colors">
               <X size={24} />
            </button>

            <div className="flex items-center gap-4 mb-8">
               <div className={`p-4 rounded-3xl ${activeAction === 'IMPORT' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                  {activeAction === 'IMPORT' ? <ArrowDownLeft size={32} /> : <ArrowUpRight size={32} />}
               </div>
               <div>
                  <h3 className="text-2xl font-black text-gray-900">
                     {activeAction === 'IMPORT' ? 'স্টক ক্রয় (ইন)' : 'স্টক বিক্রি (আউট)'}
                  </h3>
                  <p className="text-xs text-gray-400 font-bold">নিচের তথ্যগুলো সঠিকভাবে পূরণ করুন</p>
               </div>
            </div>

            <div className="space-y-6">
               {/* Product Selection */}
               <div className="relative" ref={actionDropdownRef}>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">পণ্য সিলেক্ট করুন</label>
                  <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input 
                      type="text" 
                      placeholder="পণ্যের নাম টাইপ করুন..." 
                      value={selectedProductForAction ? selectedProductForAction.name : actionSearchTerm}
                      onChange={(e) => {
                        setActionSearchTerm(e.target.value);
                        setShowActionDropdown(true);
                        if (selectedProductForAction) setSelectedProductForAction(null);
                      }}
                      onFocus={() => setShowActionDropdown(true)}
                      className={inputClasses + " pl-12 text-base"}
                    />
                    {selectedProductForAction && <button onClick={() => setSelectedProductForAction(null)} className="absolute right-4 top-1/2 -translate-y-1/2 text-red-600"><X size={20} /></button>}
                  </div>

                  {showActionDropdown && !selectedProductForAction && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white border-2 border-gray-100 rounded-2xl shadow-2xl z-50 max-h-56 overflow-y-auto no-scrollbar ring-8 ring-black/5">
                       {filteredActionItems.map(item => (
                         <button key={item.id} onClick={() => { setSelectedProductForAction(item); setShowActionDropdown(false); }} className="w-full text-left p-4 hover:bg-red-50 flex items-center justify-between border-b border-gray-50 last:border-0 transition-colors">
                           <div>
                              <div className="font-black text-gray-800 text-base">{item.name}</div>
                              <div className="text-[10px] font-bold text-gray-400">বর্তমান স্টক: {item.quantity} {item.unit}</div>
                           </div>
                           <ArrowRight size={16} className="text-gray-300" />
                         </button>
                       ))}
                       {filteredActionItems.length === 0 && <div className="p-6 text-center text-sm text-gray-400 italic">পণ্য খুঁজে পাওয়া যায়নি</div>}
                    </div>
                  )}
               </div>

               {selectedProductForAction && (
                 <div className="space-y-6 animate-in slide-in-from-top-4 duration-300">
                    <div className="grid grid-cols-2 gap-4">
                       <div>
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">পরিমাণ ({selectedProductForAction.unit})</label>
                          <input type="number" value={actionQuantity} onChange={(e) => setActionQuantity(e.target.value)} placeholder="0.00" className={inputClasses + " text-2xl"} autoFocus />
                       </div>
                       <div>
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">দাম (একক)</label>
                          <div className={inputClasses + " bg-gray-50 border-gray-100 flex items-center text-gray-500"}>
                             ৳{activeAction === 'IMPORT' ? selectedProductForAction.buyingPrice : selectedProductForAction.sellingPrice}
                          </div>
                       </div>
                    </div>

                    {/* PARTY NAME (With Autocomplete) */}
                    <div className="relative" ref={partyDropdownRef}>
                      <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">
                        {activeAction === 'IMPORT' ? 'সাপ্লায়ারের নাম' : 'কাস্টমারের নাম'}
                      </label>
                      <div className="relative">
                        {activeAction === 'IMPORT' ? <Truck className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} /> : <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />}
                        <input 
                          type="text" 
                          placeholder="নাম টাইপ করুন..." 
                          value={partyName} 
                          onChange={(e) => {
                            setPartyName(e.target.value);
                            setShowPartyDropdown(true);
                          }}
                          onFocus={() => setShowPartyDropdown(true)}
                          className={inputClasses + " pl-12 text-base"} 
                        />
                      </div>

                      {showPartyDropdown && partyName && activeAction === 'IMPORT' && (
                        <div className="absolute top-full left-0 right-0 mt-2 bg-white border-2 border-gray-100 rounded-2xl shadow-2xl z-50 max-h-40 overflow-y-auto no-scrollbar ring-8 ring-black/5">
                           {filteredSuppliers.map(s => (
                             <button key={s.id} onClick={() => { setPartyName(s.name); setShowPartyDropdown(false); }} className="w-full text-left p-3 px-4 hover:bg-blue-50 flex items-center gap-3 border-b border-gray-50 last:border-0 transition-colors">
                                <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold text-xs">{s.name[0]}</div>
                                <div>
                                   <div className="font-black text-gray-800 text-sm">{s.name}</div>
                                   <div className="text-[9px] font-bold text-gray-400">ব্যালেন্স: ৳{Math.abs(s.balance)}</div>
                                </div>
                             </button>
                           ))}
                           {filteredSuppliers.length === 0 && (
                             <div className="p-4 text-center text-[10px] text-gray-400 italic">নতুন নাম হিসেবে সেভ হবে</div>
                           )}
                        </div>
                      )}
                    </div>

                    <button onClick={handleStockAction} className="w-full py-5 rounded-[2rem] font-black text-xl text-white shadow-2xl active:scale-95 transition-all bg-red-600 shadow-red-100 hover:bg-red-700">
                      ট্রানজেকশন নিশ্চিত করুন
                    </button>
                 </div>
               )}
            </div>
          </div>
        </div>
      )}

      {/* SUPPLIER QUICK VIEW MODAL */}
      {showSupplierDetail && (
        <div className="fixed inset-0 bg-black/80 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-6 shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[85vh]">
              <div className="flex justify-between items-start mb-6">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-3xl bg-blue-50 flex items-center justify-center text-blue-600">
                       <Truck size={32} />
                    </div>
                    <div>
                       <h3 className="text-xl font-black text-gray-900">{showSupplierDetail}</h3>
                       <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">সাপ্লায়ার প্রোফাইল</p>
                    </div>
                 </div>
                 <button onClick={() => setShowSupplierDetail(null)} className="p-2 bg-gray-50 rounded-full text-gray-400"><X size={20} /></button>
              </div>

              {/* SUPPLIER BALANCE (from contacts) */}
              <div className="bg-blue-600 text-white p-5 rounded-3xl shadow-xl shadow-blue-100 mb-6">
                 <div className="text-[10px] font-black uppercase tracking-widest opacity-70 mb-1">মোট পাওনা (আপনার কাছে)</div>
                 <div className="text-3xl font-black">
                   ৳{Math.abs(contacts.find(c => c.name === showSupplierDetail)?.balance || 0).toLocaleString('bn-BD')}
                 </div>
                 <div className="mt-4 flex items-center gap-2 text-xs font-bold opacity-80 bg-white/10 p-2 rounded-xl">
                    <Phone size={12} /> {contacts.find(c => c.name === showSupplierDetail)?.phone || 'ফোন নেই'}
                 </div>
              </div>

              {/* SUPPLIED ITEMS LIST */}
              <div className="flex-1 overflow-y-auto no-scrollbar space-y-3">
                 <div className="flex items-center gap-2 px-1 mb-2">
                    <Briefcase size={16} className="text-blue-600" />
                    <span className="text-xs font-black text-gray-400 uppercase tracking-widest">সরবরাহকৃত পণ্যসমূহ</span>
                 </div>

                 {transactions.filter(t => t.partyName === showSupplierDetail && t.type === 'IN').length === 0 ? (
                    <div className="text-center py-10 text-xs text-gray-300 italic">কোনো রেকর্ড পাওয়া যায়নি</div>
                 ) : (
                    transactions.filter(t => t.partyName === showSupplierDetail && t.type === 'IN').map(t => (
                      <div key={t.id} className="p-3 bg-gray-50 rounded-2xl border border-gray-100 flex justify-between items-center">
                         <div>
                            <div className="text-sm font-black text-gray-800">{t.itemName}</div>
                            <div className="text-[9px] font-bold text-gray-400 uppercase">{t.date}</div>
                         </div>
                         <div className="text-right">
                            <div className="text-xs font-black text-gray-900">{t.quantity} × ৳{t.price}</div>
                            <div className="text-[10px] font-bold text-blue-600">৳{(t.quantity * t.price).toLocaleString('bn-BD')}</div>
                         </div>
                      </div>
                    ))
                 )}
              </div>
           </div>
        </div>
      )}

      {/* HISTORY MODAL (Modified for better scrolling) */}
      {showHistory && (
        <div className="fixed inset-0 bg-black/80 z-[100] flex flex-col items-center justify-center p-4 backdrop-blur-md">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-6 shadow-2xl h-[85vh] flex flex-col">
              <div className="flex justify-between items-center mb-6 px-2">
                 <div className="flex items-center gap-2">
                    <div className="p-2 bg-red-100 rounded-lg text-red-600"><History size={20} /></div>
                    <h3 className="text-xl font-black text-gray-900">পার্সেস ও সেল হিস্টোরি</h3>
                 </div>
                 <button onClick={() => setShowHistory(false)} className="p-2 bg-gray-100 rounded-full"><X size={20} /></button>
              </div>

              <div className="flex-1 overflow-y-auto space-y-3 no-scrollbar pr-1">
                 {transactions.length === 0 ? (
                   <div className="text-center py-20 opacity-30">
                      <History size={48} className="mx-auto mb-2" />
                      <p className="font-bold">কোনো হিস্টোরি নেই</p>
                   </div>
                 ) : (
                   transactions.map(t => (
                    <div key={t.id} className="p-4 bg-gray-50 rounded-2xl border border-gray-100 relative group active:bg-red-50 transition-colors">
                       <div className="flex justify-between items-start mb-2">
                          <span className={`text-[9px] font-black px-2 py-0.5 rounded-full ${t.type === 'IN' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                             {t.type === 'IN' ? 'পার্সেস (ইন)' : 'বিক্রি (আউট)'}
                          </span>
                          <span className="text-[9px] font-bold text-gray-400 uppercase">{t.date}</span>
                       </div>
