      {editingId && (
        <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center p-6 backdrop-blur-sm">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-xl font-black text-gray-900 mb-6 flex items-center gap-2">
                 <Edit2 size={20} className="text-blue-600" /> তথ্য এডিট
              </h3>
              <div className="space-y-4">
                 <input className={inputClasses} placeholder="পণ্যের নাম" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} />
                 <input className={inputClasses} placeholder="সিরিয়াল নাম্বার" value={editForm.serialNumber || ''} onChange={e => setEditForm({...editForm, serialNumber: e.target.value})} />
                 <div className="grid grid-cols-2 gap-3">
                   <input type="number" className={inputClasses} placeholder="কেনা মূল্য" value={editForm.buyingPrice || ''} onChange={e => setEditForm({...editForm, buyingPrice: parseFloat(e.target.value)})} />
                   <input type="number" className={inputClasses} placeholder="বিক্রি মূল্য" value={editForm.sellingPrice || ''} onChange={e => setEditForm({...editForm, sellingPrice: parseFloat(e.target.value)})} />
