import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, 
  Wallet, 
  Menu, 
  BookOpen, 
  Search, 
  UserPlus, 
  Plus, 
  Minus, 
  ArrowLeft, 
  MoreVertical, 
  Calendar, 
  Camera, 
  ChevronRight,
  Filter,
  Download,
  Package,
  FileText,
  Bell,
  HelpCircle,
  QrCode,
  CloudUpload,
  MessageSquare,
  ChevronDown,
  Sparkles,
  Store
} from 'lucide-react';
import { Contact, ContactType, ViewState, Transaction, SalePurchaseRecord, StockItem, StockTransaction, ShopSettings } from './types';
import TallyView from './components/TallyView';
import CashboxView from './components/CashboxView';
import AddContactForm from './components/AddContactForm';
import ContactDetails from './components/ContactDetails';
import Navigation from './components/Navigation';
import Sidebar from './components/Sidebar';
import BechaKenaView from './components/BechaKenaView';
import CloudBackup, { UserProfile } from './components/CloudBackup';
import AIChatView, { Message } from './components/AIChatView';
import SmartRecommendationsView from './components/SmartRecommendationsView';
import StockView from './components/StockView';
import SaleEntryView from './components/SaleEntryView';

const HELP_WHATSAPP_URL = 'https://wa.me/8801797464478';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('TALLY');
  const [isSyncing, setIsSyncing] = useState(false);

  const defaultShopSettings: ShopSettings = { shopName: 'গেস্ট', shopAddress: '', shopPhone: '' };

  const [shopSettings, setShopSettings] = useState<ShopSettings>(() => {
    const saved = localStorage.getItem('dokan_shop_settings');
    return saved ? JSON.parse(saved) : defaultShopSettings;
  });

  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(() => {
    return localStorage.getItem('dokan_user_logged_in') === 'true';
  });
  const [user, setUser] = useState<UserProfile | null>(() => {
    const savedUser = localStorage.getItem('dokan_user_profile');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  const [contacts, setContacts] = useState<Contact[]>(() => {
    const saved = localStorage.getItem('dokan_contacts');
    return saved ? JSON.parse(saved) : [];
  });

  const [salePurchaseRecords, setSalePurchaseRecords] = useState<SalePurchaseRecord[]>(() => {
    const saved = localStorage.getItem('dokan_becha_kena');
    return saved ? JSON.parse(saved) : [];
  });

  const [stockItems, setStockItems] = useState<StockItem[]>(() => {
    const saved = localStorage.getItem('dokan_stock');
    return saved ? JSON.parse(saved) : [];
  });

  const [stockTransactions, setStockTransactions] = useState<StockTransaction[]>(() => {
    const saved = localStorage.getItem('dokan_stock_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [aiMessages, setAiMessages] = useState<Message[]>([
    { 
      role: 'ai', 
      text: 'আসসালামু আলাইকুম! আমি আপনার দোকানের এআই অ্যাসিস্ট্যান্ট।' 
    }
  ]);

  const [selectedContactId, setSelectedContactId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [editingContact, setEditingContact] = useState<Contact | undefined>(undefined);

  useEffect(() => {
    localStorage.setItem('dokan_contacts', JSON.stringify(contacts));
  }, [contacts]);

  useEffect(() => {
    localStorage.setItem('dokan_becha_kena', JSON.stringify(salePurchaseRecords));
  }, [salePurchaseRecords]);

  useEffect(() => {
    localStorage.setItem('dokan_stock', JSON.stringify(stockItems));
    localStorage.setItem('dokan_stock_transactions', JSON.stringify(stockTransactions));
  }, [stockItems, stockTransactions]);

  useEffect(() => {
    localStorage.setItem('dokan_shop_settings', JSON.stringify(shopSettings));
  }, [shopSettings]);

  const handleRestoreData = (restoredData: any) => {
    setIsSyncing(true);
    setTimeout(() => {
      if (restoredData.contacts) setContacts(restoredData.contacts);
      if (restoredData.salePurchaseRecords) setSalePurchaseRecords(restoredData.salePurchaseRecords);
      if (restoredData.stockItems) setStockItems(restoredData.stockItems);
      if (restoredData.stockTransactions) setStockTransactions(restoredData.stockTransactions);
      if (restoredData.shopSettings) setShopSettings(restoredData.shopSettings);
      setIsSyncing(false);
      setCurrentView('TALLY');
    }, 2000);
  };

  const addContact = (updatedContact: Contact) => {
    const exists = contacts.find(c => c.id === updatedContact.id);
    if (exists) {
      setContacts(prev => prev.map(c => c.id === updatedContact.id ? updatedContact : c));
    } else {
      setContacts(prev => [...prev, updatedContact]);
    }
    setEditingContact(undefined);
    setCurrentView('TALLY');
  };

  const deleteContact = (id: string) => {
    setContacts(prev => prev.filter(c => c.id !== id));
    setSelectedContactId(null);
    setCurrentView('TALLY');
  };

  const addSalePurchaseRecord = (record: SalePurchaseRecord) => {
    setSalePurchaseRecords(prev => [...prev, record]);
  };

  const updateContactTransactions = (contactId: string, transaction: Transaction) => {
    setContacts(prev => prev.map(c => {
      if (c.id === contactId) {
        const newBalance = transaction.type === 'DUE_GIVEN' 
          ? c.balance + transaction.amount 
          : c.balance - transaction.amount;
        return {
          ...c,
          balance: newBalance,
          lastActivity: 'এখনই',
          transactions: [transaction, ...c.transactions]
        };
      }
      return c;
    }));
  };

  const handleUpdateStock = (updatedItems: StockItem[], updatedTransactions: StockTransaction[]) => {
    setStockItems(updatedItems);
    setStockTransactions(updatedTransactions);
  };

  const handleUpdateContacts = (updatedContacts: Contact[]) => {
    setContacts(updatedContacts);
  };

  const handleConfirmSale = (saleData: { 
    contactId: string; 
    customerName: string;
    customerPhone: string;
    customerAddress: string;
    items: { productId: string; name: string; quantity: number; price: number }[]; 
    total: number; 
    isCash: boolean;
  }): SalePurchaseRecord => {
    const date = new Date().toLocaleDateString('bn-BD', { day: '2-digit', month: 'long', year: 'numeric' });

    const updatedStock = stockItems.map(p => {
      const soldItem = saleData.items.find(si => si.productId === p.id);
      if (soldItem) {
        return { ...p, quantity: p.quantity - soldItem.quantity };
      }
      return p;
    });
    setStockItems(updatedStock);

    const record: SalePurchaseRecord = {
      id: Date.now().toString(),
      type: 'SALE',
      amount: saleData.total,
      description: saleData.items.map(i => `${i.name} (${i.quantity})`).join(', '),
      date,
      isCash: saleData.isCash,
      customerName: saleData.customerName,
      customerPhone: saleData.customerPhone,
      customerAddress: saleData.customerAddress,
      items: saleData.items
    };
    setSalePurchaseRecords(prev => [...prev, record]);

    if (!saleData.isCash && saleData.contactId !== 'CASH_CUSTOMER' && saleData.contactId !== '') {
      const transaction: Transaction = {
        id: (Date.now() + 1).toString(),
        type: 'DUE_GIVEN',
        amount: saleData.total,
        description: `বিক্রি: ${record.description}`,
        date
      };
      updateContactTransactions(saleData.contactId, transaction);
    } else if (!saleData.isCash && (saleData.contactId === 'CASH_CUSTOMER' || saleData.contactId === '')) {
       const newContactId = Date.now().toString();
       const newContact: Contact = {
          id: newContactId,
          name: saleData.customerName,
          phone: saleData.customerPhone,
          type: ContactType.CUSTOMER,
          balance: saleData.total,
          lastActivity: 'এখনই',
          transactions: [{
            id: (Date.now() + 2).toString(),
            type: 'DUE_GIVEN',
            amount: saleData.total,
            description: `বিক্রি: ${record.description}`,
            date
          }]
       };
       setContacts(prev => [...prev, newContact]);
    }

    return record;
  };

  const selectedContact = useMemo(() => 
    contacts.find(c => c.id === selectedContactId), 
    [contacts, selectedContactId]
  );

  const handleHelpClick = () => {
    window.open(HELP_WHATSAPP_URL, '_blank');
  };

  const handleLoginSuccess = (profile: UserProfile) => {
    setUser(profile);
    setIsLoggedIn(true);
    localStorage.setItem('dokan_user_logged_in', 'true');
    localStorage.setItem('dokan_user_profile', JSON.stringify(profile));
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUser(null);
    setShopSettings(defaultShopSettings); 
    localStorage.removeItem('dokan_user_logged_in');
    localStorage.removeItem('dokan_user_profile');
    localStorage.removeItem('dokan_shop_settings'); 
    setCurrentView('TALLY');
    setIsSidebarOpen(false);
  };

  const handleNavigation = (view: ViewState) => {
    if (view === 'MENU') {
      setIsSidebarOpen(true);
    } else {
      setCurrentView(view);
    }
  };

  const renderView = () => {
    if (isSyncing) {
      return (
        <div className="flex-1 flex flex-col items-center justify-center p-10 text-center space-y-6">
          <div className="relative">
             <div className="w-20 h-20 border-4 border-red-50 border-t-red-600 rounded-full animate-spin"></div>
             <div className="absolute inset-0 flex items-center justify-center">
                <img src="https://www.google.com/favicon.ico" alt="g" className="w-6 h-6 animate-pulse" />
             </div>
          </div>
          <div>
            <h3 className="text-xl font-black text-gray-900 leading-tight">ড্রাইভ থেকে ডাটা লোড হচ্ছে...</h3>
            <p className="text-sm text-gray-400 font-bold mt-2 uppercase tracking-widest">দয়া করে অপেক্ষা করুন</p>
          </div>
        </div>
      );
    }

    switch (currentView) {
      case 'TALLY':
        return <TallyView contacts={contacts} saleRecords={salePurchaseRecords} onSelectContact={id => { setSelectedContactId(id); setCurrentView('CONTACT_DETAILS'); }} onAddContact={() => { setEditingContact(undefined); setCurrentView('ADD_CONTACT'); }} onNavigate={handleNavigation} />;
      case 'CASHBOX': return <CashboxView />;
      case 'ADD_CONTACT': return <AddContactForm onBack={() => setCurrentView(editingContact ? 'CONTACT_DETAILS' : 'TALLY')} onSave={addContact} editContact={editingContact} />;
      case 'CONTACT_DETAILS': return selectedContact ? <ContactDetails contact={selectedContact} onBack={() => setCurrentView('TALLY')} onAddTransaction={t => updateContactTransactions(selectedContact.id, t)} onDeleteContact={deleteContact} onEditContact={c => { setEditingContact(c); setCurrentView('ADD_CONTACT'); }} /> : null;
      case 'BECHA_KENA': return <BechaKenaView records={salePurchaseRecords} onBack={() => setCurrentView('TALLY')} onAddRecord={addSalePurchaseRecord} />;
      case 'CLOUD_BACKUP': return <CloudBackup data={{ contacts, salePurchaseRecords, stockItems, shopSettings, stockTransactions }} onBack={() => setCurrentView('TALLY')} onLoginSuccess={handleLoginSuccess} onLogout={handleLogout} onRestore={handleRestoreData} currentLoggedInState={isLoggedIn} currentUserProfile={user} shopSettings={shopSettings} onUpdateShopSettings={setShopSettings} />;
      case 'AI_CHAT': return <AIChatView contacts={contacts} records={salePurchaseRecords} onBack={() => setCurrentView('TALLY')} persistedMessages={aiMessages} onMessagesUpdate={setAiMessages} onClearChat={() => setAiMessages([])} />;
      case 'STOCK': return <StockView items={stockItems} transactions={stockTransactions} contacts={contacts} onBack={() => setCurrentView('TALLY')} onUpdateStock={handleUpdateStock} onUpdateContacts={handleUpdateContacts} />;
      case 'SALE_ENTRY': return <SaleEntryView contacts={contacts} stockItems={stockItems} onBack={() => setCurrentView('TALLY')} onConfirmSale={handleConfirmSale} shopSettings={shopSettings} />;
      default: return <TallyView contacts={contacts} saleRecords={salePurchaseRecords} onSelectContact={() => {}} onAddContact={() => {}} onNavigate={handleNavigation} />;
    }
  };

  const displayShopName = isLoggedIn && shopSettings.shopName !== 'গেস্ট' ? shopSettings.shopName : 'গেস্ট';
  const headerPhoto = isLoggedIn ? (shopSettings.shopLogo || (user ? user.photo : null)) : null;

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen flex flex-col relative shadow-xl">
      <header className="bg-[#D32F2F] text-white px-4 py-3 sticky top-0 z-40 shadow-md">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer active:opacity-80 transition-opacity" onClick={() => setIsSidebarOpen(true)}>
            <div className="bg-white/20 p-1 rounded-md flex items-center gap-2">
              {headerPhoto ? <img src={headerPhoto} className="w-5 h-5 rounded-full border border-white/40 object-cover" alt="p" /> : <div className="w-5 h-5 rounded-full bg-white/20 flex items-center justify-center text-[10px] font-bold"><Store size={12} /></div>}
              <span className="text-sm font-bold truncate max-w-[120px]">{displayShopName}</span>
            </div>
            <ChevronDown size={16} />
          </div>
          <div className="flex items-center gap-4">
            <div onClick={() => setCurrentView('AI_CHAT')} className="flex flex-col items-center cursor-pointer"><Sparkles size={24} className="text-yellow-300" /><span className="text-[10px] mt-1 text-white font-bold">এআই</span></div>
            <div className="relative flex flex-col items-center cursor-pointer"><Bell size={24} /><span className="text-[10px] mt-1 text-white font-bold">ইনবক্স</span></div>
            <div onClick={handleHelpClick} className="flex flex-col items-center cursor-pointer"><HelpCircle size={24} /><span className="text-[10px] mt-1 text-white font-bold">হেল্প</span></div>
          </div>
        </div>
      </header>
      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} isLoggedIn={isLoggedIn} user={user} shopSettings={shopSettings} onNavigate={view => { setCurrentView(view); setIsSidebarOpen(false); }} onLogout={handleLogout} />
      <main className="flex-1 overflow-y-auto pb-20 bg-gray-50">{renderView()}</main>
      {['TALLY', 'CASHBOX', 'STOCK'].includes(currentView) || currentView === 'TALLY' ? (
        <Navigation currentView={currentView} onNavigate={handleNavigation} />
      ) : null}
    </div>
  );
};

