            </div>
            <div className="text-right">
               <div className="flex flex-col items-end">
                  <div className="text-xs font-black text-gray-900">৳{item.sellingPrice}</div>
                  <div className="flex items-center gap-1 text-[8px] font-bold text-gray-400">
                    কেনা: {showPriceMap[item.id] ? `৳${item.buyingPrice}` : '***'}
                    <button onClick={() => togglePriceVisibility(item.id)} className="ml-1 text-red-600">
                      {showPriceMap[item.id] ? <EyeOff size={10} /> : <Eye size={10} />}
                    </button>
                  </div>
                  {showPriceMap[item.id] && (
                    <button 
                      onClick={() => openSupplierProfile(transactions.find(t => t.itemId === item.id && t.type === 'IN')?.partyName || 'অজানা')}
                      className="text-[8px] font-black text-blue-600 mt-0.5 uppercase tracking-tighter hover:underline"
                    >
                      সাপ্লায়ার: {transactions.find(t => t.itemId === item.id && t.type === 'IN')?.partyName || 'অজানা'}
                    </button>
                  )}
               </div>
            </div>
          </div>
        ))}
      </div>

      {/* STOCK IN/OUT MODAL (EXPANDED) */}
      {(activeAction !== 'NONE') && (
        <div className="fixed inset-0 bg-black/95 z-[100] flex items-center justify-center p-4 backdrop-blur-md overflow-y-auto">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-8 animate-in zoom-in-95 duration-300 shadow-2xl relative my-auto">
            <button onClick={resetActionStates} className="absolute top-6 right-6 p-2 bg-gray-100 rounded-full text-gray-500">
               <X size={24} />
            </button>

            <div className="flex items-center gap-4 mb-8">
               <div className={`p-4 rounded-3xl ${activeAction === 'IMPORT' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                  {activeAction === 'IMPORT' ? <ArrowDownLeft size={36} /> : <ArrowUpRight size={36} />}
               </div>
               <div>
                  <h3 className="text-2xl font-black text-gray-900 uppercase">
                     {activeAction === 'IMPORT' ? 'স্টক ক্রয় (ইন)' : 'স্টক বিক্রি (আউট)'}
                  </h3>
                  <p className="text-xs text-gray-400 font-bold">পণ্যের পরিমাণ ও পেমেন্ট তথ্য দিন</p>
               </div>
            </div>

            <div className="space-y-6">
               <div className="relative" ref={actionDropdownRef}>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">পণ্য নির্বাচন করুন</label>
                  <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input 
                      type="text" 
                      placeholder="পণ্যের নাম লিখুন..." 
                      value={selectedProductForAction ? selectedProductForAction.name : actionSearchTerm}
                      onChange={(e) => {
                        setActionSearchTerm(e.target.value);
                        setShowActionDropdown(true);
                        if (selectedProductForAction) setSelectedProductForAction(null);
                      }}
                      onFocus={() => setShowActionDropdown(true)}
                      className={inputClasses + " pl-12 text-base"}
                    />
                  </div>

                  {showActionDropdown && !selectedProductForAction && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white border-2 border-gray-100 rounded-2xl shadow-2xl z-50 max-h-56 overflow-y-auto no-scrollbar ring-8 ring-black/5">
                       {filteredActionItems.map(item => (
                         <button key={item.id} onClick={() => { setSelectedProductForAction(item); setShowActionDropdown(false); }} className="w-full text-left p-4 hover:bg-red-50 flex items-center justify-between border-b border-gray-50 last:border-0">
                           <div className="font-black text-gray-800 text-base">{item.name}</div>
                           <Plus size={16} className="text-gray-300" />
                         </button>
                       ))}
                    </div>
                  )}
               </div>

               {selectedProductForAction && (
                 <div className="space-y-6 animate-in slide-in-from-top-4 duration-300">
                    <div className="grid grid-cols-2 gap-4">
                       <div>
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">পরিমাণ ({selectedProductForAction.unit})</label>
                          <input type="number" value={actionQuantity} onChange={(e) => setActionQuantity(e.target.value)} placeholder="0.00" className={inputClasses + " text-2xl"} />
                       </div>
                       <div>
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">একক মূল্য</label>
                          <div className={inputClasses + " bg-gray-50 border-gray-100 flex items-center text-gray-500"}>
                             ৳{activeAction === 'IMPORT' ? selectedProductForAction.buyingPrice : selectedProductForAction.sellingPrice}
                          </div>
                       </div>
                    </div>

                    <div className="relative" ref={partyDropdownRef}>
                      <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">
                        {activeAction === 'IMPORT' ? 'সাপ্লায়ারের নাম' : 'কাস্টমারের নাম'}
                      </label>
                      <input 
                        type="text" 
                        placeholder="নাম লিখুন..." 
                        value={partyName} 
                        onChange={(e) => { setPartyName(e.target.value); setShowPartyDropdown(true); }}
                        onFocus={() => setShowPartyDropdown(true)}
                        className={inputClasses + " text-base"} 
                      />
                      {showPartyDropdown && partyName && activeAction === 'IMPORT' && filteredSuppliers.length > 0 && (
                        <div className="absolute top-full left-0 right-0 mt-2 bg-white border-2 border-gray-100 rounded-2xl shadow-2xl z-50">
                           {filteredSuppliers.map(s => (
                             <button key={s.id} onClick={() => { setPartyName(s.name); setShowPartyDropdown(false); }} className="w-full text-left p-3 px-4 hover:bg-blue-50 border-b last:border-0 font-bold">
                                {s.name}
                             </button>
                           ))}
                        </div>
                      )}
                    </div>

                    {activeAction === 'IMPORT' && (
                      <div className="bg-gray-50 p-6 rounded-[2rem] border-2 border-gray-100 space-y-5">
                         <div className="flex items-center justify-between">
                            <span className="font-black text-gray-700">সম্পূর্ণ টাকা দিয়েছেন?</span>
                            <div className="flex p-1 bg-white border border-gray-200 rounded-full">
                               <button onClick={() => setIsFullPaid(true)} className={`px-4 py-1.5 rounded-full text-xs font-black transition-all ${isFullPaid ? 'bg-green-600 text-white shadow-md' : 'text-gray-400'}`}>হ্যাঁ</button>
                               <button onClick={() => setIsFullPaid(false)} className={`px-4 py-1.5 rounded-full text-xs font-black transition-all ${!isFullPaid ? 'bg-red-600 text-white shadow-md' : 'text-gray-400'}`}>না</button>
                            </div>
                         </div>
                         {!isFullPaid && (
                           <div className="animate-in slide-in-from-top-2 duration-200">
                             <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">পরিশোধিত টাকা (টাকা দিয়েছেন)</label>
                             <input type="number" value={paidAmount} onChange={(e) => setPaidAmount(e.target.value)} placeholder="0.00" className={inputClasses} />
                           </div>
                         )}
                         <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1 mb-2 block">অতিরিক্ত নোট (ঐচ্ছিক)</label>
                            <input type="text" value={note} onChange={(e) => setNote(e.target.value)} placeholder="কেনা সংক্রান্ত বিশেষ তথ্য..." className={inputClasses + " text-sm"} />
                         </div>
                      </div>
                    )}

                    <button onClick={handleStockAction} className="w-full py-5 rounded-[2rem] font-black text-xl text-white shadow-2xl active:scale-95 transition-all bg-red-600 shadow-red-100 hover:bg-red-700">
                      ট্রানজেকশন নিশ্চিত করুন
                    </button>
                 </div>
               )}
            </div>
          </div>
        </div>
      )}

      {/* SUPPLIER PROFILE VIEW */}
      {showSupplierDetail && (
        <div className="fixed inset-0 bg-black/95 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-6 shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
              <div className="flex justify-between items-start mb-6">
                 <div className="flex items-center gap-4">
                    <div className="w-16 h-16 rounded-[2rem] bg-blue-50 flex items-center justify-center text-blue-600 border border-blue-100">
                       <Truck size={36} />
                    </div>
                    <div>
                       <h3 className="text-xl font-black text-gray-900 leading-tight">{showSupplierDetail.name}</h3>
                       <div className="flex items-center gap-2 mt-1">
                          <span className="text-[9px] font-black px-2 py-0.5 bg-blue-100 text-blue-600 rounded-full uppercase">সাপ্লায়ার</span>
                          <span className="text-[9px] font-bold text-gray-400 uppercase">আইডি: #{showSupplierDetail.id.slice(0,4)}</span>
                       </div>
                    </div>
                 </div>
                 <button onClick={() => setShowSupplierDetail(null)} className="p-2 bg-gray-50 rounded-full text-gray-400"><X size={20} /></button>
              </div>

              <div className="bg-gray-900 text-white p-6 rounded-[2.5rem] shadow-xl mb-6 relative overflow-hidden">
                 <div className="relative z-10">
                   <div className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-1">মোট পাওনা (আপনার কাছে)</div>
                   <div className="text-3xl font-black text-red-400">
                     ৳{Math.abs(showSupplierDetail.balance).toLocaleString('bn-BD')}
                   </div>
                   <div className="mt-4 flex items-center gap-3">
                      <button 
                        onClick={() => setIsPaying(true)}
                        className="flex-1 bg-white text-gray-900 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg active:scale-95 transition-all"
                      >
                         বকেয়া পরিশোধ
                      </button>
                      <button className="p-3 bg-white/10 rounded-2xl text-white border border-white/10"><Phone size={18} /></button>
                   </div>
                 </div>
                 <div className="absolute -right-6 -bottom-6 w-32 h-32 bg-white/5 rounded-full blur-3xl"></div>
              </div>

              {isPaying && (
                <div className="mb-6 p-5 bg-blue-50 border-2 border-blue-200 rounded-[2rem] animate-in slide-in-from-top-4 duration-300">
                   <div className="flex justify-between items-center mb-4">
                      <h4 className="text-xs font-black text-blue-700 uppercase">টাকা পরিশোধ করুন</h4>
                      <button onClick={() => setIsPaying(false)} className="text-blue-400"><X size={16} /></button>
                   </div>
                   <div className="space-y-4">
                      <div className="relative">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 font-black text-blue-600">৳</span>
                        <input type="number" value={paymentAmount} onChange={(e) => setPaymentAmount(e.target.value)} placeholder="পরিমাণ" className={inputClasses + " pl-10 border-blue-100 focus:border-blue-600"} />
                      </div>
                      <button onClick={handleSupplierPayment} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-lg shadow-blue-100">
