                      </button>
                   </div>
                </div>
              )}

              <div className="flex-1 overflow-y-auto no-scrollbar space-y-4">
                 <div className="flex items-center justify-between px-1">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">সরবরাহকৃত পণ্য ও লেনদেন</span>
